  const m = content.match(re)
  if (!m) return null
  return m[1]
}

function writeFile(contents) {
  fs.mkdirSync(path.dirname(outFile), { recursive: true })
  fs.writeFileSync(outFile, contents, 'utf8')
}

const files = fs.existsSync(iconsDir)
  ? fs.readdirSync(iconsDir).filter((f) => f.endsWith('.mjs'))
  : []

const entries = []

for (const file of files) {
  const name = path.basename(file, '.mjs') // e.g., layout-grid
  const pascal = pascalCase(name)
  const content = fs.readFileSync(path.join(iconsDir, file), 'utf8')
  const nodeText = extractIconNode(content)
  if (!nodeText) continue

  // Evaluate the array literal to turn into JS structure
  let nodeVal
  try {
    // Wrap in parentheses to allow top-level array
    nodeVal = eval('(' + nodeText + ')')
  } catch (err) {
    console.warn('skip', name, err.message)
    continue
  }

  // Build JSX children
  const children = nodeVal
    .map(([tag, attrs]) => {
      const props = Object.entries(attrs || {})
        .map(([k, v]) => {
          // numeric-like strings can remain strings; use JSON.stringify
          return `${k}={${JSON.stringify(v)}}`
        })
        .join(' ')
      return `    <${tag} ${props} />`
    })
    .join('\n')

  const component = `export const ${pascal} = ({ size = 24, strokeWidth = 2, color = 'currentColor', strokeLinecap = 'round', strokeLinejoin = 'round', className, ...props }) => (\n  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth={strokeWidth} strokeLinecap={strokeLinecap} strokeLinejoin={strokeLinejoin} className={className} {...props}>\n${children}\n  </svg>\n)\n`

  entries.push({ name: pascal, component })
}

if (entries.length === 0) {
  console.error('No icons generated: icons directory missing or parser failed.')
  process.exit(1)
}

const header = `/* THIS FILE IS GENERATED - DO NOT EDIT DIRECTLY */\nimport React from 'react'\n\n`

const exports = entries.map((e) => e.component).join('\n')

const namedExports = '\nexport default {' + entries.map((e) => ` ${e.name}`).join(',') + ' }\n'

writeFile(header + exports + namedExports)

console.log('Wrote', outFile, 'with', entries.length, 'icons')

import { ChevronDown } from "lucide-react"
import { memo, useMemo } from "react"
import { useBranchContext } from "../context/BranchContext"

function BranchSelectorComponent({ className = "", onChange = null, value = null, viewMode = null }) {
  const { 
    activeBranch, 
    viewMode: globalViewMode, 
    setViewMode, 
    availableBranches, 
    canViewAll, 
    loading,
    showAllBranches,
    setActiveBranch,
    isOwner,
    isManager
  } = useBranchContext()

  // Use local or global values
  const currentViewMode = viewMode !== null ? viewMode : globalViewMode
  const currentValue = value !== null ? value : (currentViewMode === 'all' ? 'all' : activeBranch?.id || '')
  const hasLocalControl = onChange !== null
  const canSwitch = isOwner || isManager

  // Memoize expensive calculations
  const allBranchesLabel = useMemo(() => {
    if (isOwner) return "All Branches"
    if (isManager) return "All My Branches"
    return "All Branches"
  }, [isOwner, isManager])

  const branchOptions = useMemo(() => {
    if (loading) {
      return [<option key="loading" value="">Loading branches...</option>]
    }
    const options = []

    if (canViewAll) {
      options.push(<option key="all" value="all">{allBranchesLabel}</option>)
    }

    availableBranches.forEach(branch => {
      options.push(
        <option key={branch.id} value={branch.id}>
          {branch.name} {branch.code && `(${branch.code})`}
        </option>
      )
    })

    return options
  }, [loading, canViewAll, allBranchesLabel, availableBranches])

  const handleChange = (e) => {
    if (hasLocalControl) {
      // Page has local control - call the provided onChange
      onChange(e.target.value)
    } else {
      // Use global context
      if (e.target.value === 'all') {
        showAllBranches()
      } else {
        const branch = availableBranches.find(b => b.id === e.target.value)
        if (branch) setActiveBranch(branch)
      }
    }
  }

  // Don't render the selector at all for single-branch users
  if (!canViewAll && availableBranches.length <= 1) return null

  return (
    <div className={`relative ${className}`}>
      <select
        value={currentValue}
        onChange={handleChange}
        disabled={loading || !canSwitch}
        className={`appearance-none bg-zinc-800 border border-zinc-700 text-white rounded-lg px-3 py-2 pr-8 text-sm focus:outline-none focus:border-emerald-500 transition-colors ${
          loading || !canSwitch ? 'cursor-not-allowed opacity-50' : 'cursor-pointer hover:bg-zinc-700'
        }`}
      >
        {branchOptions}
      </select>

      {/* Custom dropdown arrow */}
      <div className="absolute inset-y-0 right-0 flex items-center pr-2 pointer-events-none">
        <ChevronDown className="h-4 w-4 text-zinc-400" />
      </div>
    </div>
  )
}

