import { useState, useCallback, useRef } from 'react'
import { useNavigate } from 'react-router-dom'

// Pre-loaded page components cache
const componentCache = new Map()
const dataCache = new Map()

export function useInstantNavigation() {
  const navigate = useNavigate()
  const [isTransitioning, setIsTransitioning] = useState(false)
  const preloadTimeoutRef = useRef(null)

  // Pre-load page components
  const preloadPage = useCallback(async (route) => {
    if (componentCache.has(route)) return componentCache.get(route)

    try {
      let component
      switch (route) {
        case '/inventory/new-stock':
          component = await import('../pages/inventory/NewStock')
          break
        case '/transactions/add-sale':
          component = await import('../pages/transactions/AddSale')
          break
        case '/transactions/add-expense':
          component = await import('../pages/transactions/AddExpense')
          break
        case '/settings/branches':
          component = await import('../pages/settings/Branches')
          break
        case '/settings/branch-employees':
          component = await import('../pages/settings/BranchEmployees')
          break
        case '/settings/opening-stock':
          component = await import('../pages/settings/OpeningStock')
          break
        case '/settings/branch-detail':
        case '/settings/branches/:id':
          component = await import('../pages/settings/BranchDetail')
          break
        case '/settings/employee-detail':
        case '/settings/employees/:id':
          component = await import('../pages/settings/EmployeeDetail')
          break
        default:
          return null
      }

      if (component) {
        componentCache.set(route, component.default)
        return component.default
      }
    } catch (error) {
      console.error(`Failed to preload ${route}:`, error)
      return null
    }
  }, [])

  // Instant navigation with pre-loading
  const navigateInstant = useCallback((to, options = {}) => {
    setIsTransitioning(true)

    // Clear any pending preloads
    if (preloadTimeoutRef.current) {
      clearTimeout(preloadTimeoutRef.current)
    }

    // Navigate immediately
    navigate(to, { ...options, replace: false })

    // Reset transition state after a short delay
    setTimeout(() => setIsTransitioning(false), 50)
  }, [navigate])

  // Pre-load likely next pages
  const preloadLikelyPages = useCallback((currentRoute) => {
    const likelyRoutes = {
      '/dashboard': ['/transactions/add-sale', '/transactions/add-expense', '/inventory/new-stock'],
      '/transactions': ['/transactions/add-sale', '/transactions/add-expense'],
      '/inventory': ['/inventory/new-stock'],
      '/settings': ['/transactions/add-expense'],
      '/inventory/new-stock': ['/inventory'],
      '/transactions/add-sale': ['/transactions'],
      '/transactions/add-expense': ['/transactions'],
      '/settings/branches': ['/settings/branch-employees'],
      '/settings/opening-stock': ['/transactions/add-sale'],
      '/settings/branch-employees': ['/settings/branches'],
      '/settings/branches/': ['/settings/branch-employees']
    }

    const routes = likelyRoutes[currentRoute] || []

    // Pre-load with delay to not block current navigation
    preloadTimeoutRef.current = setTimeout(() => {
      routes.forEach(route => preloadPage(route))
    }, 100)
  }, [preloadPage])

  return {
    navigateInstant,
    preloadPage,
    preloadLikelyPages,
    isTransitioning
  }
}

// Hook for optimistic updates
export function useOptimisticUpdate() {
  const optimisticStoreRef = useRef(new Map())

  const updateOptimistically = useCallback((cacheKey, updateFn) => {
    const currentData = optimisticStoreRef.current.get(cacheKey) || []
    const updatedData = updateFn(currentData)
    optimisticStoreRef.current.set(cacheKey, updatedData)
    return updatedData
  }, [])

  const invalidateRelated = useCallback(() => {
    // No-op: RxDB observers now drive UI freshness.
  }, [])

  return {
    updateOptimistically,
    invalidateRelated
  }
}

import { useState, useEffect } from 'react'
import { getDb, startProductsReplication } from '../lib/db'
import { useInstantAuth } from './useInstantAuth'

export function useProducts(branchId = null, isOwnerOrManager = false) {
  const { business } = useInstantAuth()
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    console.log('useProducts hook:', { business, branchId, isOwnerOrManager })
    if (!business?.id) return

    if (!isOwnerOrManager && !branchId) {
      setProducts([])
      setLoading(false)
      return
    }

    let subscription
    let replication
    let active = true

    getDb().then(async (db) => {
      if (!active) return

      try {
        replication = startProductsReplication(db.products, business.id)
      } catch (error) {
        console.error('Failed to start products replication:', error)
        // Continue without replication - we'll still have cached data
      }

      // Initial data fetch - ensure we have data even if replication is slow
      const selector = {
        business_id: business.id,
        _deleted: { $ne: true },
        // Show active products, or products without is_active set (defaults to active)
        $or: [
          { is_active: true },
          { is_active: null }
        ],
        ...(branchId ? { branch_id: branchId } : {}),
        // For non-owners, ensure they only see active products (default behavior)
        ...(isOwnerOrManager ? {} : {}),
      }

      // Try to get existing data first
      try {
        const existingDocs = await db.products.find({ selector }).exec()
        if (existingDocs.length > 0) {
          setProducts(existingDocs.map((doc) => doc.toJSON()))
          setLoading(false)
        }
      } catch (error) {
        console.error('useProducts initial fetch error:', error)
        setProducts([]) // Set empty array on error to prevent infinite loading
        setLoading(false)
      }

      // Subscribe for live updates
      subscription = db.products
        .find({ selector, sort: [{ name: 'asc' }, { id: 'asc' }] })
        .$
        .subscribe({
          next: (docs) => {
            if (!active) return
            setProducts(docs.map((doc) => doc.toJSON()))
            setLoading(false)
          },
          error: (error) => {
            console.error('useProducts subscription error:', error)
            setLoading(false)
          }
        })
    })

    return () => {
      active = false
      subscription?.unsubscribe()
      replication?.cancel()
    }
  }, [business?.id, branchId, isOwnerOrManager])

  return { products, loading }
}

