  const [error, setError] = useState("")
  const [linkType, setLinkType] = useState(null) // "recovery" | "invite"
  const [employeeName, setEmployeeName] = useState("")

  useEffect(() => {
    handleCallback()
  }, [])

  const handleCallback = async () => {
    // Supabase puts the session tokens in the URL hash after redirect.
    // Calling getSession() after a magic link automatically exchanges them.
    const { data: { session }, error: sessionError } = await supabase.auth.getSession()

    if (sessionError || !session) {
      setScreen("error")
      return
    }

    const user = session.user

    // Read the type from the URL hash Supabase appends e.g. #type=signup
    const hash = window.location.hash
    const params = new URLSearchParams(hash.replace("#", "?"))
    const type = params.get("type") || user.app_metadata?.invite_flow || ""

    setLinkType(type)

    // ΓöÇΓöÇ OWNER EMAIL CONFIRMATION ΓöÇΓöÇ
    if (type === "signup") {
      await handleOwnerConfirmation(user)
      return
    }

    // ΓöÇΓöÇ PASSWORD RECOVERY ΓöÇΓöÇ
    if (type === "recovery") {
      setScreen("set-password")
      return
    }

    // ΓöÇΓöÇ EMPLOYEE INVITE ΓöÇΓöÇ
    if (type === "invite") {
      // Try to get their name from our users table (owner may have pre-inserted)
      const { data: userData } = await supabase
        .from("users")
        .select("full_name")
        .eq("email", user.email)
        .single()

      setEmployeeName(userData?.full_name || "")
      setScreen("invite-password")
      return
    }

    // Fallback ΓÇö if we can't determine type, check if they have a users row
    const { data: existingUser } = await supabase
      .from("users")
      .select("id, role")
      .eq("id", user.id)
      .single()

    if (existingUser) {
      navigate("/dashboard")
    } else {
      await handleOwnerConfirmation(user)
    }
  }

  const handleOwnerConfirmation = async (user) => {
    // Since we removed email confirmation, users should not reach here via signup flow
    // If they do, just redirect to dashboard
    navigate("/dashboard")
  }

  // ΓöÇΓöÇ SET PASSWORD (recovery or invite) ΓöÇΓöÇ
  const handleSetPassword = async () => {
    setError("")

    if (!password) { setError("Please enter a password"); return }
    if (password.length < 6) { setError("Password must be at least 6 characters"); return }
    if (password !== confirmPassword) { setError("Passwords do not match"); return }

    setLoading(true)

    const { error: updateError } = await supabase.auth.updateUser({ password })

    if (updateError) {
      setError(updateError.message)
      setLoading(false)
      return
    }

    if (linkType === "recovery") {
      // Password reset ΓÇö go to dashboard
      navigate("/dashboard")
    } else if (linkType === "invite") {
      // Employee invite ΓÇö mark their users row as active
      const { data: { user } } = await supabase.auth.getUser()
      await supabase
        .from("users")
        .update({ is_active: true })
        .eq("id", user.id)

      navigate("/dashboard")
    }

    setLoading(false)
  }

  // ΓöÇΓöÇ LOADING ΓöÇΓöÇ
  if (screen === "loading") {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-5">
        <div className="text-center space-y-4">
          <div className="w-10 h-10 border-2 border-zinc-700 border-t-emerald-500 rounded-full animate-spin mx-auto" />
          <p className="text-zinc-500 text-sm">Verifying your link...</p>
        </div>
      </div>
    )
  }

  // ΓöÇΓöÇ ERROR ΓöÇΓöÇ
  if (screen === "error") {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-5">
        <div className="w-full max-w-sm text-center space-y-6">
          <div className="w-20 h-20 bg-red-400/10 border border-red-400/20 rounded-full flex items-center justify-center mx-auto">
            <span className="text-3xl">ΓÜá∩╕Å</span>
          </div>
          <div>
            <h2 className="text-white font-bold text-2xl tracking-tight">Something went wrong</h2>
            <p className="text-zinc-400 text-sm mt-2 leading-relaxed">
              {error || "This link may have expired or already been used. Please try again."}
            </p>
          </div>
          <button
            onClick={() => navigate("/")}
            className="w-full bg-zinc-900 hover:bg-zinc-800 border border-zinc-800 text-white font-medium rounded-xl py-3.5 text-sm transition-colors"
          >
            ΓåÉ Back to sign in
          </button>
        </div>
      </div>
    )
  }

  // ΓöÇΓöÇ SET PASSWORD (recovery) ΓöÇΓöÇ
  if (screen === "set-password") {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-5">
        <div className="w-full max-w-sm space-y-6">
          <div>
            <p className="text-zinc-500 text-xs font-mono uppercase tracking-widest mb-3">Password reset</p>
            <h1 className="text-white font-bold text-2xl tracking-tight">Set a new password</h1>
            <p className="text-zinc-500 text-sm mt-1.5">Choose something strong that you'll remember.</p>
          </div>

          <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-5 space-y-4">
            {error && (
              <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
                <p className="text-red-400 text-sm">{error}</p>
              </div>
            )}
            <div>
              <label className="text-zinc-400 text-xs mb-2 block">New password</label>
              <input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Min. 6 characters"
                autoFocus
                className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
              />
            </div>
            <div>
              <label className="text-zinc-400 text-xs mb-2 block">Confirm new password</label>
              <input
                type="password"
                value={confirmPassword}
                onChange={e => setConfirmPassword(e.target.value)}
                placeholder="Repeat password"
                onKeyDown={e => e.key === "Enter" && handleSetPassword()}
                className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
              />
            </div>
            <button
              onClick={handleSetPassword}
              disabled={loading}
              className="w-full bg-emerald-500 hover:bg-emerald-400 disabled:opacity-50 text-black font-semibold rounded-xl py-3.5 text-sm transition-colors tracking-wide"
            >
              {loading ? "Saving..." : "Save new password ΓåÆ"}
            </button>
          </div>
        </div>
      </div>
    )
  }

  // ΓöÇΓöÇ INVITE PASSWORD (employee) ΓöÇΓöÇ
  if (screen === "invite-password") {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-5">
        <div className="w-full max-w-sm space-y-6">
          <div className="w-16 h-16 bg-emerald-500/10 border border-emerald-500/20 rounded-full flex items-center justify-center mx-auto">
            <span className="text-2xl">≡ƒæï</span>
          </div>

          <div className="text-center">
            <p className="text-zinc-500 text-xs font-mono uppercase tracking-widest mb-2">You've been invited</p>
            <h1 className="text-white font-bold text-2xl tracking-tight">
              Welcome{employeeName ? `, ${employeeName.split(" ")[0]}` : ""} to Elevate
            </h1>
            <p className="text-zinc-500 text-sm mt-2 leading-relaxed">
              Set your password to activate your account and get started.
            </p>
          </div>

          <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-5 space-y-4">
            {error && (
              <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
                <p className="text-red-400 text-sm">{error}</p>
              </div>
            )}
            <div>
              <label className="text-zinc-400 text-xs mb-2 block">Choose a password</label>
              <input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Min. 6 characters"
                autoFocus
                className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
              />
            </div>
            <div>
              <label className="text-zinc-400 text-xs mb-2 block">Confirm password</label>
              <input
                type="password"
                value={confirmPassword}
                onChange={e => setConfirmPassword(e.target.value)}
                placeholder="Repeat password"
                onKeyDown={e => e.key === "Enter" && handleSetPassword()}
                className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
              />
            </div>
            <button
              onClick={handleSetPassword}
              disabled={loading}
              className="w-full bg-emerald-500 hover:bg-emerald-400 disabled:opacity-50 text-black font-semibold rounded-xl py-3.5 text-sm transition-colors tracking-wide"
            >
              {loading ? "Activating..." : "Activate my account ΓåÆ"}
            </button>
          </div>

          <p className="text-zinc-600 text-xs text-center">
            This link expires after 24 hours for security.
          </p>
        </div>
      </div>
    )
  }
}

// src/pages/auth/ForgotPassword.jsx
import { useState } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"
import { SessionShell, UiButton } from "../../components/ui"

export default function ForgotPassword() {
  const navigate = useNavigate()
  const [email, setEmail] = useState("")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  // "form" | "sent"
  const [screen, setScreen] = useState("form")

  const handleSendReset = async () => {
    setError("")

    const trimmed = email.trim()
    if (!trimmed) { setError("Please enter your email address"); return }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    if (!emailRegex.test(trimmed)) { setError("That doesn't look like a valid email"); return }

    setLoading(true)

    try {
      const { error: resetError } = await supabase.auth.resetPasswordForEmail(trimmed, {
        redirectTo: `${window.location.origin}/reset-password`,
      })

      // Supabase returns success even if the email doesn't exist (security by design)
      // We only hard-fail on a real error (network, config, etc.)
      if (resetError) {
        setError(resetError.message)
        setLoading(false)
        return
      }

      // All good ΓÇö move to the "check your email" screen
      setScreen("sent")
    } catch (err) {
      setError("Something went wrong. Please try again.")
    }

    setLoading(false)
  }

  // ΓöÇΓöÇ SENT SCREEN ΓöÇΓöÇ
  if (screen === "sent") {
    return (
      <SessionShell
        badge="Email sent"
        title="Check your inbox for the reset link."
        subtitle={`We sent a password reset link to ${email.trim()}. Open the email and click the link to continue.`}
        points={[
          { title: "Open the email", text: "Find the email from Elevate in your inbox" },
          { title: "Click the link", text: "Tap the reset link inside the email" },
          { title: "Set new password", text: "Choose a strong password and you're all set" },
        ]}
        progress={[]}
        footer={
          <div className="flex items-center justify-between gap-4 text-sm">
            <span className="text-zinc-400">Didn't get it?</span>
            <button type="button" onClick={() => { setScreen("form"); setError("") }} className="text-emerald-300 hover:text-emerald-200 font-medium">Try again</button>
          </div>
        }
      >
        <div className="space-y-5">
          <div className="text-center">
            <div className="w-20 h-20 bg-emerald-500/10 border border-emerald-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-3xl">≡ƒô¼</span>
            </div>
            <p className="text-zinc-400 text-sm">
              Check your spam folder if you don't see it within a few minutes.
            </p>
          </div>

          <UiButton variant="secondary" className="w-full rounded-2xl py-3.5" onClick={() => navigate("/")}>
            ΓåÉ Back to sign in
          </UiButton>
        </div>
      </SessionShell>
    )
  }

  // ΓöÇΓöÇ FORM SCREEN ΓöÇΓöÇ
  return (
    <SessionShell
      badge="Reset password"
      title="Forgot your password?"
      subtitle="Enter the email address on your account and we'll send you a reset link to get back into your business."
      points={[
        { title: "Quick reset", text: "Get back into your account in under 2 minutes" },
        { title: "Secure link", text: "Reset links expire after 1 hour for security" },
        { title: "Email delivery", text: "Check your spam folder if you don't see the email" },
      ]}
      progress={[]}
      footer={
        <div className="flex items-center justify-between gap-4 text-sm">
          <span className="text-zinc-400">Remember your password?</span>
          <button type="button" onClick={() => navigate("/")} className="text-emerald-300 hover:text-emerald-200 font-medium">Sign in</button>
        </div>
      }
    >
      <div className="space-y-5">
        {error && <p className="rounded-2xl border border-red-400/20 bg-red-400/10 px-3 py-2 text-sm text-red-300">{error}</p>}

        <div className="space-y-4">
          <div>
            <label className="mb-1 block text-xs text-zinc-400">Email address</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSendReset()}
              placeholder="you@business.com"
              autoFocus
              className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
            />
          </div>
        </div>

        <UiButton variant="primary" className="w-full rounded-2xl py-3.5" onClick={handleSendReset} disabled={loading}>
          {loading ? "Sending link..." : "Send reset link ΓåÆ"}
        </UiButton>

        <p className="text-zinc-500 text-xs text-center">
          The link expires after 1 hour for security.
        </p>
      </div>
    </SessionShell>
  )
}

// src/pages/auth/ResetPassword.jsx
import { useState, useEffect } from "react"
import { useNavigate, useSearchParams } from "react-router-dom"
import { supabase } from "../../lib/supabase"
import { SessionShell, UiButton } from "../../components/ui"

export default function ResetPassword() {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const [password, setPassword] = useState("")
  const [confirmPassword, setConfirmPassword] = useState("")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const [success, setSuccess] = useState(false)

  useEffect(() => {
    // Check if we have the necessary tokens in the URL
    const accessToken = searchParams.get('access_token')
    const refreshToken = searchParams.get('refresh_token')

    if (!accessToken || !refreshToken) {
      setError("Invalid or expired reset link. Please request a new password reset.")
      setTimeout(() => navigate("/forgot-password"), 3000)
    }
  }, [searchParams, navigate])

  const handleResetPassword = async () => {
    setError("")

    if (!password) { 
      setError("Please enter a password"); 
      return 
    }
    if (password.length < 6) { 
      setError("Password must be at least 6 characters"); 
      return 
    }
    if (password !== confirmPassword) { 
      setError("Passwords do not match"); 
      return 
    }

    setLoading(true)

    try {
      const { error: updateError } = await supabase.auth.updateUser({ password })

      if (updateError) {
        setError(updateError.message)
        setLoading(false)
        return
      }

      setSuccess(true)
      setLoading(false)

      // Redirect to sign in after 2 seconds
      setTimeout(() => navigate("/"), 2000)
    } catch (err) {
      setError("Something went wrong. Please try again.")
      setLoading(false)
    }
  }

  // ΓöÇΓöÇ SUCCESS SCREEN ΓöÇΓöÇ
  if (success) {
    return (
      <SessionShell
        badge="Success"
        title="Password reset complete!"
        subtitle="Your password has been updated successfully. You can now sign in with your new password."
        points={[
          { title: "Password updated", text: "Your account password has been changed" },
          { title: "Secure access", text: "Your business data is now protected with your new password" },
          { title: "Ready to go", text: "Sign in and get back to managing your business" },
        ]}
        progress={[]}
        footer={
          <div className="text-center">
            <p className="text-zinc-400 text-sm">Redirecting to sign in...</p>
          </div>
        }
      >
        <div className="space-y-5">
          <div className="text-center">
            <div className="w-20 h-20 bg-emerald-500/10 border border-emerald-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-3xl">Γ£à</span>
            </div>
            <p className="text-zinc-400 text-sm">
              You'll be redirected to the sign in page automatically.
            </p>
          </div>

          <UiButton variant="primary" className="w-full rounded-2xl py-3.5" onClick={() => navigate("/")}>
            Sign in now ΓåÆ
          </UiButton>
        </div>
      </SessionShell>
    )
  }

  // ΓöÇΓöÇ RESET FORM SCREEN ΓöÇΓöÇ
  return (
    <SessionShell
      badge="Set new password"
      title="Choose a new password"
      subtitle="Create a strong password to secure your business account. Make it something memorable but hard to guess."
      points={[
        { title: "Strong password", text: "Use at least 6 characters with a mix of letters and numbers" },
        { title: "Keep it secure", text: "Don't reuse passwords from other accounts" },
        { title: "Business protection", text: "This password protects your business data and transactions" },
      ]}
      progress={[]}
      footer={
        <div className="flex items-center justify-between gap-4 text-sm">
          <span className="text-zinc-400">Need help?</span>
          <button type="button" onClick={() => navigate("/forgot-password")} className="text-emerald-300 hover:text-emerald-200 font-medium">Request new link</button>
        </div>
      }
    >
      <div className="space-y-5">
        {error && <p className="rounded-2xl border border-red-400/20 bg-red-400/10 px-3 py-2 text-sm text-red-300">{error}</p>}

        <div className="space-y-4">
          <div>
            <label className="mb-1 block text-xs text-zinc-400">New password</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="Min. 6 characters"
              autoFocus
              className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
            />
          </div>
          <div>
            <label className="mb-1 block text-xs text-zinc-400">Confirm new password</label>
            <input
              type="password"
              value={confirmPassword}
              onChange={e => setConfirmPassword(e.target.value)}
              placeholder="Repeat password"
              onKeyDown={e => e.key === "Enter" && handleResetPassword()}
              className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
            />
          </div>
        </div>

        <UiButton variant="primary" className="w-full rounded-2xl py-3.5" onClick={handleResetPassword} disabled={loading}>
          {loading ? "Saving..." : "Save new password ΓåÆ"}
        </UiButton>

        <p className="text-zinc-500 text-xs text-center">
          This reset link will expire after 1 hour for security.
        </p>
      </div>
    </SessionShell>
  )
}

// src/pages/auth/SignUp.jsx
import { useEffect, useState } from "react"
import { Link, useNavigate } from "react-router-dom"
import { supabase } from "../../lib/supabase"
import { getDb } from "../../lib/db"
import { SessionShell, UiButton } from "../../components/ui"

export default function SignUp() {
  const navigate = useNavigate()
  const [fullName, setFullName] = useState("")
  const [businessName, setBusinessName] = useState("")
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [confirmPassword, setConfirmPassword] = useState("")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session) navigate("/dashboard")
    })
  }, [navigate])

  const handleSignIn = async () => {
    await supabase.auth.signOut()
    navigate("/")
  }

  const handleSignUp = async () => {
    setError("")

    if (!fullName.trim() || !businessName.trim() || !email.trim() || !password) {
      setError("All fields are required")
      return
    }
    if (password.length < 6) {
      setError("Password must be at least 6 characters")
      return
    }
    if (password !== confirmPassword) {
      setError("Passwords do not match")
      return
    }

    setLoading(true)

    // Step 1: Create auth account
    const { data, error: signUpError } = await supabase.auth.signUp({
      email: email.trim(),
      password,
      options: {
        data: {
          full_name: fullName.trim(),
          business_name: businessName.trim(),
        },
      },
    })

    if (signUpError) {
      setError(signUpError.message)
      setLoading(false)
      return
    }

    if (!data.user) {
      setError("Failed to create account")
      setLoading(false)
      return
    }

    // Step 2: Sign in immediately to establish session
    const { error: signInError } = await supabase.auth.signInWithPassword({
      email: email.trim(),
      password,
    })

    if (signInError) {
      setError(signInError.message)
      setLoading(false)
      return
    }

    // Step 3: Create business row
    const { data: businessData, error: businessError } = await supabase
      .from("businesses")
      .insert({ name: businessName.trim(), type: "retail" })
      .select("id")
      .single()

    if (businessError) {
      setError("Failed to create business: " + businessError.message)
      setLoading(false)
      return
    }

    // Step 4: Create user row via RxDB
    const db = await getDb()
    const { error: userError } = await db.transactions.insert({
      id: `user-${data.user.id}`,
      business_id: businessData.id,
      branch_id: businessData.id,
      type: 'user_creation',
      transaction_type_tag: 'system',
      payment_account: 'system',
      account_code: 'system',
      date: new Date().toISOString(),
      created_by: data.user.id,
      lifecycle_state: 'completed',
      amount: 0,
      display_name: 'User Account Creation',
      user_data: {
        id: data.user.id,
        full_name: fullName.trim(),
        email: email.trim(),
        role: "owner",
        business_id: businessData.id,
        is_active: true,
      },
      _modified: Date.now(),
      _deleted: false,
    })

    if (userError) {
      setError("Failed to set up your account: " + userError.message)
      setLoading(false)
      return
    }

    setLoading(false)
    navigate("/onboarding")
  }

  return (
    <SessionShell
      badge="Get started"
      title="Create your business account in minutes."
      subtitle="Set up your owner account first. You'll add your team right after and start managing sales, stock, and cash flow from one place."
      points={[
        { title: "Fast setup", text: "Get your business running in under 5 minutes with our streamlined onboarding." },
        { title: "Team ready", text: "Add employees and assign roles right away - no waiting for IT setup." },
        { title: "Mobile first", text: "Manage everything from your phone or desktop, wherever you are." },
      ]}
      progress={[]}
      footer={
        <div className="flex items-center justify-between gap-4 text-sm">
          <span className="text-zinc-400">Already have an account?</span>
          <button type="button" onClick={handleSignIn} className="text-emerald-300 hover:text-emerald-200 font-medium">Sign in</button>
        </div>
      }
    >
      <div className="space-y-5">
        {error && <p className="rounded-2xl border border-red-400/20 bg-red-400/10 px-3 py-2 text-sm text-red-300">{error}</p>}

        <div className="space-y-4">
          <div>
            <label className="mb-1 block text-xs text-zinc-400">Full name</label>
            <input
              type="text"
              value={fullName}
              onChange={e => setFullName(e.target.value)}
              placeholder="Jane Wanjiku"
              className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
            />
          </div>

          <div>
            <label className="mb-1 block text-xs text-zinc-400">Business name</label>
            <input
              type="text"
              value={businessName}
              onChange={e => setBusinessName(e.target.value)}
              placeholder="Kamau General Store"
              className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
            />
          </div>

          <div>
            <label className="mb-1 block text-xs text-zinc-400">Email address</label>
            <input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="you@business.com"
              className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="mb-1 block text-xs text-zinc-400">Password</label>
              <input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Min. 6 characters"
                className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
              />
            </div>
            <div>
              <label className="mb-1 block text-xs text-zinc-400">Confirm password</label>
              <input
                type="password"
                value={confirmPassword}
                onChange={e => setConfirmPassword(e.target.value)}
                placeholder="Repeat password"
                className="w-full rounded-2xl border border-white/6 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
              />
            </div>
          </div>
        </div>

        <UiButton variant="primary" className="w-full rounded-2xl py-3.5" onClick={handleSignUp} disabled={loading}>
          {loading ? "Creating account..." : "Create account ΓåÆ"}
        </UiButton>
      </div>
    </SessionShell>
  )
}

// src/pages/dashboard/Dashboard.jsx
import { useState, useEffect, useMemo } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"
import FloatingBottomNav from "../../components/layout/FloatingBottomNav"
import { AppShell, UiButton } from "../../components/ui"
import { useUser, useIsOwnerOrManager, useIsCashier } from "../../hooks/useRole"
import { useInstantNavigation } from "../../hooks/useInstantNavigation"
import { useInstantAuth } from "../../hooks/useInstantAuth"
import { useBranchContext } from "../../context/BranchContext"
import { BranchSelector } from "../../components/BranchSelector"

const DASHBOARD_CACHE_KEY = 'elevate:dashboard:stats'
const WEEK_DAYS = ["All", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
const OWNER_PERIODS = ["Week", "Month"]
const EAT_OFFSET_MS = 3 * 60 * 60 * 1000

export default function Dashboard() {
  const navigate = useNavigate()
  const { user: authUser } = useUser()
  const { user: instantUser, business: instantBusiness, signOut } = useInstantAuth()
  const { navigateInstant } = useInstantNavigation()
  const isOwnerOrManager = useIsOwnerOrManager()
  const isCashier = useIsCashier()
  const { canViewAll, availableBranches, readyToFetch, activeBranch, viewMode, effectiveBranchId } = useBranchContext()
  const [business, setBusiness] = useState(null)
  const [stats, setStats] = useState({
    todaySales: 0,
    totalRevenue: 0,
    transactions: 0,
    lowStock: 0,
  })
  const [period, setPeriod] = useState("Week")
  const [selectedDay, setSelectedDay] = useState("All")
  const [periodTransactions, setPeriodTransactions] = useState([])
  const [todayTransactions, setTodayTransactions] = useState([])
  const [periodSummary, setPeriodSummary] = useState({
    totalSales: 0, totalExpenses: 0, net: 0, cash: 0, mpesa: 0, bank: 0,
  })
  const [todaySummary, setTodaySummary] = useState({
    totalSales: 0, totalExpenses: 0, net: 0, cash: 0, mpesa: 0,
  })
  const [lowStockItems, setLowStockItems] = useState([])
  const [loading, setLoading] = useState(true)
  const [periodLoading, setPeriodLoading] = useState(false)
  const [accessIssue, setAccessIssue] = useState("")
  
  // Clear today's activity immediately when branch changes
  useEffect(() => {
    setTodayTransactions([])
    setTodaySummary({ totalSales: 0, totalExpenses: 0, net: 0, cash: 0, mpesa: 0 })
  }, [effectiveBranchId])

  const setBusinessFromProfile = (profile, fallbackBusiness) => {
    const resolvedBusiness = fallbackBusiness || profile?.businesses || null
    if (!resolvedBusiness) return null

    const nextBusiness = {
      ...resolvedBusiness,
      userName: profile?.full_name || resolvedBusiness.userName || "",
    }
    setBusiness(nextBusiness)

    return nextBusiness
  }

  // Use instant auth data if available
  useEffect(() => {
    if (instantUser && instantBusiness) {
      setBusiness({ ...instantBusiness, userName: instantUser.full_name })
      setLoading(false)
      
      fetchDashboardData()
    } else if (authUser) {
      fetchDashboardData()
    }
  }, [instantUser, instantBusiness, authUser])

  useEffect(() => { if (business && readyToFetch) fetchPeriodData() }, [period, selectedDay, business, effectiveBranchId, readyToFetch])
  useEffect(() => { if (business && readyToFetch) fetchTodayData() }, [business, effectiveBranchId, readyToFetch])
  useEffect(() => { if (business && readyToFetch) fetchDashboardData() }, [business?.id, effectiveBranchId, readyToFetch])

  // Re-fetch data when window gains focus
  useEffect(() => {
    const handleFocus = () => {
      if (business && readyToFetch) {
        fetchDashboardData()
        fetchTodayData()
        fetchPeriodData()
      }
    }
    window.addEventListener('focus', handleFocus)
    return () => window.removeEventListener('focus', handleFocus)
  }, [business, readyToFetch])

  const getEATNow = () => new Date(Date.now() + EAT_OFFSET_MS)

  const toUtcIsoFromEAT = (eatDate) => new Date(eatDate.getTime() - EAT_OFFSET_MS).toISOString()

  const getTodayStartUtcIsoEAT = () => {
    const start = getEATNow()
    start.setUTCHours(0, 0, 0, 0)
    return toUtcIsoFromEAT(start)
  }

  const getWeekRange = () => {
    const nowEAT = getEATNow()
    const day = nowEAT.getUTCDay()
    const daysSinceMonday = (day + 6) % 7
    const start = new Date(nowEAT)
    start.setUTCDate(nowEAT.getUTCDate() - daysSinceMonday)
    start.setUTCHours(0, 0, 0, 0)
    return { start: toUtcIsoFromEAT(start), end: new Date().toISOString() }
  }

  const getSelectedDayRange = () => {
    const nowEAT = getEATNow()
    const day = nowEAT.getUTCDay()
    const daysSinceMonday = (day + 6) % 7
    const weekStart = new Date(nowEAT)
    weekStart.setUTCDate(nowEAT.getUTCDate() - daysSinceMonday)
    weekStart.setUTCHours(0, 0, 0, 0)

    const dayIndex = WEEK_DAYS.indexOf(selectedDay) - 1
    const start = new Date(weekStart)
    start.setUTCDate(weekStart.getUTCDate() + dayIndex)
    start.setUTCHours(0, 0, 0, 0)
    const end = new Date(start)
    end.setUTCHours(23, 59, 59, 999)
    return { start: toUtcIsoFromEAT(start), end: toUtcIsoFromEAT(end) }
  }

  const getPeriodRange = () => {
    const now = new Date()
    const start = getEATNow()
    start.setUTCHours(0, 0, 0, 0)

    if (period === "Week") {
      if (selectedDay !== "All") return getSelectedDayRange()
      return getWeekRange()
    } else if (period === "Month") {
      start.setUTCDate(1)
      start.setUTCHours(0, 0, 0, 0)
    }
    return { start: toUtcIsoFromEAT(start), end: now.toISOString() }
  }

  const fetchDashboardData = async () => {
    if (!authUser) {
      setLoading(false)
      return
    }

    setAccessIssue("")

    // Show cached stats immediately while fetching
    try {
      const cached = localStorage.getItem(DASHBOARD_CACHE_KEY)
      if (cached) {
        const { stats: cachedStats, lowStockItems: cachedLowStock } = JSON.parse(cached)
        setStats(cachedStats)
        setLowStockItems(cachedLowStock)
      }
    } catch {}

    const { data: userData, error: userError } = await supabase
      .from("users")
      .select("business_id, full_name, businesses(*)")
      .eq("id", authUser.id)
      .maybeSingle()

    if (userError || !userData) {
      setAccessIssue("Your account is signed in, but profile setup is incomplete. Please sign out and sign in again.")
      setLoading(false)
      return
    }

    const resolvedBusiness = setBusinessFromProfile(userData, userData.businesses)
    if (!resolvedBusiness) {
      setAccessIssue("Your business profile is missing. Please contact support or complete onboarding.")
      setLoading(false)
      return
    }

    const todayStart = getTodayStartUtcIsoEAT()
    const businessId = userData.business_id
    const branchFilter = effectiveBranchId

    const todayTxnsQuery = supabase
      .from("transactions")
      .select("id, branch_id, date, sale_items(total_amount)")
      .eq("business_id", businessId)
      .eq("type", "sale")
      .gte("date", todayStart)

    const allTxnsQuery = supabase
      .from("transactions")
      .select("id, branch_id, sale_items(total_amount)")
      .eq("business_id", businessId)
      .eq("type", "sale")

    const lowStockQuery = supabase
      .from("products")
      .select("id, branch_id, name, current_quantity, reorder_point")
      .eq("business_id", businessId)
      .eq("is_active", true)
      .limit(100)

    // Apply branch filtering if a specific branch is selected
    if (branchFilter) {
      todayTxnsQuery.eq("branch_id", branchFilter)
      allTxnsQuery.eq("branch_id", branchFilter)
      lowStockQuery.eq("branch_id", branchFilter)
    }

    const [todayTxnsResult, allTxnsResult, lowStockResult] = await Promise.all([
      todayTxnsQuery,
      allTxnsQuery,
      lowStockQuery,
    ])

    const todayTxns = todayTxnsResult?.data || []
    const allTxns = allTxnsResult?.data || []
    const lowStock = lowStockResult?.data || []

    const todaySales = todayTxns.reduce((sum, t) =>
      sum + (t.sale_items?.reduce((s, i) => s + i.total_amount, 0) || 0), 0) || 0

    const totalRevenue = allTxns.reduce((sum, t) =>
      sum + (t.sale_items?.reduce((s, i) => s + i.total_amount, 0) || 0), 0) || 0

    const filteredLowStock = (lowStock || [])
      .filter(p => p.current_quantity <= p.reorder_point)
      .slice(0, 5)

    setLowStockItems(filteredLowStock)
    setStats({
      todaySales,
      totalRevenue,
      transactions: todayTxns.length || 0,
      lowStock: filteredLowStock.length,
    })

    // Cache stats for offline display
    try {
      localStorage.setItem(DASHBOARD_CACHE_KEY, JSON.stringify({
        stats: { todaySales, totalRevenue, transactions: todayTxns.length, lowStock: filteredLowStock.length },
        lowStockItems: filteredLowStock,
        cachedAt: Date.now(),
      }))
    } catch {}

    setLoading(false)
  }

  const fetchTodayData = async () => {
    if (!business?.id) return

    const todayStart = getTodayStartUtcIsoEAT()
    const businessId = business.id

    // Build base queries
    const baseTxnQuery = supabase
      .from("transactions")
      .select(`id, type, payment_account, date,
        sale_items(total_amount, quantity, unit_price, products(name)),
        expenses(amount, category)`)
      .eq("business_id", businessId)
      .gte("date", todayStart)
      .order("date", { ascending: true })

    const baseAllTxnQuery = supabase
      .from("transactions")
      .select("type, payment_account, sale_items(total_amount), expenses(amount)")
      .eq("business_id", businessId)

    // Apply branch filtering if a specific branch is selected
    if (effectiveBranchId) {
      baseTxnQuery.eq("branch_id", effectiveBranchId)
      baseAllTxnQuery.eq("branch_id", effectiveBranchId)
    }

    const transfersQuery = supabase
      .from("transfers")
      .select("*")
      .eq("business_id", businessId)

    if (effectiveBranchId) transfersQuery.eq("branch_id", effectiveBranchId)

    const [txnsResult, floatResult, allTxnsResult, transfersResult] = await Promise.all([
      baseTxnQuery,
      supabase
        .from("float_baseline")
        .select("*")
        .eq("business_id", businessId)
        .maybeSingle(),
      baseAllTxnQuery,
      transfersQuery,
    ])

    const txns = txnsResult?.data || []
    const floatData = floatResult?.data || null
    const allTxns = allTxnsResult?.data || []
    const transfers = transfersResult?.data || []

    const enriched = txns.map(t => {
      if (t.type === "sale") {
        const amount = t.sale_items?.reduce((s, i) => s + i.total_amount, 0) || 0
        const name = t.sale_items?.length > 1
          ? `${t.sale_items[0].products?.name} +${t.sale_items.length - 1} more`
          : t.sale_items?.[0]?.products?.name || "Sale"
        return { ...t, amount, display_name: name }
      } else {
        const amount = t.expenses?.reduce((s, e) => s + e.amount, 0) || 0
        const name = t.expenses?.[0]?.category || "Expense"
        return { ...t, amount, display_name: name }
      }
    })

    setTodayTransactions(enriched)

    const todaySales = enriched.filter(t => t.type === "sale").reduce((s, t) => s + t.amount, 0)
    const todayExpenses = enriched.filter(t => t.type === "expense").reduce((s, t) => s + t.amount, 0)

    const calc = (account) => {
      const opening = floatData?.[`${account}_opening`] || 0
      const salesIn = (allTxns || [])
        .filter(t => t.type === "sale" && t.payment_account === account)
        .reduce((s, t) => s + (t.sale_items?.reduce((a, i) => a + i.total_amount, 0) || 0), 0)
      const expOut = (allTxns || [])
        .filter(t => t.type === "expense" && t.payment_account === account)
        .reduce((s, t) => s + (t.expenses?.reduce((a, e) => a + e.amount, 0) || 0), 0)
      const transferOut = (transfers || [])
        .filter(t => t.from_account === account)
        .reduce((s, t) => s + t.amount + t.transaction_cost, 0)
      const transferIn = (transfers || [])
        .filter(t => t.to_account === account)
        .reduce((s, t) => s + t.amount, 0)
      return opening + salesIn - expOut - transferOut + transferIn
    }

    setTodaySummary({
      totalSales: todaySales,
      totalExpenses: todayExpenses,
      net: todaySales - todayExpenses,
      cash: calc("cash"),
      mpesa: calc("mpesa"),
    })
  }

  const fetchPeriodData = async () => {
    if (!business?.id) return

    setPeriodLoading(true)
    const businessId = business.id
    const { start, end } = getPeriodRange()

    const txnsQuery = supabase
        .from("transactions")
        .select(`id, type, payment_account, date,
          sale_items(total_amount, products(name)),
          expenses(amount, category)`)
        .eq("business_id", businessId)
        .gte("date", start)
        .lte("date", end)
        .order("date", { ascending: false })

    const allTxnsQuery = supabase
        .from("transactions")
        .select("type, payment_account, sale_items(total_amount), expenses(amount)")
        .eq("business_id", businessId)

    const transfersQuery = supabase
        .from("transfers")
        .select("*")
        .eq("business_id", businessId)

    if (effectiveBranchId) {
      txnsQuery.eq("branch_id", effectiveBranchId)
      allTxnsQuery.eq("branch_id", effectiveBranchId)
      transfersQuery.eq("branch_id", effectiveBranchId)
    }

    const [txnsResult, floatResult, allTxnsResult, transfersResult] = await Promise.all([
      txnsQuery,
      supabase
        .from("float_baseline")
        .select("*")
        .eq("business_id", businessId)
        .maybeSingle(),
      allTxnsQuery,
      transfersQuery,
    ])

    const txns = txnsResult?.data || []
    const floatData = floatResult?.data || null
    const allTxns = allTxnsResult?.data || []
    const transfers = transfersResult?.data || []

    const enriched = txns.map(t => {
      if (t.type === "sale") {
        const amount = t.sale_items?.reduce((s, i) => s + i.total_amount, 0) || 0
        const name = t.sale_items?.length > 1
          ? `${t.sale_items[0].products?.name} +${t.sale_items.length - 1} more`
          : t.sale_items?.[0]?.products?.name || "Sale"
        return { ...t, amount, display_name: name }
      } else {
        const amount = t.expenses?.reduce((s, e) => s + e.amount, 0) || 0
        const name = t.expenses?.[0]?.category || "Expense"
        return { ...t, amount, display_name: name }
      }
    })

    setPeriodTransactions(enriched)

    const totalSales = enriched.filter(t => t.type === "sale").reduce((s, t) => s + t.amount, 0)
    const totalExpenses = enriched.filter(t => t.type === "expense").reduce((s, t) => s + t.amount, 0)

    const calc = (account) => {
      const opening = floatData?.[`${account}_opening`] || 0
      const salesIn = (allTxns || [])
        .filter(t => t.type === "sale" && t.payment_account === account)
        .reduce((s, t) => s + (t.sale_items?.reduce((a, i) => a + i.total_amount, 0) || 0), 0)
      const expOut = (allTxns || [])
        .filter(t => t.type === "expense" && t.payment_account === account)
        .reduce((s, t) => s + (t.expenses?.reduce((a, e) => a + e.amount, 0) || 0), 0)
      const transferOut = (transfers || [])
        .filter(t => t.from_account === account)
        .reduce((s, t) => s + t.amount + t.transaction_cost, 0)
      const transferIn = (transfers || [])
        .filter(t => t.to_account === account)
        .reduce((s, t) => s + t.amount, 0)
      return opening + salesIn - expOut - transferOut + transferIn
    }

    setPeriodSummary({
      totalSales,
      totalExpenses,
      net: totalSales - totalExpenses,
      cash: calc("cash"),
      mpesa: calc("mpesa"),
      bank: calc("bank"),
    })

    setPeriodLoading(false)
  }

  const handleSignOut = async () => {
    await signOut()
    navigateInstant("/")
  }

  const pageHeader = (
    <div className="rounded-2xl border border-zinc-800 bg-zinc-900/80 p-4 sm:p-5 shadow-lg shadow-black/10">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <p className="text-[10px] uppercase tracking-[0.24em] text-zinc-500">Store</p>
          <h1 className="text-white text-xl sm:text-2xl font-semibold tracking-tight">Dashboard</h1>
          <div className="mt-1 flex flex-wrap items-center gap-2">
            <p className="text-zinc-400 text-xs sm:text-sm">
              {business?.name}
            </p>
            {activeBranch && (
              <span className="inline-flex items-center px-2 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 text-[10px] font-medium">
                {activeBranch.name}
              </span>
            )}
            {!isOwnerOrManager && viewMode === 'all' && !activeBranch && (
              <span className="inline-flex items-center px-2 py-1 rounded-full bg-amber-500/10 border border-amber-500/20 text-amber-400 text-[10px] font-medium">
                No branch assigned
              </span>
            )}
            {isOwnerOrManager && viewMode === 'all' && !activeBranch && (
              <span className="inline-flex items-center px-2 py-1 rounded-full bg-zinc-800 border border-zinc-700 text-zinc-400 text-[10px] font-medium">
                All branches
              </span>
            )}
          </div>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          {canViewAll ? (
            <BranchSelector />
          ) : null}
          <UiButton variant="tertiary" size="sm" onClick={handleSignOut} className="text-zinc-400 hover:text-red-400">
            Sign out
          </UiButton>
        </div>
      </div>
    </div>
  )

  const fmt = (n) => `KES ${Number(n).toLocaleString("en-KE", { minimumFractionDigits: 2 })}`

  const pendingActions = useMemo(() => {
    const actions = []

    if (stats.lowStock > 0) {
      actions.push({
        title: "Low stock",
        detail: `${stats.lowStock} item${stats.lowStock === 1 ? "" : "s"} need review`,
        tone: "red",
      })
    }

    if (todaySummary.totalSales === 0) {
      actions.push({
        title: "No sales yet",
        detail: "Record the first sale of the day",
        tone: "amber",
      })
    }

    if (todaySummary.totalExpenses > todaySummary.totalSales) {
      actions.push({
        title: "Expenses ahead of sales",
        detail: `${Number(todaySummary.totalExpenses - todaySummary.totalSales).toLocaleString("en-KE", { minimumFractionDigits: 2 })} gap today`,
        tone: "amber",
      })
    }

    if (stats.totalRevenue === 0) {
      actions.push({
        title: "Setup still incomplete",
        detail: "Add products to start tracking revenue",
        tone: "zinc",
      })
    }

    return actions.slice(0, 3)
  }, [stats.lowStock, stats.totalRevenue, todaySummary.totalExpenses, todaySummary.totalSales])

  const QuickActions = () => (
    <div className="flex flex-wrap gap-2">
      <UiButton variant="primary" size="sm" onClick={() => navigateInstant("/transactions/add-sale")}>
        + Sale
      </UiButton>
      {isOwnerOrManager && (
        <UiButton variant="secondary" size="sm" onClick={() => navigateInstant("/transactions/add-expense")}>
          + Expense
        </UiButton>
      )}
    </div>
  )

  if (loading) return (
    <div className="min-h-screen bg-zinc-950 flex items-center justify-center">
      <p className="text-zinc-500 text-sm">Loading...</p>
    </div>
  )

  if (accessIssue) {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-5">
        <div className="w-full max-w-md bg-zinc-900 border border-zinc-800 rounded-2xl p-6 space-y-5">
          <div>
            <h2 className="text-white text-xl font-semibold">Account setup required</h2>
            <p className="text-zinc-400 text-sm mt-2">{accessIssue}</p>
          </div>
          <UiButton variant="primary" className="w-full" onClick={handleSignOut}>
            Sign out
          </UiButton>
        </div>
      </div>
    )
  }

  // ΓöÇΓöÇ SHARED TODAY COMPONENT ΓöÇΓöÇ
  const TodayReport = () => (
    <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-4 space-y-3">
      <h3 className="text-white font-semibold text-sm">Today's activity</h3>
      {todayTransactions.map((t, i) => (
        <div key={i} className="py-2 border-b border-zinc-800 last:border-0">
          <div className="flex items-center justify-between mb-1">
            <p className="text-zinc-500 text-xs">
              {new Date(t.date).toLocaleTimeString("en-KE", { hour: "2-digit", minute: "2-digit" })} ┬╖ {t.payment_account === "mpesa" ? "M-Pesa" : t.payment_account}
            </p>
          </div>
          {t.type === "sale" && t.sale_items?.length > 0 ? (
            <table className="w-full">
              <tbody>
                {t.sale_items.map((item, j) => (
                  <tr key={j}>
                    <td className="text-white text-xs py-0.5">{item.products?.name}</td>
                    <td className="text-zinc-500 text-xs py-0.5 text-right font-mono">{fmt(item.unit_price)}</td>
                    <td className="text-zinc-500 text-xs py-0.5 text-right px-2">├ù{item.quantity}</td>
                    <td className="text-emerald-400 text-xs py-0.5 text-right font-mono">{fmt(item.total_amount)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p className="text-white text-sm">{t.display_name}</p>
          )}
        </div>
      ))}

      <div className="border-t border-zinc-800 pt-3 space-y-2">
        <div className="flex justify-between">
          <p className="text-zinc-400 text-sm">Today's sales</p>
          <p className="text-emerald-400 text-sm font-mono">{fmt(todaySummary.totalSales)}</p>
        </div>
        <div className="flex justify-between">
          <p className="text-zinc-400 text-sm">Today's expenses</p>
          <p className="text-red-400 text-sm font-mono">-{fmt(todaySummary.totalExpenses)}</p>
        </div>
        <div className="flex justify-between border-t border-zinc-800 pt-2">
          <p className="text-white font-semibold text-sm">Net today</p>
          <p className={`text-sm font-mono font-bold ${todaySummary.net >= 0 ? "text-white" : "text-red-400"}`}>
            {fmt(todaySummary.net)}
          </p>
        </div>
      </div>

      <div className="border-t border-zinc-800 pt-3 space-y-3">
        <p className="text-zinc-500 text-xs">Business pulse</p>
        <div className="grid grid-cols-2 gap-2">
          <div className="rounded-xl bg-zinc-800 px-4 py-3">
            <p className="text-zinc-500 text-[11px] mb-1">Transactions today</p>
            <p className="text-white text-sm font-semibold">{stats.transactions}</p>
          </div>
          <div className="rounded-xl bg-zinc-800 px-4 py-3">
            <p className="text-zinc-500 text-[11px] mb-1">Low stock alerts</p>
            <p className={`text-sm font-semibold ${stats.lowStock > 0 ? "text-red-400" : "text-emerald-400"}`}>
              {stats.lowStock}
            </p>
          </div>
        </div>
        <div className="rounded-xl bg-zinc-800 px-4 py-3 border border-zinc-700">
          <p className="text-zinc-500 text-[11px] mb-1">Pending actions</p>
          {pendingActions.length > 0 ? (
            <div className="space-y-2">
              {pendingActions.map((action, index) => (
                <div key={index} className="flex items-start justify-between gap-3 rounded-lg bg-zinc-900/80 px-3 py-2">
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-white">{action.title}</p>
                    <p className="text-[11px] text-zinc-500">{action.detail}</p>
                  </div>
                  <span className={`shrink-0 rounded-full px-2 py-1 text-[10px] font-medium uppercase tracking-wider ${
                    action.tone === "red"
                      ? "bg-red-500/10 text-red-400"
                      : action.tone === "amber"
                      ? "bg-amber-500/10 text-amber-400"
                      : "bg-zinc-700 text-zinc-300"
                  }`}>
                    {action.tone === "red" ? "Now" : action.tone === "amber" ? "Soon" : "Info"}
                  </span>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-emerald-400 text-sm">All caught up</p>
          )}
        </div>
      </div>
    </div>
  )

  // ΓöÇΓöÇ CASHIER VIEW ΓöÇΓöÇ
  if (isCashier) {
    return (
      <AppShell
        className="pb-28"
        showHeader={false}
        contentClassName="max-w-lg space-y-4"
      >
          {pageHeader}

          <div>
            <h2 className="text-white text-xl font-bold">Good {getGreeting()}, {business?.userName?.split(" ")[0]}</h2>
            <p className="text-zinc-500 text-sm mt-1">
              {new Date().toLocaleDateString("en-KE", { weekday: "long", year: "numeric", month: "long", day: "numeric" })}
            </p>
          </div>
          <QuickActions />
          <TodayReport />

        <FloatingBottomNav
          activePath="/dashboard"
          itemClassName="px-6 py-2.5"
          items={[
            { label: "Dashboard", path: "/dashboard" },
            { label: "Transactions", path: "/transactions" },
          ]}
        />
      </AppShell>
    )
  }

  // ΓöÇΓöÇ OWNER / MANAGER VIEW ΓöÇΓöÇ
  return (
    <AppShell
      className="pb-28"
      showHeader={false}
      contentClassName="max-w-5xl space-y-6"
    >

        {pageHeader}

        <div>
          <h2 className="text-white text-2xl font-bold">Good {getGreeting()}, {business?.userName?.split(" ")[0]}</h2>
          <p className="text-zinc-500 text-sm mt-1">
            {new Date().toLocaleDateString("en-KE", { weekday: "long", year: "numeric", month: "long", day: "numeric" })}
          </p>
        </div>
        <QuickActions />

        {stats.totalRevenue === 0 && stats.lowStock === 0 && (
          <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-2xl p-4 flex items-center justify-between">
            <div>
              <p className="text-emerald-400 font-medium text-sm">Set up your inventory</p>
              <p className="text-zinc-400 text-xs mt-0.5">Add your products to start tracking stock and sales</p>
            </div>
            <button
              onClick={() => navigateInstant("/inventory")}
              className="bg-emerald-500 hover:bg-emerald-400 text-black text-xs font-semibold px-4 py-2 rounded-xl transition-colors"
            >
              Go to Inventory
            </button>
          </div>
        )}

        {/* Stat cards */}
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
          {[
            { label: "Today's sales", value: fmt(stats.todaySales), accent: "emerald" },
            { label: "Total revenue", value: fmt(stats.totalRevenue), accent: "emerald" },
            { label: "Transactions today", value: stats.transactions, accent: "blue" },
            { label: "Low stock alerts", value: stats.lowStock, accent: stats.lowStock > 0 ? "red" : "zinc" },
          ].map((s, i) => (
            <div key={i} className="bg-zinc-900 border border-zinc-800 rounded-2xl p-4">
              <p className="text-zinc-500 text-xs mb-2">{s.label}</p>
              <p className={`text-xl font-bold font-mono ${
                s.accent === "emerald" ? "text-emerald-400" :
                s.accent === "blue" ? "text-blue-400" :
                s.accent === "red" ? "text-red-400" : "text-white"
              }`}>{s.value}</p>
            </div>
          ))}
        </div>

        {/* Today report */}
        <TodayReport />

        {/* Period filter */}
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-4 space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-white font-semibold text-sm">Activity</h3>
            <div className="flex gap-1">
              {OWNER_PERIODS.map(p => (
                <button key={p} onClick={() => { setPeriod(p); setSelectedDay("All") }}
                  className={`px-3 py-1.5 rounded-xl text-xs font-medium transition-colors ${
                    period === p ? "bg-emerald-500 text-black" : "bg-zinc-800 text-zinc-400 hover:text-white"
                  }`}>
                  {p}
                </button>
              ))}
            </div>
          </div>

          {/* Week day drill-down */}
          {period === "Week" && (
            <div className="flex gap-1 overflow-x-auto pb-1">
              {WEEK_DAYS.map(d => (
                <button key={d} onClick={() => setSelectedDay(d)}
                  className={`flex-shrink-0 px-3 py-1.5 rounded-xl text-xs font-medium transition-colors ${
                    selectedDay === d ? "bg-zinc-600 text-white" : "bg-zinc-800 text-zinc-500 hover:text-white"
                  }`}>
                  {d}
                </button>
              ))}
            </div>
          )}

          {periodLoading ? (
            <p className="text-zinc-600 text-sm text-center py-6">Loading...</p>
          ) : (
            <>
              {periodTransactions.length === 0 ? (
                <p className="text-zinc-600 text-sm text-center py-6">No activity for this period</p>
              ) : (
                <div className="space-y-2 max-h-72 overflow-y-auto">
                  {periodTransactions.map((t, i) => (
                    <div key={i} className="flex items-center justify-between py-2 border-b border-zinc-800 last:border-0">
                      <div className="flex items-center gap-3">
                        <div className={`w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0 ${
                          t.type === "sale" ? "bg-emerald-500/10" : "bg-red-400/10"
                        }`}>
                          <span className="text-xs">{t.type === "sale" ? "Γåæ" : "Γåô"}</span>
                        </div>
                        <div>
                          <p className="text-white text-sm">{t.display_name}</p>
                          <p className="text-zinc-500 text-xs">
                            {new Date(t.date).toLocaleDateString("en-KE", { weekday: "short", month: "short", day: "numeric" })} ┬╖ {new Date(t.date).toLocaleTimeString("en-KE", { hour: "2-digit", minute: "2-digit" })} ┬╖ {t.payment_account === "mpesa" ? "M-Pesa" : t.payment_account}
                          </p>
                        </div>
                      </div>
                      <p className={`text-sm font-mono font-medium ${
                        t.type === "sale" ? "text-emerald-400" : "text-red-400"
                      }`}>
                        {t.type === "sale" ? "+" : "-"}{fmt(t.amount)}
                      </p>
                    </div>
                  ))}
                </div>
              )}

              <div className="border-t border-zinc-800 pt-4 space-y-2">
                <div className="flex justify-between">
                  <p className="text-zinc-400 text-sm">Total sales</p>
                  <p className="text-emerald-400 text-sm font-mono">{fmt(periodSummary.totalSales)}</p>
                </div>
                <div className="flex justify-between">
                  <p className="text-zinc-400 text-sm">Total expenses</p>
                  <p className="text-red-400 text-sm font-mono">-{fmt(periodSummary.totalExpenses)}</p>
                </div>
                <div className="flex justify-between border-t border-zinc-800 pt-2">
                  <p className="text-white font-semibold text-sm">Net</p>
                  <p className={`text-sm font-mono font-bold ${periodSummary.net >= 0 ? "text-white" : "text-red-400"}`}>
                    {fmt(periodSummary.net)}
                  </p>
                </div>
              </div>

              <div className="border-t border-zinc-800 pt-4">
                <p className="text-zinc-500 text-xs mb-3">Account balances</p>
                <div className="grid grid-cols-3 gap-2">
                  {[
                    { label: "Cash", value: periodSummary.cash, icon: "≡ƒÆ╡" },
                    { label: "M-Pesa", value: periodSummary.mpesa, icon: "≡ƒô▒" },
                    { label: "Bank", value: periodSummary.bank, icon: "≡ƒÅª" },
                  ].map((acc, i) => (
                    <div key={i} className="bg-zinc-800 rounded-xl p-3">
                      <div className="flex items-center gap-1 mb-1">
                        <span className="text-xs">{acc.icon}</span>
                        <p className="text-zinc-500 text-xs">{acc.label}</p>
                      </div>
                      <p className={`text-sm font-mono font-bold ${acc.value >= 0 ? "text-white" : "text-red-400"}`}>
                        {fmt(acc.value)}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>

        {/* Low stock */}
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-4">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-white font-semibold text-sm">Low stock alerts</h3>
            <button onClick={() => navigateInstant("/inventory")} className="text-xs text-emerald-500 hover:text-emerald-400">
              View all
            </button>
          </div>
          {lowStockItems.length === 0 ? (
            <p className="text-zinc-600 text-sm text-center py-4">All stock levels are healthy</p>
          ) : (
            <div className="space-y-3">
              {lowStockItems.map((p, i) => (
                <div key={i} className="flex items-center justify-between">
                  <div>
                    <p className="text-white text-sm">{p.name}</p>
                    <p className="text-zinc-500 text-xs">Reorder point: {p.reorder_point}</p>
                  </div>
                  <p className="text-red-400 text-sm font-mono">{p.current_quantity} left</p>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="h-28" />

      <FloatingBottomNav activePath="/dashboard" />
    </AppShell>
  )
}

function getGreeting() {
  const h = new Date().getHours()
  if (h < 12) return "morning"
  if (h < 17) return "afternoon"
  return "evening"
}

// src/pages/inventory/NewStock.jsx
import { useState, useEffect, useMemo } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"
import { useUser, useIsOwnerOrManager, useCurrentBusiness } from "../../hooks/useRole"
import { useBranchContext } from "../../context/BranchContext"
import { AppShell, UiButton, UiCard, UiSectionTitle, CategorySelect } from "../../components/ui"
import { getDb, startProductsReplication, startStockEntriesReplication } from "../../lib/db"
import { BranchSelector } from "../../components/BranchSelector"

export default function NewStock() {
  const navigate = useNavigate()
  const { user: authUser } = useUser()
  const isOwnerOrManager = useIsOwnerOrManager()
  const { businessId } = useCurrentBusiness()
  const { canViewAll, effectiveBranchId, readyToFetch } = useBranchContext()
  const [userId, setUserId] = useState(null)
  const [suppliers, setSuppliers] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const [success, setSuccess] = useState(false)

  // Product
  const [isNewProduct, setIsNewProduct] = useState(true)
  const [existingProducts, setExistingProducts] = useState([])
  const [selectedProduct, setSelectedProduct] = useState(null)
  const [productSearch, setProductSearch] = useState("")
  const [name, setName] = useState("")
  const [category, setCategory] = useState("")

  // Sourcing
  const [sourcingType, setSourcingType] = useState("local")
  const [supplierId, setSupplierId] = useState("")
  const [quantity, setQuantity] = useState("")
  const [totalPurchaseCost, setTotalPurchaseCost] = useState("")
  const [shippingClearingCost, setShippingClearingCost] = useState("")
  const [vatType, setVatType] = useState("inclusive")
  const [additionalCosts, setAdditionalCosts] = useState([])

  // Pricing
  const [sellingPrice, setSellingPrice] = useState("")
  const [composerStep, setComposerStep] = useState(1)
  const defaultUnit = "pcs"

  const categoryOptions = useMemo(() => {
    return Array.from(new Set(existingProducts.map((product) => product.category).filter(Boolean))).sort((a, b) => String(a).localeCompare(String(b)))
  }, [existingProducts])

  useEffect(() => {
    if (businessId && authUser && readyToFetch) {
      fetchInitialData()
    }
  }, [businessId, authUser, readyToFetch, effectiveBranchId, canViewAll])

  const fetchInitialData = async () => {
    if (canViewAll && !effectiveBranchId) {
      setExistingProducts([])
      setError("Select a branch before receiving stock")
      return
    }
    if (!effectiveBranchId) {
      setExistingProducts([])
      setError("Your branch is not assigned yet. Contact the owner.")
      return
    }

    setError("")
    setUserId(authUser.id)

    const { data: suppliersData } = await supabase
      .from("suppliers")
      .select("id, name")
      .eq("business_id", businessId)
      .eq("is_active", true)

    setSuppliers(suppliersData || [])

    const { data: productsData } = await supabase
      .from("products")
      .select("id, name, sku_id, selling_price, unit_of_measure, branch_id, branches!left(name, code), category")
      .eq("business_id", businessId)
      .eq("branch_id", effectiveBranchId)
      .eq("is_active", true)
      .order("name")

    setExistingProducts(productsData || [])
  }

  const generateSKU = (productName) => {
    const words = productName.trim().toUpperCase().split(" ")
    const base = words.map(w => w.slice(0, 3)).join("-")
    const suffix = Math.floor(Math.random() * 900 + 100)
    return `${base}-${suffix}`
  }

  // ΓöÇΓöÇ CALCULATIONS ΓöÇΓöÇ
  const qty = parseFloat(quantity) || 0
  const totalPurchase = parseFloat(totalPurchaseCost) || 0
  const shippingClearing = parseFloat(shippingClearingCost) || 0
  const unitCost = qty > 0 ? totalPurchase / qty : 0
  const stockValue = totalPurchase
  const fc = shippingClearing
  const additionalTotal = additionalCosts.reduce((s, c) => s + (parseFloat(c.amount) || 0), 0)
  const cif = totalPurchase + shippingClearing

  const importDuty = sourcingType === "import" ? cif * 0.25 : 0
  const idf = sourcingType === "import" ? cif * 0.035 : 0
  const rdl = sourcingType === "import" ? cif * 0.02 : 0
  const vatOnImport = sourcingType === "import" ? (cif + importDuty) * 0.16 : 0
  const totalDuties = importDuty + idf + rdl + vatOnImport

  const totalLandedCost = stockValue + fc + totalDuties + additionalTotal
  const landedCostPerUnit = qty > 0 ? totalLandedCost / qty : 0

  const suggestedLow = Math.ceil(landedCostPerUnit * 1.4)
  const suggestedHigh = Math.ceil(landedCostPerUnit * 1.8)

  const sp = parseFloat(sellingPrice) || 0
  const profitPerUnit = sp - landedCostPerUnit
  const profitTotal = profitPerUnit * qty

  const canProceedStep1 = isNewProduct ? Boolean(name.trim()) : Boolean(selectedProduct)
  const canProceedStep2 = Boolean(quantity) && Boolean(totalPurchaseCost)
  const canProceedStep3 = Boolean(sellingPrice)
  const canSubmit = canProceedStep1 && canProceedStep2 && canProceedStep3

  const fmt = (n) => `KES ${Number(n).toLocaleString("en-KE", { minimumFractionDigits: 2 })}`
  const fmtShort = (n) => `KES ${Math.round(n).toLocaleString("en-KE")}`

  // ΓöÇΓöÇ ADDITIONAL COSTS ΓöÇΓöÇ
  const addCostLine = () => setAdditionalCosts([...additionalCosts, { label: "", amount: "" }])
  const updateCostLine = (index, field, value) => {
    const updated = [...additionalCosts]
    updated[index][field] = value
    setAdditionalCosts(updated)
  }
  const removeCostLine = (index) => setAdditionalCosts(additionalCosts.filter((_, i) => i !== index))

  // ΓöÇΓöÇ SUBMIT ΓöÇΓöÇ
  const handleSubmit = async () => {
    setError("")
    if (!quantity || !totalPurchaseCost) { setError("Quantity and total purchase cost are required"); return }
    if (isNewProduct && !name) { setError("Product name is required"); return }
    if (!isNewProduct && !selectedProduct) { setError("Please select an existing product"); return }
    if (!sellingPrice) { setError("Selling price is required"); return }

    if (canViewAll && !effectiveBranchId) { setError("Select a branch before receiving stock"); return }
    if (!effectiveBranchId) { setError("Your branch is not assigned yet. Contact the owner."); return }

    setLoading(true)

    try {
      const db = await getDb()

      const productsReplication = startProductsReplication(db.products, businessId)
      const stockEntriesReplication = startStockEntriesReplication(db.stock_entries, businessId)

      const productId = isNewProduct ? crypto.randomUUID() : selectedProduct.id
      const branchId = effectiveBranchId || null

      if (isNewProduct) {
        await db.products.insert({
          id: productId,
          business_id: businessId,
          branch_id: branchId,
          sku_id: generateSKU(name),
          name,
          category: category || null,
          unit_of_measure: defaultUnit,
          buying_price: landedCostPerUnit,
          selling_price: parseFloat(sellingPrice),
          vat_type: vatType,
          current_quantity: qty,
          is_active: true,
          _modified: Date.now(),
          _deleted: false,
        })
      } else {
        const productDoc = await db.products.findOne(selectedProduct.id).exec()
        if (!productDoc) {
          throw new Error("Selected product not found")
        }

        const nextQty = Number(productDoc.current_quantity || 0) + qty
        await productDoc.incrementalPatch({
          buying_price: landedCostPerUnit,
          selling_price: parseFloat(sellingPrice),
          vat_type: vatType,
          current_quantity: nextQty,
          _modified: Date.now(),
        })
      }

      await db.stock_entries.insert({
        id: crypto.randomUUID(),
        business_id: businessId,
        branch_id: branchId,
        product_id: productId,
        supplier_id: supplierId || null,
        quantity: qty,
        buying_price: unitCost,
        freight_cost: shippingClearing,
        import_duty: importDuty,
        idf,
        rdl,
        vat_on_import: vatOnImport,
        insurance: 0,
        additional_costs: additionalCosts,
        total_cost: totalLandedCost,
        created_by: userId,
        _modified: Date.now(),
        _deleted: false,
      })

      productsReplication.reSync()
      stockEntriesReplication.reSync()

      setSuccess(true)
    } catch (submitError) {
      setError(submitError.message || "Failed to receive stock")
    } finally {
      setLoading(false)
    }
  }

  const resetForm = () => {
    setSuccess(false)
    setComposerStep(1)
    setName(""); setCategory("")
    setQuantity(""); setTotalPurchaseCost(""); setShippingClearingCost("")
    setAdditionalCosts([]); setSupplierId("")
    setSellingPrice(""); setSelectedProduct(null)
    setVatType("inclusive"); setIsNewProduct(true); setSourcingType("local")
  }

  // ΓöÇΓöÇ SUCCESS ΓöÇΓöÇ
  if (success) {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-4">
        <div className="w-full max-w-md text-center space-y-6">
          <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto border border-emerald-500/20">
            <span className="text-emerald-400 text-4xl">Γ£ô</span>
          </div>
          <div>
            <h2 className="text-white font-bold text-2xl tracking-tight">Stock received</h2>
            <p className="text-zinc-500 text-sm mt-2">Inventory has been updated successfully</p>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={resetForm} className="flex-1 bg-zinc-900 hover:bg-zinc-800 border border-zinc-700 text-white font-medium rounded-xl py-3 text-sm transition-colors">
              Add more
            </button>
            <button onClick={() => navigate("/inventory")} className="flex-1 bg-emerald-500 hover:bg-emerald-400 text-black font-semibold rounded-xl py-3 text-sm transition-colors">
              View inventory
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <AppShell
      title="Receive Stock"
      subtitle={`Step ${composerStep} of 4 ┬╖ Product ΓåÆ Sourcing ΓåÆ Pricing ΓåÆ Review`}
      contentClassName="max-w-6xl"
      right={
        <div className="flex items-center gap-2">
          <UiButton variant="tertiary" size="sm" onClick={() => navigate("/inventory")}>ΓåÉ Back</UiButton>
          {canViewAll ? <BranchSelector /> : null}
        </div>
      }
    >
      <div className="grid gap-4 lg:grid-cols-[1.3fr_0.7fr]">
        <div className="space-y-4">
          {error && (
            <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
              <p className="text-red-400 text-sm">{error}</p>
            </div>
          )}

          <div className="grid grid-cols-4 gap-2">
            {[
              { n: 1, label: "Identity" },
              { n: 2, label: "Sourcing" },
              { n: 3, label: "Pricing" },
              { n: 4, label: "Review" },
            ].map((s) => (
              <button
                key={s.n}
                onClick={() => {
                  if (s.n === 1) setComposerStep(1)
                  if (s.n === 2 && canProceedStep1) setComposerStep(2)
                  if (s.n === 3 && canProceedStep1 && canProceedStep2) setComposerStep(3)
                  if (s.n === 4 && canSubmit) setComposerStep(4)
                }}
                className={`rounded-xl px-3 py-2 text-xs font-medium transition-colors ${
                  composerStep === s.n
                    ? "bg-emerald-500 text-black"
                    : "bg-zinc-900 border border-zinc-800 text-zinc-500"
                }`}
              >
                {s.label}
              </button>
            ))}
          </div>

          {composerStep === 1 && (
            <Section label="01 ΓÇö Product Identity">
              <UiSectionTitle title="Choose what you are receiving" caption="Create a new product or top up an existing one" />
              <div className="flex gap-2 mb-5">
                <ToggleBtn active={isNewProduct} onClick={() => setIsNewProduct(true)}>New product</ToggleBtn>
                <ToggleBtn active={!isNewProduct} onClick={() => setIsNewProduct(false)}>Existing product</ToggleBtn>
              </div>

              {canViewAll && !effectiveBranchId && (
                <p className="text-amber-400 text-xs mb-3">Select a branch from the header before continuing.</p>
              )}

              {isNewProduct ? (
                <div className="space-y-4">
                  <Field label="Product name">
                    <Input value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Nike Air Max 90 Black Size 40" />
                    {name && <p className="text-zinc-600 text-xs mt-1.5 font-mono tracking-wide">SKU auto-generated on save</p>}
                  </Field>
                  <CategorySelect
                    label="Category"
                    value={category}
                    onChange={setCategory}
                    options={categoryOptions}
                    placeholder="Type or choose a category"
                  />
                  <p className="text-[11px] text-zinc-600">Unit is managed centrally and defaults to pcs for now.</p>
                </div>
              ) : (
                <div className="space-y-3">
                  <Input value={productSearch} onChange={e => setProductSearch(e.target.value)} placeholder="Search products..." />
                  <div className="space-y-1.5 max-h-64 overflow-y-auto">
                    {existingProducts
                      .filter(p => p.name.toLowerCase().includes(productSearch.toLowerCase()))
                      .map(p => (
                        <div
                          key={p.id}
                          onClick={() => setSelectedProduct(p)}
                          className={`flex items-center justify-between px-4 py-3 rounded-xl cursor-pointer transition-colors ${
                            selectedProduct?.id === p.id
                              ? "bg-emerald-500/10 border border-emerald-500/30"
                              : "bg-zinc-900 hover:bg-zinc-800 border border-zinc-800"
                          }`}
                        >
                          <div>
                            <p className="text-white text-sm font-medium">{p.name}</p>
                            <p className="text-zinc-600 text-xs font-mono mt-0.5">{p.sku_id}</p>
                          </div>
                          {selectedProduct?.id === p.id && <span className="text-emerald-400 text-sm">Γ£ô</span>}
                        </div>
                      ))}
                  </div>
                </div>
              )}
            </Section>
          )}

          {composerStep === 2 && (
            <Section label="02 ΓÇö Sourcing & Cost Build">
              <UiSectionTitle title="Capture intake cost" caption="This sets landed cost before pricing" />
              <div className="flex gap-2 mb-5">
                <ToggleBtn active={sourcingType === "local"} onClick={() => setSourcingType("local")}>Local</ToggleBtn>
                <ToggleBtn active={sourcingType === "import"} onClick={() => setSourcingType("import")}>Import</ToggleBtn>
              </div>

              <div className="space-y-4">
                <Field label="Supplier (optional)">
                  <select
                    value={supplierId}
                    onChange={e => setSupplierId(e.target.value)}
                    className="w-full bg-zinc-900 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors"
                  >
                    <option value="">No supplier</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </Field>

                <div className="grid grid-cols-2 gap-3">
                  <Field label="Amount paid to supplier (KES)">
                    <Input type="number" value={totalPurchaseCost} onChange={e => setTotalPurchaseCost(e.target.value)} placeholder="0.00" />
                  </Field>
                  <Field label="Quantity received">
                    <Input type="number" value={quantity} onChange={e => setQuantity(e.target.value)} placeholder="0" />
                  </Field>
                </div>

                {!!totalPurchaseCost && !!quantity && <StatRow label="Unit cost" value={fmt(unitCost)} accent />}

                <Field label="Transport / shipping cost (KES) ΓÇö optional">
                  <Input type="number" value={shippingClearingCost} onChange={e => setShippingClearingCost(e.target.value)} placeholder="0.00" />
                </Field>

                {sourcingType === "import" && quantity && totalPurchaseCost && (
                  <div className="bg-zinc-950 border border-zinc-800 rounded-xl p-4 space-y-2.5">
                    <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-3">Import duties ΓÇö auto-calculated</p>
                    {[
                      { label: "CIF value", value: fmt(cif), muted: true },
                      { label: "Import Duty (25%)", value: fmt(importDuty) },
                      { label: "IDF (3.5%)", value: fmt(idf) },
                      { label: "RDL (2%)", value: fmt(rdl) },
                      { label: "VAT on import (16%)", value: fmt(vatOnImport) },
                      { label: "Total duties", value: fmt(totalDuties), red: true, bold: true },
                    ].map((r, i) => (
                      <div key={i} className={`flex items-center justify-between ${r.bold ? "border-t border-zinc-800 pt-2.5 mt-1" : ""}`}>
                        <p className={`text-xs ${r.muted ? "text-zinc-600" : "text-zinc-400"}`}>{r.label}</p>
                        <p className={`text-xs font-mono ${r.red ? "text-red-400 font-bold" : r.muted ? "text-zinc-500" : "text-zinc-300"}`}>{r.value}</p>
                      </div>
                    ))}
                  </div>
                )}

                <div>
                  <div className="flex items-center justify-between mb-2">
                    <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium">Additional costs</p>
                    <button onClick={addCostLine} className="text-xs text-emerald-500 hover:text-emerald-400 transition-colors font-medium">+ Add line</button>
                  </div>
                  {additionalCosts.length > 0 && (
                    <div className="space-y-2">
                      {additionalCosts.map((cost, i) => (
                        <div key={i} className="flex items-center gap-2">
                          <input
                            type="text"
                            value={cost.label}
                            onChange={e => updateCostLine(i, "label", e.target.value)}
                            placeholder="Label (e.g. Insurance)"
                            className="flex-1 bg-zinc-950 border border-zinc-800 text-white rounded-xl px-3 py-2.5 text-xs outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
                          />
                          <input
                            type="number"
                            value={cost.amount}
                            onChange={e => updateCostLine(i, "amount", e.target.value)}
                            placeholder="0.00"
                            className="w-28 bg-zinc-950 border border-zinc-800 text-white rounded-xl px-3 py-2.5 text-xs outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
                          />
                          <button onClick={() => removeCostLine(i)} className="text-zinc-700 hover:text-red-400 transition-colors text-sm px-1">Γ£ò</button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </Section>
          )}

          {composerStep === 3 && (
            <Section label="03 ΓÇö Pricing">
              <UiSectionTitle title="Set selling strategy" caption="Price using landed cost and VAT mode" />
              <div className="space-y-5">
                <StatRow label="Landed cost / unit" value={fmt(landedCostPerUnit)} accent />

                <Field label="VAT on this product">
                  <div className="flex gap-2">
                    {[
                      { value: "none", label: "No VAT" },
                      { value: "inclusive", label: "Inclusive" },
                      { value: "exclusive", label: "Exclusive" },
                    ].map(opt => (
                      <ToggleBtn key={opt.value} active={vatType === opt.value} onClick={() => setVatType(opt.value)}>
                        {opt.label}
                      </ToggleBtn>
                    ))}
                  </div>
                </Field>

                <Field label={`Selling price (KES)${vatType === "inclusive" ? " ΓÇö VAT included" : vatType === "exclusive" ? " ΓÇö before VAT" : ""}`}>
                  <Input type="number" value={sellingPrice} onChange={e => setSellingPrice(e.target.value)} placeholder="0.00" />
                  {landedCostPerUnit > 0 && (
                    <p className="text-zinc-600 text-xs mt-1.5">Suggested range ┬╖ {fmtShort(suggestedLow)} ΓÇô {fmtShort(suggestedHigh)}</p>
                  )}
                </Field>

                {sp > 0 && (
                  <div className="space-y-2.5">
                    <div className="flex items-center justify-between">
                      <p className="text-sm text-zinc-400">Profit per unit</p>
                      <p className={`text-sm font-mono font-bold ${profitPerUnit > 0 ? "text-emerald-400" : "text-red-400"}`}>{fmt(profitPerUnit)}</p>
                    </div>
                    <div className="flex items-center justify-between border-t border-zinc-800 pt-3">
                      <p className="text-sm text-white font-medium">Profit for {qty} units</p>
                      <p className={`text-sm font-mono font-bold ${profitTotal > 0 ? "text-emerald-400" : "text-red-400"}`}>{fmt(profitTotal)}</p>
                    </div>
                  </div>
                )}
              </div>
            </Section>
          )}

          {composerStep === 4 && (
            <Section label="04 ΓÇö Review & Confirm">
              <UiSectionTitle title="Final check" caption="Verify values before inventory update" />
              <div className="space-y-2.5">
                <StatRow label="Product" value={isNewProduct ? (name || "-") : (selectedProduct?.name || "-")} />
                <StatRow label="Quantity" value={qty} />
                <StatRow label="Landed cost / unit" value={fmt(landedCostPerUnit)} />
                <StatRow label="Selling price" value={fmt(sp)} />
                <StatRow label="Total landed cost" value={fmt(totalLandedCost)} accent />
              </div>
            </Section>
          )}

          <UiCard className="p-4">
            <div className="flex items-center justify-between gap-2">
              <UiButton
                variant="secondary"
                onClick={() => setComposerStep((s) => Math.max(1, s - 1))}
                disabled={composerStep === 1 || loading}
              >
                Back
              </UiButton>

              {composerStep < 4 && (
                <UiButton
                  variant="primary"
                  onClick={() => setComposerStep((s) => Math.min(4, s + 1))}
                  disabled={
                    (composerStep === 1 && !canProceedStep1) ||
                    (composerStep === 2 && !canProceedStep2) ||
                    (composerStep === 3 && !canProceedStep3)
                  }
                >
                  Continue
                </UiButton>
              )}

              {composerStep === 4 && (
                <UiButton variant="primary" onClick={handleSubmit} disabled={loading || !canSubmit}>
                  {loading ? "Saving..." : "Receive stock"}
                </UiButton>
              )}
            </div>
          </UiCard>
        </div>

        <div className="space-y-4 lg:sticky lg:top-6 self-start">
          <UiCard className="p-5 space-y-3">
            <UiSectionTitle title="Live preview" caption="Realtime impact as you type" />
            <StatRow label="Product" value={isNewProduct ? (name || "Draft") : (selectedProduct?.name || "Select product")} />
            <StatRow label="Qty" value={qty || 0} />
            <StatRow label="Unit cost" value={fmt(unitCost)} />
            <StatRow label="Landed / unit" value={fmt(landedCostPerUnit)} accent />
            <StatRow label="Sell price" value={fmt(sp)} />
          </UiCard>

          <UiCard className="p-5 space-y-3">
            <UiSectionTitle title="Confidence checklist" />
            {[
              { ok: canProceedStep1, text: "Product is selected or named" },
              { ok: canProceedStep2, text: "Quantity and purchase cost provided" },
              { ok: canProceedStep3, text: "Selling price set" },
            ].map((item, i) => (
              <div key={i} className="flex items-center justify-between text-xs">
                <p className={item.ok ? "text-zinc-300" : "text-zinc-600"}>{item.text}</p>
                <span className={item.ok ? "text-emerald-400" : "text-zinc-700"}>{item.ok ? "Γ£ô" : "ΓÇó"}</span>
              </div>
            ))}
          </UiCard>
        </div>
      </div>
    </AppShell>
  )
}

// ΓöÇΓöÇ SUB-COMPONENTS ΓöÇΓöÇ

function Section({ label, children }) {
  return (
    <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
      <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-5">{label}</p>
      {children}
    </div>
  )
}

function Field({ label, children }) {
  return (
    <div>
      <label className="text-zinc-400 text-xs mb-2 block">{label}</label>
      {children}
    </div>
  )
}

function Input({ value, onChange, placeholder, type = "text" }) {
  return (
    <input
      type={type}
      value={value}
      onChange={onChange}
      placeholder={placeholder}
      className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
    />
  )
}

function ToggleBtn({ active, onClick, children }) {
  return (
    <button
      onClick={onClick}
      className={`flex-1 py-2.5 rounded-xl text-xs font-medium transition-colors ${
        active ? "bg-emerald-500 text-black" : "bg-zinc-950 border border-zinc-800 text-zinc-400 hover:text-white"
      }`}
    >
      {children}
    </button>
  )
}

function StatRow({ label, value, accent }) {
  return (
    <div className="flex items-center justify-between bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3">
      <p className="text-zinc-400 text-sm">{label}</p>
      <p className={`text-sm font-mono font-bold ${accent ? "text-emerald-400" : "text-white"}`}>{value}</p>
    </div>
  )
}

// src/pages/inventory/ProductDetail.jsx
import { useState, useEffect, useMemo } from "react"
import { useNavigate, useParams } from "react-router-dom"
import { AppShell, UiButton, UiCard, UiSectionTitle } from "../../components/ui"
import { useIsOwnerOrManager } from "../../hooks/useRole"
import { useBranchContext } from "../../context/BranchContext"
import { useInstantAuth } from "../../hooks/useInstantAuth"
import { useProducts } from "../../hooks/useProducts"
import { getDb } from "../../lib/db"

export default function ProductDetail() {
  const navigate = useNavigate()
  const { id } = useParams()
  const { business: instantBusiness } = useInstantAuth()
  const isOwnerOrManager = useIsOwnerOrManager()
  const { canViewAll, availableBranches, effectiveBranchId } = useBranchContext()
  const { products: allProducts } = useProducts(
    canViewAll ? null : effectiveBranchId,
    isOwnerOrManager,
  )
  const [product, setProduct] = useState(null)
  const [stockHistory, setStockHistory] = useState([])
  const [salesHistory, setSalesHistory] = useState([])
  const [loading, setLoading] = useState(true)
  const [editing, setEditing] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState("")
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [isAssigning, setIsAssigning] = useState(false)
  const [selectedBranch, setSelectedBranch] = useState("")

  const [name, setName] = useState("")
  const [category, setCategory] = useState("")
  const [unit, setUnit] = useState("")
  const [sellingPrice, setSellingPrice] = useState("")
  const [buyingPrice, setBuyingPrice] = useState("")
  const [reorderPoint, setReorderPoint] = useState("")

  // Get branch info once for reuse
  const currentBranchInfo = useMemo(() => {
    if (!product || !availableBranches.length) return null
    return availableBranches.find(b => b.id === product.branch_id)
  }, [product, availableBranches])

  useEffect(() => {
    if (allProducts.length > 0) {
      const foundProduct = allProducts.find(p => p.id === id)
      setProduct(foundProduct || null)
      setName(foundProduct?.name || "")
      setCategory(foundProduct?.category || "")
      setUnit(foundProduct?.unit_of_measure || "")
      setSellingPrice(foundProduct?.selling_price ?? "")
      setBuyingPrice(foundProduct?.buying_price ?? "")
      setReorderPoint(foundProduct?.reorder_point ?? "")
      setLoading(false)
    }
  }, [allProducts, id])

  const handleSave = async () => {
    setSaving(true)
    setError("")

    try {
      const db = await getDb()
      const updateData = {
        name,
        category: category || null,
        unit_of_measure: unit || null,
        selling_price: parseFloat(sellingPrice),
        buying_price: parseFloat(buyingPrice),
        reorder_point: parseInt(reorderPoint),
        _modified: Date.now(),
      }

      if (!canViewAll && effectiveBranchId) {
        updateData.branch_id = effectiveBranchId
      }

      await db.products.upsert(id, updateData)
      setEditing(false)
      // Update local state immediately
      setProduct(prev => ({ ...prev, ...updateData }))
    } catch (error) {
      setError(error.message)
    }
    setSaving(false)
  }

  const handleDeactivate = async () => {
    if (!confirm("Remove this product from inventory?")) return
    
    try {
      const db = await getDb()
      await db.products.upsert(id, {
        is_active: false,
        _modified: Date.now(),
      })
      setEditing(false)
      // Update local state immediately
      setProduct(prev => ({ ...prev, is_active: false }))
      navigate("/inventory")
    } catch (error) {
      setError(error.message)
    }
  }

  const fmt = (n) => `KES ${Number(n).toLocaleString("en-KE", { minimumFractionDigits: 2 })}`
  const isLowStock = product && product.current_quantity <= product.reorder_point
  const selling = Number(product?.selling_price || 0)
  const buying = Number(product?.buying_price || 0)
  const marginPerUnit = selling - buying
  const marginPct = selling > 0 ? (marginPerUnit / selling) * 100 : 0
  const stockValue = Number(product?.current_quantity || 0) * buying

  const accountLabel = (acc) => {
    if (acc === "mpesa") return "M-Pesa"
    return acc ? acc.charAt(0).toUpperCase() + acc.slice(1) : "-"
  }

  const goToSalesReport = (date) => {
    const d = new Date(date)
    const dateStr = d.toISOString().split("T")[0]
    navigate(`/settings/sales-report?date=${dateStr}`)
  }

  const handleBranchAssignment = async () => {
    if (!selectedBranch) {
      setError("Please select a branch")
      return
    }

    setIsAssigning(true)
    setError("")

    try {
      const db = await getDb()
      await db.products.upsert(id, {
        branch_id: selectedBranch,
        updated_at: new Date().toISOString(),
        _modified: Date.now(),
      })
      
      // Update local state for immediate feedback
      setProduct(prev => ({
        ...prev,
        branch_id: selectedBranch,
      }))
      
      // Close modal and reset on success
      setIsModalOpen(false)
      setSelectedBranch("")
    } catch (err) {
      setError(err.message || "Failed to assign branch")
    } finally {
      setIsAssigning(false)
    }
  }

  const needsBranchAssignment = product && !product.branch_id

  if (loading) {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center">
        <p className="text-zinc-500 text-sm">Loading...</p>
      </div>
    )
  }

  return (
    <AppShell
      title={product?.name || "Product"}
      subtitle={product?.sku_id || ""}
      contentClassName="max-w-6xl"
      right={(
        <>
          <UiButton variant="secondary" size="sm" onClick={() => navigate("/inventory")}>ΓåÉ Back</UiButton>
          <UiButton variant={editing ? "ghost" : "secondary"} size="sm" onClick={() => setEditing((v) => !v)}>
            {editing ? "Cancel" : "Edit"}
          </UiButton>
        </>
      )}
    >
      <div className="grid gap-4 lg:grid-cols-[1.35fr_0.65fr]">
        <div className="space-y-4">
          {error && (
            <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
              <p className="text-red-400 text-sm">{error}</p>
            </div>
          )}

          {/* ΓöÇΓöÇ Hero card ΓöÇΓöÇ */}
          <UiCard className="p-5 overflow-hidden relative">
            <div className="absolute inset-x-0 top-0 h-1 bg-gradient-to-r from-emerald-400 via-sky-400 to-emerald-400" />
            <div className="flex flex-col lg:flex-row lg:items-end lg:justify-between gap-5">
              <div className="space-y-3">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className={`text-[10px] px-2 py-1 rounded-full font-medium ${isLowStock ? "bg-red-400/10 text-red-400" : "bg-emerald-500/10 text-emerald-400"}`}>
                    {isLowStock ? "Low stock" : "Healthy"}
                  </span>
                  <span className="text-[10px] px-2 py-1 rounded-full font-medium bg-zinc-800 text-zinc-400">
                    {product?.unit_of_measure || "units"}
                  </span>
                </div>
                <div>
                  <h2 className="text-white text-2xl lg:text-3xl font-bold tracking-tight">{product?.name}</h2>
                  <p className="text-zinc-500 text-xs mt-1 font-mono">SKU {product?.sku_id}</p>
                </div>
              </div>
              <div className="flex flex-wrap gap-2">
                <UiButton variant="primary" onClick={() => navigate("/inventory/new-stock")}>+ Receive stock</UiButton>
                <UiButton variant="secondary" onClick={() => setEditing((v) => !v)}>{editing ? "View mode" : "Quick edit"}</UiButton>
              </div>
            </div>

            <div className="grid gap-3 mt-5 sm:grid-cols-3">
              <div className="bg-zinc-950/70 border border-zinc-800 rounded-2xl p-4">
                <p className="text-zinc-500 text-[10px] uppercase tracking-widest mb-2">In stock</p>
                <p className={`text-xl font-bold font-mono ${isLowStock ? "text-red-400" : "text-emerald-400"}`}>
                  {product?.current_quantity} {product?.unit_of_measure || "units"}
                </p>
              </div>
              <div className="bg-zinc-950/70 border border-zinc-800 rounded-2xl p-4">
                <p className="text-zinc-500 text-[10px] uppercase tracking-widest mb-2">Stock value</p>
                <p className="text-xl font-bold font-mono text-white">{fmt(stockValue)}</p>
              </div>
              <div className="bg-zinc-950/70 border border-zinc-800 rounded-2xl p-4">
                <p className="text-zinc-500 text-[10px] uppercase tracking-widest mb-2">Margin</p>
                <p className={`text-xl font-bold font-mono ${marginPerUnit >= 0 ? "text-emerald-400" : "text-red-400"}`}>
                  {fmt(marginPerUnit)}
                </p>
                <p className="text-zinc-600 text-xs mt-1">{marginPct.toFixed(1)}% per unit</p>
              </div>
            </div>

            {isLowStock && (
              <div className="mt-4 bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
                <p className="text-red-400 text-sm font-medium">Low stock warning</p>
                <p className="text-zinc-400 text-xs mt-0.5">
                  Current quantity ({product?.current_quantity}) is at or below reorder point ({product?.reorder_point})
                </p>
              </div>
            )}
          </UiCard>

          {/* ΓöÇΓöÇ Sales history ΓöÇΓöÇ */}
          <UiCard className="p-5">
            <UiSectionTitle title="Sales history" caption="Every unit sold ΓÇö click any row to see full day context" />
            {salesHistory.length === 0 ? (
              <p className="text-zinc-600 text-sm text-center py-8">No sales recorded for this product yet</p>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full min-w-[480px]">
                  <thead>
                    <tr className="border-b border-zinc-800">
                      <th className="text-left text-[10px] uppercase tracking-widest text-zinc-600 font-medium px-0 py-3">Date</th>
                      <th className="text-left text-[10px] uppercase tracking-widest text-zinc-600 font-medium px-4 py-3">Time</th>
