                      <th className="text-right text-[10px] uppercase tracking-widest text-zinc-600 font-medium px-0 py-3">Payment</th>
                    </tr>
                  </thead>
                  <tbody>
                    {salesHistory.map((sale, i) => {
                      const date = sale.transactions?.date
                      return (
                        <tr
