            </div>
          </UiCard>

          <UiCard className="p-5">
            <UiSectionTitle title="Danger zone" />
            <UiButton variant="secondary" className="w-full border-red-400/20 text-red-400 hover:border-red-400/40" onClick={handleDeactivate}>
              Remove from inventory
            </UiButton>
          </UiCard>
        </div>
