        <UiButton variant="primary" onClick={() => setEditing((v) => !v)}>{editing ? "View" : "Edit"}</UiButton>
      </div>

      {/* Branch Assignment Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] bg-black/60 flex items-center justify-center p-4">
          <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 max-w-md w-full">
            <div className="w-12 h-1 bg-zinc-700 rounded-full mx-auto mb-4" />
            <h3 className="text-white text-lg font-semibold mb-2">Assign Branch to SKU</h3>
            <p className="text-zinc-400 text-sm mb-4">
              SKU: <span className="font-mono text-emerald-400">{product?.sku_id}</span>
            </p>
            
            <div className="space-y-4">
              <div>
                <label className="text-zinc-400 text-xs mb-2 block">Select Branch</label>
                <select
                  value={selectedBranch}
                  onChange={(e) => setSelectedBranch(e.target.value)}
                  className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors"
                >
                  <option value="">Choose a branch...</option>
                  {availableBranches.map(branch => (
                    <option key={branch.id} value={branch.id}>
                      {branch.name} {branch.code ? `(${branch.code})` : ""}
                    </option>
                  ))}
                </select>
              </div>

              {error && (
                <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-3 py-2">
                  <p className="text-red-400 text-xs">{error}</p>
                </div>
              )}

              <div className="grid grid-cols-2 gap-3 pt-2">
                <button
                  onClick={() => {
                    setIsModalOpen(false)
                    setSelectedBranch("")
                    setError("")
                  }}
                  className="bg-zinc-800 hover:bg-zinc-700 text-zinc-200 rounded-xl py-3 text-sm font-medium transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={handleBranchAssignment}
                  disabled={!selectedBranch || isAssigning}
                  className="bg-emerald-500 hover:bg-emerald-400 text-black rounded-xl py-3 text-sm font-semibold transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isAssigning ? "Assigning..." : "Assign Branch"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </AppShell>
  )
}

// src/pages/inventory/Products.jsx
import { useState, useEffect } from "react"
import { useNavigate } from "react-router-dom"
import { AppShell, UiButton } from "../../components/ui"
import { useBranchContext } from "../../context/BranchContext"
import { useInstantAuth } from "../../hooks/useInstantAuth"
import { useProducts } from "../../hooks/useProducts"

export default function Products() {
  const navigate = useNavigate()
  const { business: instantBusiness } = useInstantAuth()
  const { canViewAll, availableBranches, effectiveBranchId, readyToFetch } = useBranchContext()
  const { products: liveProducts } = useProducts(
    canViewAll ? null : effectiveBranchId,
    canViewAll,
  )
  const [products, setProducts] = useState([])
  const [filtered, setFiltered] = useState([])
  const [search, setSearch] = useState("")
  const [categoryFilter, setCategoryFilter] = useState("all")
  const [branchFilter, setBranchFilter] = useState("all")
  const [statusFilter, setStatusFilter] = useState("all")
  const [categories, setCategories] = useState([])

  useEffect(() => {
    setProducts(liveProducts)
  }, [liveProducts])

  useEffect(() => {
    let result = products
    if (search) {
      result = result.filter(p =>
        (p.name || "").toLowerCase().includes(search.toLowerCase()) ||
        (p.sku_id || "").toLowerCase().includes(search.toLowerCase())
      )
    }
    if (categoryFilter !== "all") {
      result = result.filter((p) => p.category === categoryFilter)
    }
    if (canViewAll && branchFilter !== "all") {
      result = result.filter((p) => p.branch_id === branchFilter)
    }
    if (statusFilter !== "all") {
      if (statusFilter === "active") {
        result = result.filter((p) => Number(p.current_quantity || 0) > 0)
      } else if (statusFilter === "low") {
        result = result.filter((p) => Number(p.current_quantity || 0) <= Number(p.reorder_point || 0))
      } else if (statusFilter === "out") {
        result = result.filter((p) => Number(p.current_quantity || 0) === 0)
      }
    }

    setFiltered(result)
  }, [search, categoryFilter, branchFilter, statusFilter, products, canViewAll])

  useEffect(() => {
    setCategories([...new Set(products.map((p) => p.category).filter(Boolean))])
  }, [products])

  const fmt = (n) => `KES ${Number(n).toLocaleString("en-KE", { minimumFractionDigits: 2 })}`

  const totalProducts = products.length
  const activeProducts = products.filter((p) => Number(p.current_quantity || 0) > 0).length
  const lowStockProducts = products.filter((p) => Number(p.current_quantity || 0) <= Number(p.reorder_point || 0)).length
  const outOfStockProducts = products.filter((p) => Number(p.current_quantity || 0) === 0).length

  return (
    <AppShell
      title="Products"
      subtitle={canViewAll ? "Complete product catalog across all branches" : "Product catalog for your branch"}
      contentClassName="max-w-7xl"
      right={<UiButton variant="secondary" size="sm" onClick={() => navigate("/inventory")}>ΓåÉ Back to Inventory</UiButton>}
    >
      <div className="space-y-4">
        {/* Metrics */}
        <div className="grid gap-3 grid-cols-2 md:grid-cols-4">
          <MetricCard label="Total products" value={totalProducts} tone="emerald" />
          <MetricCard label="In stock" value={activeProducts} tone="sky" />
          <MetricCard label="Low stock" value={lowStockProducts} tone="amber" />
          <MetricCard label="Out of stock" value={outOfStockProducts} tone="red" />
        </div>

        {/* Filters */}
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-4">
          <div className="flex flex-col md:flex-row gap-3">
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search by name or SKU..."
              className="flex-1 bg-zinc-950 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
            />
            <select
              value={categoryFilter}
              onChange={(e) => setCategoryFilter(e.target.value)}
              className="bg-zinc-950 border border-zinc-700 text-zinc-300 rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500"
            >
              <option value="all">All categories</option>
              {categories.map((cat) => (
                <option key={cat} value={cat}>
                  {cat}
                </option>
              ))}
            </select>
            {canViewAll && (
              <select
                value={branchFilter}
                onChange={(e) => setBranchFilter(e.target.value)}
                className="bg-zinc-950 border border-zinc-700 text-zinc-300 rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500"
              >
                <option value="all">All branches</option>
                {availableBranches.map((branch) => (
                  <option key={branch.id} value={branch.id}>
                    {branch.name} {branch.code ? `(${branch.code})` : ""}
                  </option>
                ))}
              </select>
            )}
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="bg-zinc-950 border border-zinc-700 text-zinc-300 rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500"
            >
              <option value="all">All status</option>
              <option value="active">In stock</option>
              <option value="low">Low stock</option>
              <option value="out">Out of stock</option>
            </select>
          </div>
        </div>

        {/* Products Table */}
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden">
          <div className="px-4 py-3 border-b border-zinc-800">
            <p className="text-white text-sm font-medium">Product Catalog ({filtered.length} products)</p>
          </div>

          {filtered.length === 0 ? (
            <div className="text-center py-16 px-4">
              <p className="text-zinc-600 text-sm">No products found</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full min-w-[1000px]">
                <thead className="sticky top-0 bg-zinc-900 z-10">
                  <tr className="text-left text-[10px] uppercase tracking-wider text-zinc-500 border-b border-zinc-800">
                    <th className="py-3 px-4 font-medium">SKU</th>
                    <th className="py-3 px-4 font-medium">Product</th>
                    <th className="py-3 px-4 font-medium">Category</th>
                    <th className="py-3 px-4 font-medium">Branch</th>
                    <th className="py-3 px-4 font-medium text-right">Stock</th>
                    <th className="py-3 px-4 font-medium text-right">Buying</th>
                    <th className="py-3 px-4 font-medium text-right">Selling</th>
                    <th className="py-3 px-4 font-medium text-right">Margin</th>
                    <th className="py-3 px-4 font-medium">Status</th>
                    <th className="py-3 px-4 font-medium text-right">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((p) => {
                    const quantity = Number(p.current_quantity || 0)
                    const reorder = Number(p.reorder_point || 0)
                    const buying = Number(p.buying_price || 0)
                    const selling = Number(p.selling_price || 0)
                    const margin = selling - buying
                    const marginPct = selling > 0 ? (margin / selling) * 100 : 0
                    const isLowStock = quantity <= reorder
                    const isOutOfStock = quantity === 0

                    return (
                      <tr
                        key={p.id}
                        onClick={() => navigate(`/inventory/product/${p.id}`)}
                        className="border-b border-zinc-900 hover:bg-zinc-800/60 cursor-pointer transition-colors"
                      >
                        <td className="py-3 px-4 text-[11px] text-zinc-400 font-mono">{p.sku_id}</td>
                        <td className="py-3 px-4">
                          <p className="text-sm text-white font-medium leading-tight">{p.name}</p>
                        </td>
                        <td className="py-3 px-4 text-xs text-zinc-400">{p.category || "-"}</td>
                        <td className="py-3 px-4 text-xs text-zinc-400">
                          {(() => {
                            if (!canViewAll) {
                              // For non-owners/managers, don't show branch column
                              return "-"
                            }
                            if (!availableBranches || availableBranches.length === 0) {
                              return p.branch_id || "Loading..."
                            }
                            const branch = availableBranches.find(b => b.id === p.branch_id)
                            return branch ? `${branch.name}${branch.code ? ` (${branch.code})` : ""}` : p.branch_id || "Unknown"
                          })()}
                        </td>
                        <td className="py-3 px-4 text-xs text-right font-mono text-zinc-200">{quantity}</td>
                        <td className="py-3 px-4 text-xs text-right font-mono text-zinc-300">{fmt(buying)}</td>
                        <td className="py-3 px-4 text-xs text-right font-mono text-emerald-400">{fmt(selling)}</td>
                        <td className="py-3 px-4 text-xs text-right font-mono text-zinc-200">{fmt(margin)}</td>
                        <td className="py-3 px-4">
                          <span
                            className={`text-[10px] px-2 py-1 rounded-full font-medium ${
                              isOutOfStock ? "bg-red-400/10 text-red-400" : 
                              isLowStock ? "bg-amber-400/10 text-amber-400" : 
                              "bg-emerald-500/10 text-emerald-400"
                            }`}
                          >
                            {isOutOfStock ? "Out" : isLowStock ? "Low" : "In Stock"}
                          </span>
                        </td>
                        <td className="py-3 px-4 text-right">
                          <button
                            onClick={(e) => {
                              e.stopPropagation()
                              navigate(`/inventory/product/${p.id}`)
                            }}
                            className="bg-zinc-800 hover:bg-zinc-700 text-zinc-300 text-[11px] px-2 py-1 rounded-lg transition-colors"
                          >
                            View
                          </button>
                        </td>
                      </tr>
                    )
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </AppShell>
  )
}

function MetricCard({ label, value, tone = "emerald" }) {
  const toneClass = {
    emerald: "before:bg-emerald-400",
    sky: "before:bg-sky-400",
    amber: "before:bg-amber-400",
    red: "before:bg-red-400",
  }[tone]

  return (
    <div className={`relative overflow-hidden bg-zinc-900 border border-zinc-800 rounded-xl p-3 before:content-[''] before:absolute before:top-0 before:left-0 before:right-0 before:h-[2px] ${toneClass}`}>
      <p className="text-zinc-500 text-[10px] uppercase tracking-wide mb-1">{label}</p>
      <p className="font-bold font-mono text-white text-xl">{value}</p>
    </div>
  )
}

// src/pages/inventory/StockTake.jsx
import { useState, useEffect, useRef } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"
import { useCurrentBusiness } from "../../hooks/useRole"
import { useInstantAuth } from "../../hooks/useInstantAuth"
import { useBranchContext } from "../../context/BranchContext"
import { getDb, startTransactionsReplication } from "../../lib/db"
import { BranchSelector } from "../../components/BranchSelector"

function classifyABC(products) {
  if (!products.length) return {}
  const sorted = [...products]
    .map((p) => ({ id: p.id, value: (p.current_quantity || 0) * (p.buying_price || 0) }))
    .sort((a, b) => b.value - a.value)
  const total = sorted.length
  const result = {}
  sorted.forEach((p, i) => {
    const pct = (i + 1) / total
    result[p.id] = pct <= 0.2 ? "A" : pct <= 0.7 ? "B" : "C"
  })
  return result
}

const fmt = (n) => `KES ${Number(n).toLocaleString("en-KE", { minimumFractionDigits: 0 })}`

// ΓöÇΓöÇ SUB-COMPONENTS (matching NewStock aesthetic) ΓöÇΓöÇ

function Section({ label, children }) {
  return (
    <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-5">
      <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-5">{label}</p>
      {children}
    </div>
  )
}

function Field({ label, children }) {
  return (
    <div>
      <label className="text-zinc-400 text-xs mb-2 block">{label}</label>
      {children}
    </div>
  )
}

function Input({ value, onChange, placeholder, type = "text", min }) {
  return (
    <input
      type={type}
      value={value}
      onChange={onChange}
      placeholder={placeholder}
      min={min}
      className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
    />
  )
}

function ToggleBtn({ active, onClick, children }) {
  return (
    <button
      onClick={onClick}
      className={`flex-1 py-2.5 rounded-xl text-xs font-medium transition-colors ${
        active
          ? "bg-emerald-500 text-black"
          : "bg-zinc-950 border border-zinc-800 text-zinc-400 hover:text-white"
      }`}
    >
      {children}
    </button>
  )
}

function StatPill({ label, value, accent, red, amber, blue, purple }) {
  const color = accent
    ? "text-emerald-400"
    : red
    ? "text-red-400"
    : amber
    ? "text-amber-400"
    : blue
    ? "text-blue-400"
    : purple
    ? "text-purple-400"
    : "text-white"
  return (
    <div className="flex items-center justify-between bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3">
      <p className="text-zinc-400 text-sm">{label}</p>
      <p className={`text-sm font-mono font-bold ${color}`}>{value}</p>
    </div>
  )
}

function ABCBadge({ cls }) {
  const style =
    cls === "A"
      ? "bg-purple-500/10 text-purple-400 border-purple-500/20"
      : cls === "B"
      ? "bg-blue-500/10 text-blue-400 border-blue-500/20"
      : "bg-zinc-800 text-zinc-500 border-zinc-700"
  return (
    <span className={`text-[10px] font-mono px-2 py-0.5 rounded-full border ${style}`}>{cls}</span>
  )
}

function StatusBadge({ status }) {
  const style =
    status === "approved"
      ? "bg-emerald-500/10 text-emerald-400"
      : status === "counting"
      ? "bg-amber-400/10 text-amber-400"
      : "bg-zinc-800 text-zinc-400"
  return (
    <span className={`text-[10px] font-mono px-2.5 py-1 rounded-full capitalize ${style}`}>
      {status}
    </span>
  )
}

function ErrorBanner({ msg }) {
  if (!msg) return null
  return (
    <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
      <p className="text-red-400 text-sm">{msg}</p>
    </div>
  )
}

function PrimaryBtn({ onClick, disabled, loading, children }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled || loading}
      className="w-full bg-emerald-500 hover:bg-emerald-400 disabled:opacity-40 text-black font-semibold rounded-xl py-4 text-sm transition-colors tracking-wide"
    >
      {loading ? "Please wait..." : children}
    </button>
  )
}

// ΓöÇΓöÇ MAIN COMPONENT ΓöÇΓöÇ

export default function StockTake() {
  const navigate = useNavigate()
  const [userId, setUserId] = useState(null)
  const [allProducts, setAllProducts] = useState([])
  const [products, setProducts] = useState([])
  const [abcMap, setAbcMap] = useState({})
  const [counts, setCounts] = useState({})
  const [causes, setCauses] = useState({})
  const [step, setStep] = useState("setup") // setup | brief | counting | review | done
  const [stockTakeId, setStockTakeId] = useState(null)
  const [type, setType] = useState("full")
  const [spotSearch, setSpotSearch] = useState("")
  const [spotSelected, setSpotSelected] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const [pastStockTakes, setPastStockTakes] = useState([])
  const [selectedVarianceId, setSelectedVarianceId] = useState(null)
  const replicationRef = useRef(null)
  const { user } = useInstantAuth()
  const { businessId } = useCurrentBusiness()
  const { canViewAll, effectiveBranchId, readyToFetch } = useBranchContext()
  const resolvedBranchId = effectiveBranchId

  useEffect(() => {
    let mounted = true

    const ensureReplication = async () => {
      if (!businessId) return
      const db = await getDb()
      if (!mounted) return

      if (!replicationRef.current) {
        replicationRef.current = startTransactionsReplication(db.transactions, businessId)
      }
    }

    ensureReplication()

    return () => {
      mounted = false
      replicationRef.current?.cancel?.()
      replicationRef.current = null
    }
  }, [businessId])

  useEffect(() => {
    if (readyToFetch && businessId && user?.id) {
      fetchInitialData(businessId, user.id)
    }
  }, [businessId, user?.id, readyToFetch, resolvedBranchId])

  const fetchInitialData = async (resolvedBusinessId, resolvedUserId) => {
    if (!resolvedBusinessId || !resolvedUserId) return
    if (canViewAll && !resolvedBranchId) {
      setError("Select a branch before running a stock take")
      setAllProducts([])
      setProducts([])
      return
    }
    if (!resolvedBranchId) {
      setError("Your branch is not assigned yet. Contact the owner.")
      setAllProducts([])
      setProducts([])
      return
    }

    setUserId(resolvedUserId)
    setError("")

    const [productsResult, pastResult] = await Promise.all([
      supabase
        .from("products")
        .select("id, name, sku_id, current_quantity, unit_of_measure, category, buying_price")
        .eq("business_id", resolvedBusinessId)
        .eq("branch_id", resolvedBranchId)
        .eq("is_active", true)
        .order("name"),
      supabase
        .from("stock_takes")
        .select("*")
        .eq("business_id", resolvedBusinessId)
        .eq("branch_id", resolvedBranchId)
        .order("created_at", { ascending: false })
        .limit(5),
    ])

    const prods = productsResult?.data || []
    setAllProducts(prods)
    setAbcMap(classifyABC(prods))
    setPastStockTakes(pastResult?.data || [])
  }

  const getProductsForType = (t, spotId = null) => {
    if (t === "full") return allProducts
    if (t === "cycle_count") return allProducts.filter((p) => ["A", "B"].includes(abcMap[p.id]))
    if (t === "spot_check") return spotId ? allProducts.filter((p) => p.id === spotId) : []
    return allProducts
  }

  const variance = (productId, expectedQty) => {
    const actual = parseFloat(counts[productId] ?? expectedQty)
    return actual - expectedQty
  }

  const totalKesVariance = () =>
    products.reduce((sum, p) => sum + variance(p.id, p.current_quantity) * (p.buying_price || 0), 0)

  const proceedToBrief = () => {
    const filtered = getProductsForType(type, spotSelected?.id)
    if (type === "spot_check" && !spotSelected) { setError("Select a product for spot check"); return }
    setProducts(filtered)
    const initCounts = {}
    const initCauses = {}
    filtered.forEach((p) => { initCounts[p.id] = p.current_quantity; initCauses[p.id] = "none" })
    setCounts(initCounts)
    setCauses(initCauses)
    setError("")
    setStep("brief")
  }

  const startCount = async () => {
    if (!resolvedBranchId) {
      setError("Branch is required to start stock take")
      return
    }

    setLoading(true)
    setError("")

    const newStockTakeId = crypto.randomUUID()

    const stockTake = {
      id: newStockTakeId,
      business_id: businessId,
      branch_id: resolvedBranchId,
      type,
      start_date: new Date().toISOString(),
      status: "counting",
      counted_by: userId,
    }

    const db = await getDb()
    await db.transactions.insert({
      id: crypto.randomUUID(),
      business_id: businessId,
      branch_id: resolvedBranchId,
      type: "stock_take_create",
      transaction_type_tag: "inventory_control",
      payment_account: "system",
      account_code: "0000",
      date: new Date().toISOString(),
      created_by: userId,
      lifecycle_state: "finalized",
      amount: 0,
      display_name: "Stock take create",
      stock_take: stockTake,
    })
    replicationRef.current?.reSync?.()

    setStockTakeId(newStockTakeId)
    setStep("counting")
    setLoading(false)
  }

  const submitCounts = async () => {
    setLoading(true)
    setError("")

    const items = products.map((p) => ({
      stock_take_id: stockTakeId,
      product_id: p.id,
      expected_quantity: p.current_quantity,
      actual_quantity: parseFloat(counts[p.id] ?? p.current_quantity),
    }))

    const db = await getDb()
    await db.transactions.insert({
      id: crypto.randomUUID(),
      business_id: businessId,
      branch_id: resolvedBranchId,
      type: "stock_take_submit_counts",
      transaction_type_tag: "inventory_control",
      payment_account: "system",
      account_code: "0000",
      date: new Date().toISOString(),
      created_by: userId,
      lifecycle_state: "finalized",
      amount: 0,
      display_name: "Stock take submit counts",
      stock_take_id: stockTakeId,
      stock_take_items: items,
    })
    replicationRef.current?.reSync?.()

    setStep("review")
    setLoading(false)
  }

  const approveStockTake = async () => {
    setLoading(true)
    setError("")

    const approvalPayload = {
      stockTakeId,
      approvedBy: userId,
      endDate: new Date().toISOString(),
    }

    const db = await getDb()
    await db.transactions.insert({
      id: crypto.randomUUID(),
      business_id: businessId,
      branch_id: resolvedBranchId,
      type: "stock_take_approve",
      transaction_type_tag: "inventory_control",
      payment_account: "system",
      account_code: "0000",
      date: new Date().toISOString(),
      created_by: userId,
      lifecycle_state: "finalized",
      amount: 0,
      display_name: "Stock take approve",
      stock_take_approval: approvalPayload,
    })
    replicationRef.current?.reSync?.()

    setStep("done")
    setLoading(false)
  }

  // ΓöÇΓöÇ STEP 1: SETUP ΓöÇΓöÇ
  if (step === "setup") {
    const typeOptions = [
      { value: "full", label: "Full count", desc: `Count all ${allProducts.length} products`, count: allProducts.length },
      { value: "cycle_count", label: "Cycle count", desc: "A and B class products only", count: allProducts.filter((p) => ["A", "B"].includes(abcMap[p.id])).length },
      { value: "spot_check", label: "Spot check", desc: "One specific product", count: 1 },
    ]

    return (
      <div className="min-h-screen bg-zinc-950 pb-16">
        {/* Header */}
        <div className="px-5 pt-8 pb-6">
          <button onClick={() => navigate("/inventory")} className="flex items-center gap-2 text-zinc-500 hover:text-white transition-colors text-sm mb-6">
            ΓåÉ Back
          </button>
          <h1 className="text-white font-bold text-2xl tracking-tight">Stock Take</h1>
          <p className="text-zinc-500 text-sm mt-1">Choose the type of count to run</p>
          <div className="mt-3">
            {canViewAll ? <BranchSelector /> : null}
          </div>
        </div>

        <div className="px-5 max-w-2xl mx-auto space-y-4">
          <ErrorBanner msg={error} />

          {/* 01 ΓÇö Count type */}
          <Section label="01 ΓÇö Count Type">
            <div className="flex gap-2 mb-1">
              {typeOptions.map((t) => (
                <ToggleBtn key={t.value} active={type === t.value} onClick={() => { setType(t.value); setSpotSelected(null); setSpotSearch("") }}>
                  {t.label}
                </ToggleBtn>
              ))}
            </div>

            <div className="mt-4 space-y-3">
              {typeOptions.map((t) => (
                <div
                  key={t.value}
                  onClick={() => { setType(t.value); setSpotSelected(null); setSpotSearch("") }}
                  className={`flex items-center justify-between px-4 py-3 rounded-xl cursor-pointer transition-colors border ${
                    type === t.value
                      ? "bg-emerald-500/10 border-emerald-500/30"
                      : "bg-zinc-950 border-zinc-800 hover:border-zinc-700"
                  }`}
                >
                  <div>
                    <p className={`text-sm font-medium ${type === t.value ? "text-emerald-400" : "text-white"}`}>{t.label}</p>
                    <p className="text-zinc-500 text-xs mt-0.5">{t.desc}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="text-[10px] font-mono text-zinc-500 bg-zinc-800 px-2.5 py-1 rounded-full">
                      {t.count} {t.count === 1 ? "product" : "products"}
                    </span>
                    {type === t.value && <span className="text-emerald-400 text-sm">Γ£ô</span>}
                  </div>
                </div>
              ))}
            </div>
          </Section>

          {/* Spot check product picker */}
          {type === "spot_check" && (
            <Section label="02 ΓÇö Select Product">
              <Input
                value={spotSearch}
                onChange={(e) => setSpotSearch(e.target.value)}
                placeholder="Search by name or SKU..."
              />
              {spotSearch && (
                <div className="mt-3 space-y-1.5 max-h-48 overflow-y-auto">
                  {allProducts
                    .filter((p) =>
                      p.name.toLowerCase().includes(spotSearch.toLowerCase()) ||
                      p.sku_id.toLowerCase().includes(spotSearch.toLowerCase())
                    )
                    .map((p) => (
                      <div
                        key={p.id}
                        onClick={() => setSpotSelected(p)}
                        className={`flex items-center justify-between px-4 py-3 rounded-xl cursor-pointer transition-colors border ${
                          spotSelected?.id === p.id
                            ? "bg-emerald-500/10 border-emerald-500/30"
                            : "bg-zinc-950 border-zinc-800 hover:border-zinc-700"
                        }`}
                      >
                        <div>
                          <p className="text-white text-sm font-medium">{p.name}</p>
                          <p className="text-zinc-600 text-xs font-mono mt-0.5">{p.sku_id}</p>
                        </div>
                        <div className="flex items-center gap-2">
                          <ABCBadge cls={abcMap[p.id] || "C"} />
                          {spotSelected?.id === p.id && <span className="text-emerald-400 text-sm">Γ£ô</span>}
                        </div>
                      </div>
                    ))}
                </div>
              )}
              {spotSelected && (
                <div className="mt-3 flex items-center justify-between bg-emerald-500/10 border border-emerald-500/20 rounded-xl px-4 py-3">
                  <p className="text-emerald-400 text-sm font-medium">{spotSelected.name}</p>
                  <button onClick={() => setSpotSelected(null)} className="text-zinc-500 hover:text-red-400 transition-colors text-sm">Γ£ò</button>
                </div>
              )}
            </Section>
          )}

          {/* Past stock takes */}
          {pastStockTakes.length > 0 && (
            <Section label={type === "spot_check" ? "03 ΓÇö Recent Stock Takes" : "02 ΓÇö Recent Stock Takes"}>
              <div className="space-y-3">
                {pastStockTakes.map((st, i) => (
                  <div key={i} className="flex items-center justify-between py-1">
                    <div>
                      <p className="text-white text-sm font-medium capitalize">{st.type.replace("_", " ")}</p>
                      <p className="text-zinc-600 text-xs mt-0.5">{new Date(st.created_at).toLocaleDateString("en-KE")}</p>
                    </div>
                    <StatusBadge status={st.status} />
                  </div>
                ))}
              </div>
            </Section>
          )}

          <PrimaryBtn onClick={proceedToBrief} loading={false}>Continue ΓåÆ</PrimaryBtn>
          <div className="h-4" />
        </div>
      </div>
    )
  }

  // ΓöÇΓöÇ STEP 2: BRIEF ΓöÇΓöÇ
  if (step === "brief") {
    const systemValue = products.reduce((s, p) => s + p.current_quantity * (p.buying_price || 0), 0)
    const aCount = products.filter((p) => abcMap[p.id] === "A").length
    const bCount = products.filter((p) => abcMap[p.id] === "B").length
    const cCount = products.filter((p) => abcMap[p.id] === "C").length
    const typeLabel = type === "full" ? "Full Count" : type === "cycle_count" ? "Cycle Count" : "Spot Check"

    return (
      <div className="min-h-screen bg-zinc-950 pb-16">
        <div className="px-5 pt-8 pb-6">
          <button onClick={() => setStep("setup")} className="flex items-center gap-2 text-zinc-500 hover:text-white transition-colors text-sm mb-6">
            ΓåÉ Back
          </button>
          <h1 className="text-white font-bold text-2xl tracking-tight">{typeLabel}</h1>
          <p className="text-zinc-500 text-sm mt-1">{products.length} product{products.length !== 1 ? "s" : ""} to count</p>
        </div>

        <div className="px-5 max-w-2xl mx-auto space-y-4">

          {/* 01 ΓÇö System snapshot */}
          <Section label="01 ΓÇö System Snapshot ┬╖ Frozen at Start">
            <div className="grid grid-cols-2 gap-3 mb-4">
              <div className="bg-zinc-950 border border-zinc-800 rounded-xl p-4 relative overflow-hidden">
                <div className="absolute top-0 left-0 right-0 h-0.5 bg-emerald-500 opacity-70" />
                <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-2">Products</p>
                <p className="text-emerald-400 text-2xl font-mono font-bold">{products.length}</p>
              </div>
              <div className="bg-zinc-950 border border-zinc-800 rounded-xl p-4 relative overflow-hidden">
                <div className="absolute top-0 left-0 right-0 h-0.5 bg-blue-400 opacity-70" />
                <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-2">Stock Value</p>
                <p className="text-blue-400 text-sm font-mono font-bold leading-tight">{fmt(systemValue)}</p>
              </div>
            </div>

            {/* ABC breakdown */}
            <div className="grid grid-cols-3 gap-2">
              {[
                { label: "A Class", count: aCount, cls: "A" },
                { label: "B Class", count: bCount, cls: "B" },
                { label: "C Class", count: cCount, cls: "C" },
              ].map((row) => (
                <div key={row.cls} className={`rounded-xl p-3 text-center border ${
                  row.cls === "A" ? "bg-purple-500/10 border-purple-500/20" :
                  row.cls === "B" ? "bg-blue-500/10 border-blue-500/20" :
                  "bg-zinc-800/50 border-zinc-700"
                }`}>
                  <p className={`text-lg font-mono font-bold ${
                    row.cls === "A" ? "text-purple-400" : row.cls === "B" ? "text-blue-400" : "text-zinc-500"
                  }`}>{row.count}</p>
                  <p className={`text-[10px] mt-0.5 ${
                    row.cls === "A" ? "text-purple-400/70" : row.cls === "B" ? "text-blue-400/70" : "text-zinc-600"
                  }`}>{row.label}</p>
                </div>
              ))}
            </div>
          </Section>

          {/* 02 ΓÇö Instructions */}
          <Section label="02 ΓÇö Before You Start">
            <div className="bg-amber-400/10 border border-amber-400/20 rounded-xl p-4 space-y-3">
              {[
                "Count what is physically on your shelf ΓÇö do not rely on the system numbers",
                "System quantities are hidden during counting to avoid bias",
                "Enter each product's actual physical count as you find it",
                "Any difference will be flagged for your review before anything is updated",
              ].map((note, i) => (
                <div key={i} className="flex gap-3">
                  <span className="text-amber-400 text-xs mt-0.5 shrink-0">ΓÇó</span>
                  <p className="text-zinc-300 text-sm leading-relaxed">{note}</p>
                </div>
              ))}
            </div>
          </Section>

          <PrimaryBtn onClick={startCount} loading={loading}>Start counting ΓåÆ</PrimaryBtn>
          <div className="h-4" />
        </div>
      </div>
    )
  }

  // ΓöÇΓöÇ STEP 3: COUNTING ΓöÇΓöÇ
  if (step === "counting") {
    const countedWithVariance = products.filter((p) => {
      const v = variance(p.id, p.current_quantity)
      return v !== 0
    }).length

    return (
      <div className="min-h-screen bg-zinc-950 pb-28">
        {/* Header */}
        <div className="px-5 pt-8 pb-5 border-b border-zinc-800">
          <div className="flex items-center justify-between mb-1">
            <h1 className="text-white font-bold text-2xl tracking-tight">Counting</h1>
            <span className="text-[10px] font-mono px-2.5 py-1 rounded-full bg-amber-400/10 text-amber-400">
              In progress
            </span>
          </div>
          <p className="text-zinc-500 text-sm">{type.replace("_", " ")} ┬╖ {products.length} products</p>

          {/* Progress strip */}
          <div className="mt-4 grid grid-cols-3 gap-2">
            <StatPill label="Total" value={products.length} />
            <StatPill label="Variances" value={countedWithVariance} amber={countedWithVariance > 0} accent={countedWithVariance === 0} />
            <StatPill label="KES impact" value={fmt(Math.abs(totalKesVariance()))} red={totalKesVariance() < 0} accent={totalKesVariance() >= 0 && countedWithVariance > 0} />
          </div>
        </div>

        <div className="px-5 max-w-2xl mx-auto">
          <p className="text-zinc-600 text-xs mt-4 mb-3">
            System quantities hidden ΓÇö enter what you physically see on the shelf.
          </p>

          <ErrorBanner msg={error} />

          <div className="mt-3 space-y-3">
            {products.map((p) => {
              const actual = parseFloat(counts[p.id] ?? p.current_quantity)
              const v = actual - p.current_quantity
              const kesVariance = v * (p.buying_price || 0)
              const hasVariance = !isNaN(v) && v !== 0
              const abc = abcMap[p.id] || "C"

              return (
                <div
                  key={p.id}
                  className={`bg-zinc-900 rounded-2xl p-4 border transition-colors ${
                    hasVariance
                      ? v < 0
                        ? "border-red-400/30"
                        : "border-emerald-500/30"
                      : "border-zinc-800"
                  }`}
                >
                  {/* Product header */}
                  <div className="flex items-start justify-between mb-3">
                    <div className="flex-1 min-w-0 pr-3">
                      <div className="flex items-center gap-2 flex-wrap mb-1">
                        <p className="text-white text-sm font-medium">{p.name}</p>
                        <ABCBadge cls={abc} />
                      </div>
                      <p className="text-zinc-600 text-xs font-mono">{p.sku_id}</p>
                    </div>

                    {hasVariance && (
                      <div className="text-right shrink-0">
                        <p className={`text-sm font-mono font-bold ${v > 0 ? "text-emerald-400" : "text-red-400"}`}>
                          {v > 0 ? "+" : ""}{v} units
                        </p>
                        <p className={`text-xs font-mono mt-0.5 opacity-80 ${v > 0 ? "text-emerald-400" : "text-red-400"}`}>
                          {v > 0 ? "+" : ""}{fmt(Math.abs(kesVariance))}
                        </p>
                      </div>
                    )}
                  </div>

                  {/* Inputs */}
                  <div className={`grid gap-3 ${hasVariance ? "grid-cols-2" : "grid-cols-1"}`}>
                    <div>
                      <label className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium block mb-1.5">
                        Physical count
                      </label>
                      <input
                        type="number"
                        value={counts[p.id] ?? p.current_quantity}
                        onChange={(e) => setCounts({ ...counts, [p.id]: e.target.value })}
                        min="0"
                        className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm font-mono outline-none focus:border-emerald-500 transition-colors"
                      />
                    </div>

                    {hasVariance && (
                      <div>
                        <label className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium block mb-1.5">
                          Cause
                        </label>
                        <select
                          value={causes[p.id] || "none"}
                          onChange={(e) => setCauses({ ...causes, [p.id]: e.target.value })}
                          className="w-full bg-zinc-950 border border-zinc-800 text-zinc-300 rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors"
                        >
                          <option value="none">Select cause</option>
                          <option value="theft">Theft / loss</option>
                          <option value="damage">Damage</option>
                          <option value="error">Data entry error</option>
                          <option value="unrecorded">Unrecorded receipt</option>
                        </select>
                      </div>
                    )}
                  </div>
                </div>
              )
            })}
          </div>
        </div>

        {/* Fixed bottom CTA */}
        <div className="fixed bottom-0 left-0 right-0 bg-zinc-950 border-t border-zinc-800 px-5 py-4">
          <PrimaryBtn onClick={submitCounts} loading={loading}>Submit counts ΓåÆ</PrimaryBtn>
        </div>
      </div>
    )
  }

  // ΓöÇΓöÇ STEP 4: REVIEW ΓöÇΓöÇ
  if (step === "review") {
    const variances = products.filter((p) => {
      const actual = parseFloat(counts[p.id] ?? p.current_quantity)
      return actual !== p.current_quantity
    })
    const totalKes = totalKesVariance()
    const selectedVariance = variances.find((p) => p.id === selectedVarianceId) || null

    return (
      <div className="min-h-screen bg-zinc-950 pb-28">
        <div className="px-5 pt-8 pb-6">
          <h1 className="text-white font-bold text-2xl tracking-tight">Variance Review</h1>
          <p className="text-zinc-500 text-sm mt-1">
            {variances.length} item{variances.length !== 1 ? "s" : ""} with variance ┬╖ review before approving
          </p>
        </div>

        <div className="px-5 max-w-2xl mx-auto space-y-4">
          <ErrorBanner msg={error} />

          {/* Summary cards */}
          <div className="grid grid-cols-3 gap-3">
            {[
              { label: "Counted", value: products.length, color: "text-white" },
              { label: "Variances", value: variances.length, color: variances.length > 0 ? "text-amber-400" : "text-emerald-400" },
              { label: "KES impact", value: fmt(Math.abs(totalKes)), color: totalKes < 0 ? "text-red-400" : totalKes > 0 ? "text-emerald-400" : "text-zinc-500", small: true },
            ].map((card, i) => (
              <div key={i} className="bg-zinc-900 border border-zinc-800 rounded-2xl p-4 relative overflow-hidden">
                <div className={`absolute top-0 left-0 right-0 h-0.5 opacity-70 ${
                  i === 0 ? "bg-zinc-500" : i === 1 && variances.length > 0 ? "bg-amber-400" : i === 1 ? "bg-emerald-500" : totalKes < 0 ? "bg-red-400" : "bg-emerald-500"
                }`} />
                <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-2">{card.label}</p>
                <p className={`font-mono font-bold ${card.color} ${card.small ? "text-xs leading-tight" : "text-2xl"}`}>{card.value}</p>
                {i === 2 && totalKes !== 0 && (
                  <p className="text-zinc-600 text-[10px] mt-1">{totalKes < 0 ? "loss" : "gain"}</p>
                )}
              </div>
            ))}
          </div>

          {/* 01 ΓÇö Variance detail */}
          <Section label="01 ΓÇö Variance Detail">
            {variances.length === 0 ? (
              <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-xl p-6 text-center">
                <p className="text-emerald-400 text-base font-semibold">Perfect count</p>
                <p className="text-zinc-400 text-sm mt-1">All quantities match the system</p>
              </div>
            ) : (
              <>
                <div className="md:hidden space-y-2">
                  {variances.map((p) => {
                    const actual = parseFloat(counts[p.id] ?? p.current_quantity)
                    const v = actual - p.current_quantity
                    const abc = abcMap[p.id] || "C"

                    return (
                      <button
                        key={p.id}
                        onClick={() => setSelectedVarianceId(p.id)}
                        className={`w-full text-left bg-zinc-950 border rounded-xl px-4 py-3 ${
                          v < 0 ? "border-red-400/20" : "border-emerald-500/20"
                        }`}
                      >
                        <div className="flex items-start justify-between gap-3">
                          <div className="min-w-0">
                            <div className="flex items-center gap-2 mb-1 flex-wrap">
                              <p className="text-white text-sm font-medium truncate">{p.name}</p>
                              <ABCBadge cls={abc} />
                            </div>
                            <p className="text-zinc-600 text-xs font-mono">{p.sku_id}</p>
                          </div>
                          <p className={`text-sm font-mono font-bold whitespace-nowrap ${v > 0 ? "text-emerald-400" : "text-red-400"}`}>
                            {v > 0 ? "+" : ""}{v}
                          </p>
                        </div>
                        <p className="text-zinc-600 text-xs mt-2">System {p.current_quantity} ΓåÆ Actual {actual}</p>
                      </button>
                    )
                  })}
                </div>

                <div className="hidden md:block bg-zinc-950 border border-zinc-800 rounded-xl overflow-hidden">
                  <div className="overflow-x-auto">
                    <table className="w-full min-w-[920px]">
                      <thead className="sticky top-0 bg-zinc-950 z-10">
                        <tr className="text-left text-[10px] uppercase tracking-wider text-zinc-500 border-b border-zinc-800">
                          <th className="py-3 px-4 font-medium">SKU</th>
                          <th className="py-3 px-4 font-medium">Product</th>
                          <th className="py-3 px-4 font-medium">Class</th>
                          <th className="py-3 px-4 font-medium text-right">System</th>
                          <th className="py-3 px-4 font-medium text-right">Actual</th>
                          <th className="py-3 px-4 font-medium text-right">Variance</th>
                          <th className="py-3 px-4 font-medium text-right">KES Impact</th>
                          <th className="py-3 px-4 font-medium">Cause</th>
                        </tr>
                      </thead>
                      <tbody>
                        {variances.map((p) => {
                          const actual = parseFloat(counts[p.id] ?? p.current_quantity)
                          const v = actual - p.current_quantity
                          const kesV = v * (p.buying_price || 0)
                          const abc = abcMap[p.id] || "C"

                          return (
                            <tr key={p.id} className="border-b border-zinc-900 hover:bg-zinc-900/50">
                              <td className="py-3 px-4 text-[11px] text-zinc-500 font-mono">{p.sku_id}</td>
                              <td className="py-3 px-4 text-sm text-white font-medium">{p.name}</td>
                              <td className="py-3 px-4"><ABCBadge cls={abc} /></td>
                              <td className="py-3 px-4 text-xs text-right font-mono text-zinc-400">{p.current_quantity}</td>
                              <td className="py-3 px-4 text-xs text-right font-mono text-zinc-200">{actual}</td>
                              <td className={`py-3 px-4 text-xs text-right font-mono font-semibold ${v > 0 ? "text-emerald-400" : "text-red-400"}`}>
                                {v > 0 ? "+" : ""}{v}
                              </td>
                              <td className={`py-3 px-4 text-xs text-right font-mono ${v > 0 ? "text-emerald-400" : "text-red-400"}`}>
                                {v > 0 ? "+" : "-"}{fmt(Math.abs(kesV))}
                              </td>
                              <td className="py-3 px-4 text-xs text-zinc-500 capitalize">{causes[p.id] && causes[p.id] !== "none" ? causes[p.id].replace("_", " ") : "-"}</td>
                            </tr>
                          )
                        })}
                      </tbody>
                    </table>
                  </div>
                </div>
              </>
            )}
          </Section>

          {/* 02 ΓÇö Warning */}
          <Section label="02 ΓÇö Confirmation">
            <div className="bg-amber-400/10 border border-amber-400/20 rounded-xl px-4 py-3">
              <p className="text-zinc-300 text-sm leading-relaxed">
                Approving will update all inventory quantities to match your physical count. <span className="text-amber-400 font-medium">This cannot be undone.</span>
              </p>
            </div>
          </Section>
        </div>

        {/* Fixed bottom CTA */}
        <div className="fixed bottom-0 left-0 right-0 bg-zinc-950 border-t border-zinc-800 px-5 py-4">
          <PrimaryBtn onClick={approveStockTake} loading={loading}>Approve & update inventory ΓåÆ</PrimaryBtn>
        </div>

        {selectedVariance && (
          <div className="md:hidden fixed inset-0 z-[60] bg-black/60" onClick={() => setSelectedVarianceId(null)}>
            <div
              className="absolute bottom-0 left-0 right-0 bg-zinc-900 border-t border-zinc-800 rounded-t-3xl p-5"
              onClick={(e) => e.stopPropagation()}
            >
              <div className="w-12 h-1 bg-zinc-700 rounded-full mx-auto mb-4" />
              <p className="text-white text-base font-semibold">{selectedVariance.name}</p>
              <p className="text-zinc-500 text-xs mt-1 font-mono">{selectedVariance.sku_id}</p>

              {(() => {
                const actual = parseFloat(counts[selectedVariance.id] ?? selectedVariance.current_quantity)
                const v = actual - selectedVariance.current_quantity
                const kesV = v * (selectedVariance.buying_price || 0)
                const abc = abcMap[selectedVariance.id] || "C"

                return (
                  <div className="mt-4 space-y-3 text-sm">
                    <div className="flex items-center justify-between">
                      <p className="text-zinc-500">Class</p>
                      <ABCBadge cls={abc} />
                    </div>
                    <div className="flex items-center justify-between">
                      <p className="text-zinc-500">System qty</p>
                      <p className="text-zinc-300 font-mono">{selectedVariance.current_quantity}</p>
                    </div>
                    <div className="flex items-center justify-between">
                      <p className="text-zinc-500">Actual qty</p>
                      <p className="text-zinc-200 font-mono">{actual}</p>
                    </div>
                    <div className="flex items-center justify-between">
                      <p className="text-zinc-500">Variance</p>
                      <p className={`font-mono font-semibold ${v > 0 ? "text-emerald-400" : "text-red-400"}`}>
                        {v > 0 ? "+" : ""}{v}
                      </p>
                    </div>
                    <div className="flex items-center justify-between">
                      <p className="text-zinc-500">KES impact</p>
                      <p className={`font-mono ${v > 0 ? "text-emerald-400" : "text-red-400"}`}>
                        {v > 0 ? "+" : "-"}{fmt(Math.abs(kesV))}
                      </p>
                    </div>
                    <div className="flex items-center justify-between border-t border-zinc-800 pt-3">
                      <p className="text-zinc-500">Cause</p>
                      <p className="text-zinc-300 capitalize">{causes[selectedVariance.id] && causes[selectedVariance.id] !== "none" ? causes[selectedVariance.id].replace("_", " ") : "-"}</p>
                    </div>
                  </div>
                )
              })()}

              <button
                onClick={() => setSelectedVarianceId(null)}
                className="mt-5 w-full bg-zinc-800 hover:bg-zinc-700 text-zinc-200 rounded-xl py-3 text-sm font-medium transition-colors"
              >
                Close
              </button>
            </div>
          </div>
        )}
      </div>
    )
  }

  // ΓöÇΓöÇ STEP 5: DONE ΓöÇΓöÇ
  if (step === "done") {
    const variances = products.filter((p) => {
      const actual = parseFloat(counts[p.id] ?? p.current_quantity)
      return actual !== p.current_quantity
    })

    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-5">
        <div className="w-full max-w-md text-center space-y-6">
          <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto border border-emerald-500/20">
            <span className="text-emerald-400 text-4xl">Γ£ô</span>
          </div>
          <div>
            <h2 className="text-white font-bold text-2xl tracking-tight">Stock take complete</h2>
            <p className="text-zinc-500 text-sm mt-2">
              {variances.length === 0
                ? "All quantities matched ΓÇö no adjustments needed"
                : `${variances.length} item${variances.length !== 1 ? "s" : ""} adjusted to match physical count`}
            </p>
          </div>

          {/* Summary pills */}
          {variances.length > 0 && (
            <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-4 text-left space-y-2">
              <StatPill label="Items adjusted" value={variances.length} accent />
              <StatPill label="KES impact" value={fmt(Math.abs(totalKesVariance()))} red={totalKesVariance() < 0} accent={totalKesVariance() >= 0} />
            </div>
          )}

          <button
            onClick={() => navigate("/inventory")}
            className="w-full bg-emerald-500 hover:bg-emerald-400 text-black font-semibold rounded-xl py-4 text-sm transition-colors tracking-wide"
          >
            Back to inventory
          </button>
        </div>
      </div>
    )
  }
}

// src/pages/onboarding/AddEmployees.jsx
import { useState } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"

const EDGE_FUNCTION_URL = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/invite-user`

export default function AddEmployees() {
  const navigate = useNavigate()
  const [employees, setEmployees] = useState([])
  const [fullName, setFullName] = useState("")
  const [email, setEmail] = useState("")
  const [role, setRole] = useState("cashier")
  const [inviting, setInviting] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState("")
  const [fieldError, setFieldError] = useState("")

  const handleInvite = async () => {
    setFieldError("")

    if (!fullName.trim()) { setFieldError("Full name is required"); return }
    if (!email.trim()) { setFieldError("Email is required"); return }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    if (!emailRegex.test(email.trim())) { setFieldError("Please enter a valid email address"); return }

    if (employees.find(e => e.email.toLowerCase() === email.trim().toLowerCase())) {
      setFieldError("This email has already been added")
      return
    }

    setInviting(true)

    try {
      const { data: { session } } = await supabase.auth.getSession()

      if (!session) {
        setFieldError("You must be logged in to invite employees")
        setInviting(false)
        return
      }

      console.log("=== INVITE REQUEST DEBUG ===")
      console.log("Session exists:", !!session)
      console.log("Session user:", session.user?.email)
      console.log("Access token length:", session.access_token?.length)
      console.log("Invite payload:", { email: email.trim(), fullName: fullName.trim(), role })
      console.log("EDGE_FUNCTION_URL:", EDGE_FUNCTION_URL)
      console.log("==========================")

      const res = await fetch(EDGE_FUNCTION_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${session.access_token}`,
          "apikey": import.meta.env.VITE_SUPABASE_ANON_KEY,
        },
        body: JSON.stringify({
          email: email.trim(),
          fullName: fullName.trim(),
          role,
        }),
      })

      const result = await res.json()
      console.log("=== INVITE RESPONSE DEBUG ===")
      console.log("Response status:", res.status)
      console.log("Response headers:", Object.fromEntries(res.headers.entries()))
      console.log("Response body:", JSON.stringify(result, null, 2))
      console.log("=============================")

      if (!res.ok) {
        setFieldError(result.error || "Failed to create user")
        setInviting(false)
        return
      }

      // Handle the new response format with temporary password
      const newUser = {
        fullName: fullName.trim(),
        email: email.trim(),
        role,
        status: "created",
        tempPassword: result.user?.tempPassword,
      }

      setEmployees([...employees, newUser])

      setFullName("")
      setEmail("")
      setRole("cashier")

      // Show success message with temp password if available
      if (result.user?.tempPassword) {
        console.log(`Γ£à User created! Temporary password: ${result.user.tempPassword}`)
      }

    } catch (err) {
      console.log("Catch error:", err)
      setFieldError("Network error ΓÇö please try again")
    }

    setInviting(false)
  }

  const removeEmployee = (index) => {
    setEmployees(employees.filter((_, i) => i !== index))
  }

  const handleContinue = async () => {
    setSaving(true)
    navigate("/onboarding/done")
    setSaving(false)
  }

  const roleLabel = (r) => r === "cashier" ? "Cashier" : "Manager"

  return (
    <div className="min-h-screen bg-zinc-950 pb-16">
      <div className="px-5 pt-8 pb-6">
        <p className="text-zinc-500 text-xs font-mono uppercase tracking-widest mb-3">Onboarding ┬╖ Step 2</p>
        <h1 className="text-white font-bold text-2xl tracking-tight">Add your team</h1>
        <p className="text-zinc-500 text-sm mt-1.5 leading-relaxed">
          Invite cashiers and managers. Each person gets an email to set their password and activate their account.
        </p>
      </div>

      <div className="px-5 max-w-lg mx-auto space-y-4">

        {error && (
          <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
            <p className="text-red-400 text-sm">{error}</p>
          </div>
        )}

        {/* ΓöÇΓöÇ TEAM LIST ΓöÇΓöÇ */}
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-5">
          <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-4">
            Your team ┬╖ {employees.length} invited
          </p>

          {employees.length === 0 ? (
            <div className="text-center py-6">
              <p className="text-zinc-600 text-sm">No one invited yet.</p>
              <p className="text-zinc-700 text-xs mt-1">Add someone below to get started.</p>
            </div>
          ) : (
            <div className="space-y-2">
              {employees.map((e, i) => (
                <div
                  key={i}
                  className="flex items-center justify-between bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3"
                >
                  <div className="min-w-0 flex-1">
                    <p className="text-white text-sm font-medium truncate">{e.fullName}</p>
                    <p className="text-zinc-500 text-xs font-mono mt-0.5 truncate">{e.email}</p>
                    {e.tempPassword && (
                      <p className="text-emerald-400 text-xs font-mono mt-1">
                        Password: {e.tempPassword}
                      </p>
                    )}
                  </div>
                  <div className="flex items-center gap-3 ml-3 shrink-0">
                    <span className={`text-[10px] font-mono px-2.5 py-1 rounded-full ${
                      e.role === "manager"
                        ? "bg-blue-500/10 text-blue-400"
                        : "bg-zinc-800 text-zinc-400"
                    }`}>
                      {roleLabel(e.role)}
                    </span>
                    <span className="text-[10px] font-mono px-2.5 py-1 rounded-full bg-emerald-500/10 text-emerald-400">
                      Created Γ£ô
                    </span>
                    <button
                      onClick={() => removeEmployee(i)}
                      className="text-zinc-600 hover:text-red-400 transition-colors text-sm"
                    >
                      Γ£ò
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ΓöÇΓöÇ INVITE FORM ΓöÇΓöÇ */}
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-5 space-y-4">
          <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium">
            Invite someone
          </p>

          {fieldError && (
            <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
              <p className="text-red-400 text-sm">{fieldError}</p>
            </div>
          )}

          <div>
            <label className="text-zinc-400 text-xs mb-2 block">Full name</label>
            <input
              type="text"
              value={fullName}
              onChange={e => setFullName(e.target.value)}
              placeholder="Jane Wanjiku"
              className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
            />
          </div>

          <div>
            <label className="text-zinc-400 text-xs mb-2 block">Email address</label>
            <input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="jane@business.com"
              onKeyDown={e => e.key === "Enter" && handleInvite()}
              className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
            />
          </div>

          <div>
            <label className="text-zinc-400 text-xs mb-2 block">Role</label>
            <div className="flex gap-2">
              {["cashier", "manager"].map(r => (
                <button
                  key={r}
                  onClick={() => setRole(r)}
                  className={`flex-1 py-2.5 rounded-xl text-xs font-medium transition-colors capitalize ${
                    role === r
                      ? "bg-emerald-500 text-black"
                      : "bg-zinc-950 border border-zinc-800 text-zinc-400 hover:text-white"
                  }`}
                >
                  {roleLabel(r)}
                </button>
              ))}
            </div>
            <p className="text-zinc-600 text-xs mt-2">
              {role === "cashier"
                ? "Can record sales and view their own shift."
                : "Can manage inventory, view reports, and invite cashiers."}
            </p>
          </div>

          <button
            onClick={handleInvite}
            disabled={inviting}
            className="w-full bg-zinc-800 hover:bg-zinc-700 disabled:opacity-50 text-white font-medium rounded-xl py-3 text-sm transition-colors"
          >
            {inviting ? "Sending invite..." : "+ Send invite"}
          </button>
        </div>

        {/* ΓöÇΓöÇ HOW IT WORKS ΓöÇΓöÇ */}
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-5">
          <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-3">How it works</p>
          <div className="space-y-3">
            {[
              { step: "1", text: "They receive an email from Elevate with an activation link" },
              { step: "2", text: "They click the link and set their own password" },
              { step: "3", text: "Their account is activated and they can log in" },
            ].map(s => (
              <div key={s.step} className="flex items-start gap-3">
                <span className="w-5 h-5 rounded-full bg-zinc-800 text-zinc-500 text-[10px] font-mono font-bold flex items-center justify-center shrink-0 mt-0.5">
                  {s.step}
                </span>
                <p className="text-zinc-400 text-sm leading-relaxed">{s.text}</p>
              </div>
            ))}
          </div>
        </div>

        {/* ΓöÇΓöÇ ACTIONS ΓöÇΓöÇ */}
        <div className="grid grid-cols-2 gap-3">
          <button
            onClick={() => navigate("/onboarding/done")}
            className="bg-zinc-900 hover:bg-zinc-800 border border-zinc-800 text-zinc-300 font-medium rounded-xl py-3.5 text-sm transition-colors"
          >
            Skip for now
          </button>
          <button
            onClick={handleContinue}
            disabled={saving}
            className="bg-emerald-500 hover:bg-emerald-400 disabled:opacity-50 text-black font-semibold rounded-xl py-3.5 text-sm transition-colors"
          >
            {saving ? "Saving..." : "Continue ΓåÆ"}
          </button>
        </div>

        <div className="h-4" />
      </div>
    </div>
  )
}

import { useEffect, useMemo, useState } from "react"
import { useNavigate, useParams } from "react-router-dom"
import { supabase } from "../../lib/supabase"
import { useCurrentBusiness, useIsOwner } from "../../hooks/useRole"
import { useBranchContext } from "../../context/BranchContext"
import { AppShell, UiButton, UiCard } from "../../components/ui"

export default function BranchDetail() {
  const { id } = useParams()
  const navigate = useNavigate()
  const { businessId } = useCurrentBusiness()
  const { availableBranches, refreshBranches } = useBranchContext()
  const isOwner = useIsOwner()

  const [branch, setBranch] = useState(null)
  const [employees, setEmployees] = useState([])
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState("")
  const [saved, setSaved] = useState(false)
  const [editing, setEditing] = useState(false)
  const [name, setName] = useState("")
  const [code, setCode] = useState("")
  const [address, setAddress] = useState("")
  const [phone, setPhone] = useState("")
  const [email, setEmail] = useState("")

  const goBack = () => {
    if (window.history.length > 1) {
      navigate(-1)
      return
    }
    navigate("/settings/branches", { replace: true })
  }

  const loadBranch = async () => {
    try {
      const { data: branchData, error: branchError } = await supabase
        .from("branches")
        .select("*")
        .eq("id", id)
        .eq("business_id", businessId)
        .single()

      if (branchError) throw branchError

      setBranch(branchData)
      setName(branchData.name || "")
      setCode(branchData.code || "")
      setAddress(branchData.address || "")
      setPhone(branchData.phone || "")
      setEmail(branchData.email || "")

      const { data: assignments, error: employeeError } = await supabase
        .from("user_branch_assignments")
        .select("user_id, users(id, full_name, email, role, is_active)")
        .eq("branch_id", id)
        .eq("is_active", true)

      if (employeeError) throw employeeError

      setEmployees((assignments || []).map((item) => item.users).filter(Boolean))
    } catch (err) {
      setError(err.message || "Failed to load branch")
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (id && businessId) {
      loadBranch()
    }
  }, [id, businessId])

  const assignedCount = useMemo(() => employees.length, [employees])

  const handleSave = async () => {
    if (!branch || !name) {
      setError("Branch name is required")
      return
    }

    setSaving(true)
    setError("")

    try {
      const { error: updateError } = await supabase
        .from("branches")
        .update({
          name,
          code: code || null,
          address: address || null,
          phone: phone || null,
          email: email || null,
        })
        .eq("id", id)

      if (updateError) throw updateError

      await refreshBranches?.()
      await loadBranch()
      setEditing(false)
      setSaved(true)
      setTimeout(() => setSaved(false), 1800)
    } catch (err) {
      setError(err.message || "Failed to update branch")
    } finally {
      setSaving(false)
    }
  }

  const handleToggleActive = async () => {
    if (!branch) return

    setSaving(true)
    setError("")

    try {
      const { error: updateError } = await supabase
        .from("branches")
        .update({ is_active: !branch.is_active })
        .eq("id", id)

      if (updateError) throw updateError

      await refreshBranches?.()
      await loadBranch()
    } catch (err) {
      setError(err.message || "Failed to update branch status")
    } finally {
      setSaving(false)
    }
  }

  const handleDelete = async () => {
    if (!confirm(`Delete ${branch?.name}? This action cannot be undone.`)) return

    setSaving(true)
    setError("")

    try {
      const { error: deleteError } = await supabase
        .from("branches")
        .update({ status: "archived" })
        .eq("id", id)

      if (deleteError) throw deleteError

      await refreshBranches?.()
      navigate("/settings/branches", { replace: true })
    } catch (err) {
      setError(err.message || "Failed to delete branch")
    } finally {
      setSaving(false)
    }
  }

  const addEmployees = () => {
    navigate("/settings/branch-employees", {
      state: { branchId: id, branchName: branch?.name },
    })
  }

  if (loading) {
    return (
      <AppShell title="Branch Details" showHeader={true} right={<UiButton variant="secondary" size="sm" onClick={goBack} aria-label="Back">ΓåÉ</UiButton>}>
        <div className="flex items-center justify-center py-12">
          <p className="text-zinc-500">Loading...</p>
        </div>
      </AppShell>
    )
  }

  if (!branch) {
    return (
      <AppShell title="Branch Details" showHeader={true} right={<UiButton variant="secondary" size="sm" onClick={goBack} aria-label="Back">ΓåÉ</UiButton>}>
        <div className="flex items-center justify-center py-12">
          <p className="text-zinc-500">Branch not found</p>
        </div>
      </AppShell>
    )
  }

  return (
    <AppShell
      title="Branch Details"
      subtitle={`${branch.name} ┬╖ Manage profile, status, and people in one place`}
      showHeader={true}
      right={(
        <div className="flex w-full flex-wrap items-stretch gap-1.5 sm:w-auto sm:items-center sm:gap-3">
          <UiButton variant="secondary" size="sm" onClick={goBack} className="flex-1 text-xs px-2 sm:flex-none sm:px-3">ΓåÉ</UiButton>
          <UiButton variant="secondary" size="sm" onClick={addEmployees} className="flex-1 text-xs px-2 sm:flex-none sm:px-3">Employees</UiButton>
          <UiButton variant="primary" size="sm" onClick={() => setEditing((current) => !current)} className="flex-1 text-xs px-2 sm:flex-none sm:px-3">
            {editing ? "Cancel" : "Edit"}
          </UiButton>
        </div>
      )}
    >
      <div className="space-y-4">
        {error && <p className="text-red-400 text-sm bg-red-400/10 px-3 py-2 rounded-lg">{error}</p>}
        {saved && <p className="text-emerald-400 text-sm bg-emerald-400/10 px-3 py-2 rounded-lg">Saved successfully</p>}

        {/* Scope Badge */}
        <UiCard className="p-3 bg-zinc-800/50 border-zinc-700/50">
          <p className="text-zinc-500 text-xs uppercase tracking-wider">Current scope</p>
          <p className="text-white text-sm font-semibold mt-1">{branch.name}</p>
        </UiCard>

        <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
          <UiCard className="p-4">
            <p className="text-zinc-500 text-xs">Employees</p>
            <p className="text-white text-2xl font-semibold mt-1">{assignedCount}</p>
          </UiCard>
          <UiCard className="p-4">
            <p className="text-zinc-500 text-xs">Status</p>
            <p className={`text-2xl font-semibold mt-1 ${branch.is_active ? "text-emerald-400" : "text-red-400"}`}>{branch.is_active ? "Live" : "Paused"}</p>
          </UiCard>
          <UiCard className="p-4">
            <p className="text-zinc-500 text-xs">Code</p>
            <p className="text-white text-lg font-semibold mt-2 break-all">{branch.code || "ΓÇö"}</p>
          </UiCard>
          <UiCard className="p-4">
            <p className="text-zinc-500 text-xs">Branch ID</p>
            <p className="text-white text-xs font-mono mt-2 break-all">{branch.id}</p>
          </UiCard>
        </div>

        <UiCard className="p-4 space-y-4">
          <div className="flex items-start justify-between gap-4">
            <div>
              <h3 className="text-white text-xl font-semibold">{branch.name}</h3>
              <p className="text-zinc-500 text-sm">{branch.code || "No code"} {branch.address ? `ΓÇó ${branch.address}` : ""}</p>
            </div>
            <span className={`text-xs px-2.5 py-1 rounded-full font-medium ${branch.is_active ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400"}`}>
              {branch.is_active ? "Active" : "Inactive"}
            </span>
          </div>

          {!editing && (
            <div className="grid gap-3 md:grid-cols-2">
              <div className="rounded-xl border border-zinc-800 bg-zinc-950 p-4">
                <p className="text-zinc-500 text-xs uppercase tracking-wider">Contact</p>
                <div className="mt-3 space-y-1 text-sm">
                  <p className="text-white">{branch.phone || "No phone"}</p>
                  <p className="text-zinc-400 break-all">{branch.email || "No email"}</p>
                </div>
              </div>
              <div className="rounded-xl border border-zinc-800 bg-zinc-950 p-4">
                <p className="text-zinc-500 text-xs uppercase tracking-wider">Address</p>
                <p className="mt-3 text-sm text-zinc-200">{branch.address || "No address set"}</p>
              </div>
            </div>
          )}

          {editing ? (
            <div className="space-y-3">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <div>
                  <label className="text-zinc-400 text-xs mb-1 block">Branch name *</label>
                  <input value={name} onChange={(e) => setName(e.target.value)} className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500" />
                </div>
                <div>
                  <label className="text-zinc-400 text-xs mb-1 block">Branch code</label>
                  <input value={code} onChange={(e) => setCode(e.target.value)} className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500" />
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <div>
                  <label className="text-zinc-400 text-xs mb-1 block">Phone</label>
                  <input value={phone} onChange={(e) => setPhone(e.target.value)} className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500" />
                </div>
                <div>
                  <label className="text-zinc-400 text-xs mb-1 block">Email</label>
                  <input value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500" />
                </div>
              </div>
              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Address</label>
                <input value={address} onChange={(e) => setAddress(e.target.value)} className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500" />
              </div>
              <div className="flex gap-3">
                <UiButton variant="primary" className="flex-1" onClick={handleSave} disabled={saving}>{saving ? "Saving..." : "Save changes"}</UiButton>
                <UiButton variant="secondary" onClick={handleToggleActive} disabled={saving}>{saving ? "Working..." : (branch.is_active ? "Deactivate" : "Activate")}</UiButton>
              </div>
            </div>
          ) : null}
        </UiCard>

        <UiCard className="p-4 space-y-3">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <h3 className="text-white font-medium text-sm">Assigned Employees</h3>
            <UiButton variant="secondary" size="sm" onClick={addEmployees}>Add employees</UiButton>
          </div>
          {employees.length === 0 ? (
            <p className="text-zinc-500 text-sm">No employees assigned to this branch yet.</p>
          ) : (
            <div className="space-y-2">
              {employees.map((employee) => (
                <button
                  key={employee.id}
                  onClick={() => navigate(`/settings/employees/${employee.id}`)}
                  className="w-full text-left bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between hover:border-emerald-500/30 transition-colors"
                >
                  <div className="min-w-0">
                    <p className="text-white text-sm font-medium">{employee.full_name}</p>
                    <p className="text-zinc-500 text-xs break-words">{employee.email} ΓÇó {employee.role}</p>
                  </div>
                  <span className={`text-xs px-2.5 py-1 rounded-full font-medium ${employee.is_active ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400"}`}>
                    {employee.is_active ? "Active" : "Inactive"}
                  </span>
                </button>
              ))}
            </div>
          )}
        </UiCard>

        <UiCard className="p-4 border-red-500/20 space-y-3">
          <div>
            <h3 className="text-red-400 font-medium text-sm">Danger Zone</h3>
            <p className="text-zinc-500 text-xs mt-1">Deleting this branch removes it from your business.</p>
          </div>
          <UiButton variant="secondary" className="border-red-500/20 text-red-400 hover:bg-red-500/10" onClick={handleDelete} disabled={saving}>
            Delete branch
          </UiButton>
        </UiCard>
      </div>
    </AppShell>
  )
}

import { useState, useEffect } from "react"
import { supabase } from "../../lib/supabase"
import { useLocation, useNavigate } from "react-router-dom"
import { useUser, useCurrentBusiness, useIsOwner, useIsManager } from "../../hooks/useRole"
import { useBranchContext } from "../../context/BranchContext"
import { AppShell, UiButton, UiCard } from "../../components/ui"
import { BranchSelector } from "../../components/BranchSelector"

export default function BranchEmployees() {
  const navigate = useNavigate()
  const location = useLocation()
  const { user: authUser } = useUser()
  const { businessId } = useCurrentBusiness()
  const { activeBranch, viewMode, canViewAll, availableBranches, readyToFetch, setActiveBranch, setViewMode, effectiveBranchId } = useBranchContext()
  const isOwner = useIsOwner()
  const isManager = useIsManager()

  const [employees, setEmployees] = useState([])
  const [adding, setAdding] = useState(false)
  const [fullName, setFullName] = useState("")
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [role, setRole] = useState("cashier")
  const [targetBranchId, setTargetBranchId] = useState("")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const [success, setSuccess] = useState(false)
  const [successMessage, setSuccessMessage] = useState("")

  const branchIdFromNavigation = location.state?.branchId || null
  const branchNameFromNavigation = location.state?.branchName || null
  const currentBranchName = branchNameFromNavigation || activeBranch?.name || "All branches"

  // Only allow access if user has branch access
  useEffect(() => {
    if (!readyToFetch) return

    if (branchIdFromNavigation) {
      const branch = availableBranches.find((item) => item.id === branchIdFromNavigation)
      if (branch) {
        setActiveBranch(branch)
        setViewMode("branch")
        setTargetBranchId(branch.id)
      }
    }

    if (!branchIdFromNavigation && canViewAll && !targetBranchId && availableBranches.length === 1) {
      setTargetBranchId(availableBranches[0].id)
    }

    if (availableBranches.length === 0) {
      navigate("/settings")
    }
  }, [availableBranches, branchIdFromNavigation, readyToFetch, canViewAll, navigate, setActiveBranch, setTargetBranchId, setViewMode, targetBranchId])

  useEffect(() => { 
    if (businessId && readyToFetch) {
      fetchEmployees() 
    } 
  }, [businessId, activeBranch, viewMode, effectiveBranchId, readyToFetch])

  const fetchEmployees = async () => {
    if (!canViewAll && !effectiveBranchId) {
      setEmployees([])
      return
    }

    let query = supabase
      .from("users")
      .select("*")
      .eq("business_id", businessId)
      .order("created_at")

    const scopeBranchId = viewMode === 'branch' ? activeBranch?.id : effectiveBranchId

    // If scoped to a branch, filter by assignments
    if (scopeBranchId) {
      const { data: assignments } = await supabase
        .from("user_branch_assignments")
        .select("user_id")
        .eq("branch_id", scopeBranchId)
        .eq("is_active", true)

      const userIds = assignments?.map(a => a.user_id) || []
      if (userIds.length > 0) {
        query = query.in("id", userIds)
      } else {
        setEmployees([])
        return
      }
    }

    const { data } = await query
    setEmployees(data || [])
  }

  const handleAddEmployee = async () => {
    setError("")

    if (!fullName || !email || !password) {
      setError("Name, email and password are required")
      return
    }

    // Email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    if (!emailRegex.test(email)) {
      setError("Invalid email format")
      return
    }

    if (password.length < 6) {
      setError("Password must be at least 6 characters")
      return
    }

    if (!businessId) {
      setError("Business ID not loaded. Please refresh the page.")
      return
    }

    const branchId = viewMode === 'branch' ? activeBranch?.id : (targetBranchId || null)

    if (!branchId) {
      setError("Please select a branch first.")
      return
    }

    setLoading(true)

    const { data: { session } } = await supabase.auth.getSession()

    if (!session?.access_token) {
      setError("Your session has expired. Please sign in again.")
      setLoading(false)
      return
    }

    const requestBody = {
      email,
      password,
      fullName,
      role,
      businessId,
      branchId,
    }
    console.log("Sending create-employee request with:", requestBody)

    const response = await fetch(
      `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/create-employee`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${session.access_token}`,
        },
        body: JSON.stringify(requestBody),
      }
    )

    let result
    try {
      result = await response.json()
    } catch (e) {
      setError(`Server error: ${response.status} ${response.statusText}`)
      setLoading(false)
      return
    }

    if (!response.ok) {
      const errorMessage = result.error || `Request failed with status ${response.status}`
      setError(errorMessage)
      console.error("Employee creation failed:", { 
        status: response.status, 
        error: result,
        sent: requestBody
      })
      setLoading(false)
      return
    }

    if (result.error) {
      setError(result.error)
    } else {
      setSuccessMessage(`${fullName} has been added to the team`)
      setSuccess(true)
      setFullName("")
      setEmail("")
      setPassword("")
      setRole("cashier")
      setAdding(false)
      fetchEmployees()
      setTimeout(() => setSuccess(false), 3000)
    }

    setLoading(false)
  }

  const toggleActive = async (emp) => {
    await supabase.from("users").update({ is_active: !emp.is_active }).eq("id", emp.id)
    fetchEmployees()
  }

  const goBack = () => {
    if (window.history.length > 1) {
      navigate(-1)
      return
    }
    navigate("/settings", { replace: true })
  }

  const getBranchContext = () => {
    if (branchNameFromNavigation) {
      return ` ΓÇó ${branchNameFromNavigation}`
    }
    if (viewMode === 'branch' && activeBranch) {
      return ` ΓÇó ${activeBranch.name}`
    }
    if (canViewAll) {
      if (isOwner) return " ΓÇó All Branches"
      if (isManager) return " ΓÇó All My Branches"
      return " ΓÇó All Branches"
    }
    return ""
  }

  return (
    <AppShell
      title="Employees"
      subtitle={`Manage your team and access roles${getBranchContext()}`}
      showHeader={true}
      right={(
        <div className="flex w-full flex-wrap items-stretch gap-1.5 sm:w-auto sm:items-center sm:gap-3 max-w-[calc(100vw-2rem)] sm:max-w-none">
          <UiButton variant="secondary" size="sm" onClick={goBack} className="flex-1 text-xs px-2 sm:flex-none sm:px-3" aria-label="Back">ΓåÉ</UiButton>
          {canViewAll ? <BranchSelector /> : null}
          <UiButton variant="primary" size="sm" onClick={() => setAdding(!adding)} className="flex-1 text-xs px-2 sm:flex-none sm:px-3">{adding ? "Cancel" : "+ Add"}</UiButton>
        </div>
      )}
    >
      <div className="space-y-4">
        {error && <p className="text-red-400 text-sm bg-red-400/10 px-3 py-2 rounded-lg">{error}</p>}
        {success && <p className="text-emerald-400 text-sm bg-emerald-400/10 px-3 py-2 rounded-lg">{successMessage}</p>}

        {/* Scope Badge */}
        <UiCard className="p-3 bg-zinc-800/50 border-zinc-700/50">
          <p className="text-zinc-500 text-xs uppercase tracking-wider">Current scope</p>
          <p className="text-white text-sm font-semibold mt-1">{currentBranchName}</p>
        </UiCard>

        <UiCard className="p-4">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
            <div>
              <p className="text-zinc-500 text-xs uppercase tracking-wider">Branch scope</p>
              <h2 className="text-white text-lg font-semibold mt-1">{currentBranchName}</h2>
              <p className="text-zinc-500 text-sm mt-1">Add staff, assign roles, and keep access aligned with the selected branch.</p>
            </div>
            <span className="inline-flex w-fit rounded-full bg-emerald-500/10 px-3 py-1 text-xs font-medium text-emerald-300">
              {employees.length} employee{employees.length === 1 ? "" : "s"}
            </span>
          </div>
        </UiCard>

        {adding && (
          <UiCard className="p-4 space-y-3">
            <h2 className="text-white font-semibold text-sm">New employee</h2>
            {[
              { label: "Full name", value: fullName, setter: setFullName, placeholder: "Jane Wanjiku" },
              { label: "Email", value: email, setter: setEmail, placeholder: "jane@business.com", type: "email" },
            ].map((f, i) => (
              <div key={i}>
                <label className="text-zinc-400 text-xs mb-1 block">{f.label} {f.label === "Email" && <span className="text-red-400">*</span>}</label>
                <input type={f.type || "text"} value={f.value} onChange={e => f.setter(e.target.value)}
                  placeholder={f.placeholder}
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600" />
                {f.label === "Email" && email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) && 
                  <p className="text-red-400 text-xs mt-1">Invalid email format</p>
                }
              </div>
            ))}
            <div>
              <label className="text-zinc-400 text-xs mb-1 block">Temporary password <span className="text-red-400">*</span></label>
              <input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Min 6 characters"
                className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
              />
              {password && password.length < 6 && <p className="text-red-400 text-xs mt-1">Password must be at least 6 characters</p>}
            </div>
            <div>
              <label className="text-zinc-400 text-xs mb-1 block">Role</label>
              <select value={role} onChange={e => setRole(e.target.value)}
                className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors">
                <option value="cashier">Cashier</option>
                <option value="manager">Manager</option>
              </select>
            </div>
            {viewMode === 'branch' && activeBranch && (
              <div className="bg-zinc-800 border border-zinc-700 rounded-xl px-4 py-3">
                <p className="text-zinc-400 text-xs mb-1">Branch assignment</p>
                <p className="text-white text-sm font-medium">{activeBranch.name}</p>
              </div>
            )}
            {canViewAll && viewMode !== 'branch' && (
              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Assign to branch</label>
                <select
                  value={targetBranchId}
                  onChange={(e) => setTargetBranchId(e.target.value)}
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors"
                >
                  <option value="">Select a branch</option>
                  {availableBranches.map((branch) => (
                    <option key={branch.id} value={branch.id}>
                      {branch.name} {branch.code ? `(${branch.code})` : ""}
                    </option>
                  ))}
                </select>
              </div>
            )}
            <UiButton 
              variant="primary" 
              className="w-full" 
              onClick={handleAddEmployee} 
              disabled={loading || !fullName || !email || !password || password.length < 6 || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) || !(viewMode === 'branch' ? activeBranch?.id : targetBranchId)}
            >
              {loading ? "Adding..." : "Add employee"}
            </UiButton>
          </UiCard>
        )}

        <div className="space-y-2">
          {employees.map((emp, i) => (
            <div
              key={i} 
              className="bg-zinc-900 border border-zinc-800 rounded-2xl px-4 py-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between hover:border-emerald-500/30 transition-colors cursor-pointer"
              onClick={() => navigate(`/settings/employees/${emp.id}`)}
            >
              <div className="flex items-center gap-3 min-w-0">
                <div className="w-9 h-9 bg-zinc-800 rounded-full flex items-center justify-center">
                  <span className="text-white text-sm font-bold">{emp.full_name?.charAt(0)}</span>
                </div>
                <div className="min-w-0">
                  <p className="text-white text-sm font-medium">{emp.full_name}
                    {emp.id === authUser.id && <span className="text-zinc-500 text-xs ml-1">(you)</span>}
                  </p>
                  <p className="text-zinc-500 text-xs capitalize break-words">{emp.role} ┬╖ {emp.email}</p>
                </div>
              </div>
              <div className="flex flex-wrap items-center gap-2 sm:justify-end">
                <span className={`text-xs px-2.5 py-1 rounded-full font-medium flex-shrink-0 ${
                  emp.is_active ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400"
                }`}>
                  {emp.is_active ? "Active" : "Inactive"}
                </span>
                <span className="text-xs px-2.5 py-1 rounded-full font-medium bg-zinc-800 text-zinc-400 capitalize">
                  {emp.role}
                </span>
                {emp.id !== authUser.id && (
                  <button 
                    onClick={(e) => {
                      e.stopPropagation()
                      toggleActive(emp)
                    }}
                    className={`text-xs px-3 py-1.5 rounded-xl transition-colors flex-shrink-0 ${
                      emp.is_active ? "bg-zinc-800 text-zinc-400 hover:text-red-400" : "bg-emerald-500/10 text-emerald-400"
                    }`}>
                    {emp.is_active ? "Deactivate" : "Activate"}
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </AppShell>
  )
}

import { useState, useEffect, useMemo } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"
import { useUser, useCurrentBusiness } from "../../hooks/useRole"
import { useInstantAuth } from "../../hooks/useInstantAuth"
import { AppShell, UiButton, UiCard } from "../../components/ui"
import { useBranchContext } from "../../context/BranchContext"

export default function Branches() {
  const navigate = useNavigate()
  const { user: authUser } = useUser()
  const { businessId } = useCurrentBusiness()
  const { business } = useInstantAuth()
  const { availableBranches, refreshBranches } = useBranchContext()
  const resolvedBusinessId = businessId || business?.id

  const [branches, setBranches] = useState([])
  const [search, setSearch] = useState("")
  const [adding, setAdding] = useState(false)
  const [editing, setEditing] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")

  // Form state
  const [name, setName] = useState("")
  const [code, setCode] = useState("")
  const [address, setAddress] = useState("")
  const [phone, setPhone] = useState("")
  const [email, setEmail] = useState("")

  const activeBranches = useMemo(() => branches
    .filter((branch) => branch.is_active)
    .filter((branch) => branch.name.toLowerCase().includes(search.toLowerCase()) || 
                        (branch.code && branch.code.toLowerCase().includes(search.toLowerCase())))
  , [branches, search])
  const inactiveBranches = useMemo(() => branches
    .filter((branch) => !branch.is_active)
    .filter((branch) => branch.name.toLowerCase().includes(search.toLowerCase()) ||
                        (branch.code && branch.code.toLowerCase().includes(search.toLowerCase())))
  , [branches, search])

  const resetForm = () => {
    setName("")
    setCode("")
    setAddress("")
    setPhone("")
    setEmail("")
    setEditing(null)
  }

  const openCreateForm = () => {
    resetForm()
    setAdding(true)
  }

  const closeForm = () => {
    resetForm()
    setAdding(false)
  }

  useEffect(() => {
    if (resolvedBusinessId) fetchBranches()
  }, [resolvedBusinessId])

  const fetchBranches = async () => {
    if (!resolvedBusinessId) {
      setBranches([])
      return
    }

    const { data, error } = await supabase
      .from("branches")
      .select("*")
      .eq("business_id", resolvedBusinessId)
      .order("name")

    if (error) {
      setError(error.message)
      setBranches([])
      return
    }

    setBranches((data || []).filter((branch) => branch.status !== "archived"))
  }

  const handleSave = async () => {
    setError("")

    if (!name) {
      setError("Branch name is required")
      return
    }

    setLoading(true)

    try {
      const branchData = {
        business_id: resolvedBusinessId,
        name,
        code: code || null,
        address: address || null,
        phone: phone || null,
        email: email || null,
      }

      if (!resolvedBusinessId) {
        setError("Business is still loading. Please try again in a moment.")
        return
      }

      if (editing) {
        const { error } = await supabase
          .from("branches")
          .update(branchData)
          .eq("id", editing.id)

        if (error) throw error

        closeForm()
        await fetchBranches()
        if (refreshBranches) refreshBranches()
        return
      } else {
        const { data, error } = await supabase
          .from("branches")
          .insert(branchData)
          .select("id")
          .single()

        if (error) throw error

        closeForm()
        await fetchBranches()
        if (refreshBranches) refreshBranches()
        if (data?.id) {
          navigate(`/settings/branches/${data.id}`)
        }
        return
      }

    } catch (error) {
      setError(error.message)
    } finally {
      setLoading(false)
    }
  }

  const handleEdit = (branch) => {
    setEditing(branch)
    setName(branch.name)
    setCode(branch.code || "")
    setAddress(branch.address || "")
    setPhone(branch.phone || "")
    setEmail(branch.email || "")
    setAdding(true)
  }

  const toggleActive = async (branch) => {
    try {
      const { error } = await supabase
        .from("branches")
        .update({ is_active: !branch.is_active })
        .eq("id", branch.id)

      if (error) throw error

      await fetchBranches()
      if (refreshBranches) refreshBranches()
    } catch (error) {
      setError(error.message)
    }
  }

  const handleDelete = async (branch) => {
    if (!confirm(`Are you sure you want to delete ${branch.name}? This action cannot be undone.`)) return

    try {
      const { error } = await supabase
        .from("branches")
        .update({ status: "archived" })
        .eq("id", branch.id)

      if (error) throw error

      await fetchBranches()
      if (refreshBranches) refreshBranches()
    } catch (error) {
      setError(error.message)
    }
  }

  const manageBranchEmployees = (branch) => {
    navigate("/settings/branch-employees", {
      state: { branchId: branch.id, branchName: branch.name },
    })
  }

  const viewBranchDetails = (branch) => {
    navigate(`/settings/branches/${branch.id}`)
  }

  const goBack = () => {
    if (window.history.length > 1) {
      navigate(-1)
      return
    }
    navigate("/settings", { replace: true })
  }

  return (
    <AppShell
      title="Branches"
      subtitle="Create, inspect, and switch between locations without leaving settings"
      showHeader={true}
      right={(
        <div className="flex items-center gap-1.5 sm:gap-3 max-w-[calc(100vw-2rem)] sm:max-w-none">
          <UiButton variant="secondary" size="sm" type="button" onClick={goBack} className="flex-shrink-0 text-xs px-2 sm:px-3" aria-label="Back">ΓåÉ</UiButton>
          <UiButton variant="primary" size="sm" type="button" onClick={adding ? closeForm : openCreateForm} className="flex-shrink-0 text-xs px-2 sm:px-3">
            {adding ? "Cancel" : "Add branch"}
          </UiButton>
        </div>
      )}
    >
      <div className="space-y-4">
        {error && <p className="text-red-400 text-sm bg-red-400/10 px-3 py-2 rounded-lg">{error}</p>}

        {/* Scope Badge */}
        <UiCard className="p-3 bg-zinc-800/50 border-zinc-700/50">
          <p className="text-zinc-500 text-xs uppercase tracking-wider">Business scope</p>
          <p className="text-white text-sm font-semibold mt-1">All branches</p>
        </UiCard>

        {/* Search */}
        <input
          type="text"
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search by name or code..."
          className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
        />

        <div className="grid grid-cols-3 gap-3">
          <UiCard className="p-4">
            <p className="text-zinc-500 text-xs">Total branches</p>
            <p className="text-white text-2xl font-semibold mt-1">{branches.length}</p>
          </UiCard>
          <UiCard className="p-4">
            <p className="text-zinc-500 text-xs">Active</p>
            <p className="text-emerald-400 text-2xl font-semibold mt-1">{activeBranches.length}</p>
          </UiCard>
          <UiCard className="p-4">
            <p className="text-zinc-500 text-xs">Inactive</p>
            <p className="text-red-400 text-2xl font-semibold mt-1">{inactiveBranches.length}</p>
          </UiCard>
        </div>

        {adding && (
          <UiCard className="p-4 space-y-3">
            <div className="flex items-start justify-between gap-3">
              <div>
                <h2 className="text-white font-semibold text-sm">{editing ? "Edit branch" : "New branch"}</h2>
                <p className="text-zinc-500 text-xs mt-1">Keep branch names short and codes unique for easier filtering.</p>
              </div>
              {editing && (
                <span className="text-[10px] px-2 py-1 rounded-full bg-emerald-500/10 text-emerald-300 font-medium">Editing</span>
              )}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Branch name *</label>
                <input
                  type="text"
                  value={name}
                  onChange={e => setName(e.target.value)}
                  placeholder="Main Branch"
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
                />
              </div>

              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Branch code</label>
                <input
                  type="text"
                  value={code}
                  onChange={e => setCode(e.target.value)}
                  placeholder="HQ-001"
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
                />
              </div>
            </div>

            <div>
              <label className="text-zinc-400 text-xs mb-1 block">Address</label>
              <input
                type="text"
                value={address}
                onChange={e => setAddress(e.target.value)}
                placeholder="123 Main Street, Nairobi"
                className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
              />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Phone</label>
                <input
                  type="text"
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                  placeholder="0700 000 000"
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
                />
              </div>

              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Email</label>
                <input
                  type="email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  placeholder="branch@business.com"
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              <UiButton variant="primary" type="button" className="w-full" onClick={handleSave} disabled={loading}>
                {loading ? "Saving..." : (editing ? "Update branch" : "Add branch")}
              </UiButton>
              <UiButton
                variant="secondary"
                className="w-full"
                type="button"
                onClick={() => {
                  closeForm()
                }}
              >
                Cancel
              </UiButton>
            </div>
          </UiCard>
        )}

        <div className="space-y-2">
          {branches.length === 0 ? (
            <UiCard className="p-8 text-center">
              <p className="text-white text-sm font-medium">No branches yet</p>
              <p className="text-zinc-500 text-xs mt-1">Create your first branch to start assigning employees and switching locations.</p>
              <UiButton variant="primary" type="button" className="mt-4" onClick={openCreateForm}>
                Create branch
              </UiButton>
            </UiCard>
          ) : branches.map((branch) => (
            <div
              key={branch.id}
              role="button"
              tabIndex={0}
              onClick={() => viewBranchDetails(branch)}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault()
                  viewBranchDetails(branch)
                }
              }}
              className="bg-zinc-900 border border-zinc-800 rounded-2xl px-4 py-4 flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between hover:border-emerald-500/30 transition-colors cursor-pointer"
            >
              <div className="flex items-center gap-3 min-w-0">
                <div className="w-9 h-9 bg-zinc-800 rounded-full flex items-center justify-center">
                  <span className="text-white text-sm font-bold">{branch.name?.charAt(0)}</span>
                </div>
                <div className="min-w-0">
                  <p className="text-white text-sm font-medium">{branch.name}</p>
                  <p className="text-zinc-500 text-xs break-words">
                    {branch.code || "No code"} ┬╖ {branch.address || "No address"}
                  </p>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {branch.phone && <span className="rounded-full bg-zinc-800 px-2 py-0.5 text-[10px] text-zinc-300">{branch.phone}</span>}
                    {branch.email && <span className="rounded-full bg-zinc-800 px-2 py-0.5 text-[10px] text-zinc-300">{branch.email}</span>}
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2 sm:flex sm:flex-wrap sm:items-center lg:justify-end">
                <span className={`text-xs px-2.5 py-1 rounded-full font-medium flex-shrink-0 ${
                  branch.is_active ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400"
                }`}>
                  {branch.is_active ? "Active" : "Inactive"}
                </span>

                <button
                  onClick={(e) => {
                    e.stopPropagation()
                    viewBranchDetails(branch)
                  }}
                  className="text-xs px-3 py-1.5 rounded-xl bg-zinc-800 text-zinc-400 hover:text-white transition-colors flex-shrink-0"
                >
                  View
                </button>

                <button
                  onClick={() => manageBranchEmployees(branch)}
                  onMouseDown={(e) => e.stopPropagation()}
                  className="text-xs px-3 py-1.5 rounded-xl bg-emerald-500/10 text-emerald-300 hover:bg-emerald-500/20 transition-colors flex-shrink-0"
                >
                  Employees
                </button>

                <button
                  onClick={(e) => {
                    e.stopPropagation()
                    handleEdit(branch)
                  }}
                  className="text-xs px-3 py-1.5 rounded-xl bg-zinc-800 text-zinc-400 hover:text-white transition-colors flex-shrink-0"
                >
                  Edit
                </button>

                <button
                  onClick={(e) => {
                    e.stopPropagation()
                    toggleActive(branch)
                  }}
                  className={`text-xs px-3 py-1.5 rounded-xl transition-colors flex-shrink-0 ${
                    branch.is_active ? "bg-zinc-800 text-zinc-400 hover:text-red-400" : "bg-emerald-500/10 text-emerald-400"
                  }`}
                >
                  {branch.is_active ? "Deactivate" : "Activate"}
                </button>

                <button
                  onClick={(e) => {
                    e.stopPropagation()
                    handleDelete(branch)
                  }}
                  className="text-xs px-3 py-1.5 rounded-xl bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-colors flex-shrink-0"
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </AppShell>
  )
}

// src/pages/settings/Business.jsx
import { useState, useEffect } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"
import { useCurrentBusiness } from "../../hooks/useRole"
import { AppShell, UiButton, UiCard } from "../../components/ui"

export default function Business() {
  const navigate = useNavigate()
  const goBack = () => {
    if (window.history.length > 1) {
      navigate(-1)
      return
    }
    navigate("/settings", { replace: true })
  }
  const { businessId } = useCurrentBusiness()
  const [name, setName] = useState("")
  const [type, setType] = useState("retail")
  const [phone, setPhone] = useState("")
  const [email, setEmail] = useState("")
  const [location, setLocation] = useState("")
  const [kraPin, setKraPin] = useState("")
  const [regNumber, setRegNumber] = useState("")
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState("")
  const [saved, setSaved] = useState(false)

  useEffect(() => {
    if (businessId) fetchBusiness()
  }, [businessId])

  const fetchBusiness = async () => {
    const { data } = await supabase
      .from("businesses").select("*").eq("id", businessId).single()

    if (data) {
      setName(data.name || "")
      setType(data.type || "retail")
      setPhone(data.phone || "")
      setEmail(data.email || "")
      setLocation(data.location || "")
      setKraPin(data.kra_pin || "")
      setRegNumber(data.reg_number || "")
    }
  }

  const handleSave = async () => {
    setSaving(true)
    setError("")
    const { error } = await supabase
      .from("businesses")
      .update({ name, type, phone, email, location, kra_pin: kraPin, reg_number: regNumber })
      .eq("id", businessId)

    if (error) setError(error.message)
    else setSaved(true)
    setSaving(false)
    setTimeout(() => setSaved(false), 2000)
  }

  return (
    <AppShell
      title="Business Details"
      subtitle="Keep your trading name, contacts, and registration details current"
      showHeader={false}
      right={<UiButton variant="secondary" size="sm" onClick={goBack} aria-label="Back">ΓåÉ</UiButton>}
    >
      <div className="space-y-4">
        {error && <p className="text-red-400 text-sm bg-red-400/10 px-3 py-2 rounded-lg">{error}</p>}
        {saved && <p className="text-emerald-400 text-sm bg-emerald-400/10 px-3 py-2 rounded-lg">Saved successfully</p>}

        <UiCard className="p-4 space-y-3">
          {[
            { label: "Business name", value: name, setter: setName, placeholder: "Kamau General Store" },
            { label: "Phone", value: phone, setter: setPhone, placeholder: "0712 345 678" },
            { label: "Email", value: email, setter: setEmail, placeholder: "business@email.com" },
            { label: "Location", value: location, setter: setLocation, placeholder: "Nairobi, Westlands" },
            { label: "KRA PIN", value: kraPin, setter: setKraPin, placeholder: "A000000000Z" },
            { label: "Registration number", value: regNumber, setter: setRegNumber, placeholder: "CPR/2024/123456" },
          ].map((f, i) => (
            <div key={i}>
              <label className="text-zinc-400 text-xs mb-1 block">{f.label}</label>
              <input
                type="text"
                value={f.value}
                onChange={e => f.setter(e.target.value)}
                placeholder={f.placeholder}
                className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-600"
              />
            </div>
          ))}
          <div>
            <label className="text-zinc-400 text-xs mb-1 block">Business type</label>
            <select value={type} onChange={e => setType(e.target.value)}
              className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors">
              <option value="retail">Retail</option>
              <option value="wholesale">Wholesale</option>
              <option value="other">Other</option>
            </select>
          </div>
        </UiCard>

        <UiButton variant="primary" className="w-full" onClick={handleSave} disabled={saving}>
          {saving ? "Saving..." : "Save changes"}
        </UiButton>
      </div>
    </AppShell>
  )
}

