                {months.map((m, i) => (
                  <option key={i} value={i + 1}>{m}</option>
                ))}
              </select>
            </div>
          </div>
        </UiCard>

        {/* Save Button */}
        <UiButton
          variant="primary"
          className="w-full"
          onClick={handleSave}
          disabled={saving || validateSettings() !== null}
        >
          {saving ? "Saving..." : "Save all settings"}
        </UiButton>

        {/* Info Card */}
        <UiCard className="p-4 bg-zinc-800/50 border-zinc-700/50">
          <p className="text-zinc-400 text-xs leading-relaxed">
            <strong>All settings are applied business-wide</strong>. Changes to VAT rate, stock thresholds, and financial year will affect all branches and products immediately.
          </p>
        </UiCard>
      </div>
    </AppShell>
  )
}

import { useState, useEffect } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate, useParams } from "react-router-dom"
import { useUser, useCurrentBusiness, useIsOwner } from "../../hooks/useRole"
import { useBranchContext } from "../../context/BranchContext"
import { AppShell, UiButton, UiCard } from "../../components/ui"

export default function EmployeeDetail() {
  const navigate = useNavigate()
  const { id } = useParams()
  const { user: authUser } = useUser()
  const { businessId } = useCurrentBusiness()
  const { availableBranches, effectiveBranchId, canViewAll } = useBranchContext()
  const isOwner = useIsOwner()

  const [employee, setEmployee] = useState(null)
  const [loading, setLoading] = useState(true)
  const [editing, setEditing] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState("")

  // Form state
  const [fullName, setFullName] = useState("")
  const [email, setEmail] = useState("")
  const [role, setRole] = useState("cashier")
  const [selectedBranches, setSelectedBranches] = useState([])
  const [isActive, setIsActive] = useState(true)

  useEffect(() => {
    if (id && businessId) fetchEmployee()
  }, [id, businessId])

  const fetchEmployee = async () => {
    try {
      const { data: emp } = await supabase
        .from("users")
        .select("*")
        .eq("id", id)
        .eq("business_id", businessId)
        .single()

      if (emp) {
        setEmployee(emp)
        setFullName(emp.full_name || "")
        setEmail(emp.email || "")
        setRole(emp.role || "cashier")
        setIsActive(emp.is_active !== false)

        // Fetch branch assignments
        const { data: assignments } = await supabase
          .from("user_branch_assignments")
          .select("branch_id, branches(name, code)")
          .eq("user_id", id)
          .eq("is_active", true)

        const assignedBranches = assignments?.map(a => a.branch_id) || []
        if (!canViewAll && effectiveBranchId && !assignedBranches.includes(effectiveBranchId)) {
          setError("You do not have access to this employee.")
          setEmployee(null)
          return
        }

        setSelectedBranches(assignedBranches)
      }
    } catch (error) {
      setError("Failed to load employee")
    } finally {
      setLoading(false)
    }
  }

  const handleSave = async () => {
    setError("")
    setSaving(true)

    try {
      // Update employee basic info
      const { error: updateError } = await supabase
        .from("users")
        .update({
          full_name: fullName,
          email,
          role,
          is_active: isActive,
        })
        .eq("id", id)
        .eq("business_id", businessId)

      if (updateError) throw updateError

      // Update branch assignments
      if (isOwner && availableBranches.length > 0) {
        // Remove existing assignments
        await supabase
          .from("user_branch_assignments")
          .delete()
          .eq("user_id", id)

        // Add new assignments
        if (selectedBranches.length > 0) {
          const assignments = selectedBranches.map(branchId => ({
            user_id: id,
            branch_id: branchId,
            role,
            is_active: true,
          }))

          const { error: assignmentError } = await supabase
            .from("user_branch_assignments")
            .insert(assignments)

          if (assignmentError) throw assignmentError
        }
      }

      setEditing(false)
      fetchEmployee() // Refresh data
    } catch (error) {
      setError(error.message)
    } finally {
      setSaving(false)
    }
  }

  const toggleBranch = (branchId) => {
    setSelectedBranches(prev => 
      prev.includes(branchId) 
        ? prev.filter(id => id !== branchId)
        : [...prev, branchId]
    )
  }

  const goBack = () => {
    navigate(-1)
  }

  if (loading) {
    return (
      <AppShell title="Employee" showHeader={true}>
        <div className="flex items-center justify-center py-12">
          <p className="text-zinc-500">Loading...</p>
        </div>
      </AppShell>
    )
  }

  if (!employee) {
    return (
      <AppShell title="Employee" showHeader={true}>
        <div className="flex items-center justify-center py-12">
          <p className="text-zinc-500">Employee not found</p>
        </div>
      </AppShell>
    )
  }

  return (
    <AppShell
      title="Employee Details"
      subtitle={employee.full_name}
      showHeader={true}
      right={(
        <div className="flex items-center gap-1.5 sm:gap-3">
          <UiButton variant="secondary" size="sm" onClick={goBack} className="text-xs px-2 sm:px-3">ΓåÉ</UiButton>
          <UiButton 
            variant="primary" 
            size="sm" 
            onClick={() => setEditing(!editing)} 
            className="text-xs px-2 sm:px-3"
          >
            {editing ? "Cancel" : "Edit"}
          </UiButton>
        </div>
      )}
    >
      <div className="space-y-4">
        {error && <p className="text-red-400 text-sm bg-red-400/10 px-3 py-2 rounded-lg">{error}</p>}

        {editing ? (
          <UiCard className="p-4 space-y-4">
            <h3 className="text-white font-semibold text-sm">Edit Employee</h3>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Full name</label>
                <input
                  type="text"
                  value={fullName}
                  onChange={e => setFullName(e.target.value)}
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm"
                />
              </div>

              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Email</label>
                <input
                  type="email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Role</label>
                <select
                  value={role}
                  onChange={e => setRole(e.target.value)}
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm"
                >
                  <option value="cashier">Cashier</option>
                  <option value="manager">Manager</option>
                </select>
              </div>

              <div>
                <label className="text-zinc-400 text-xs mb-1 block">Status</label>
                <select
                  value={isActive ? "active" : "inactive"}
                  onChange={e => setIsActive(e.target.value === "active")}
                  className="w-full bg-zinc-800 border border-zinc-700 text-white rounded-xl px-4 py-3 text-sm"
                >
                  <option value="active">Active</option>
                  <option value="inactive">Inactive</option>
                </select>
              </div>
            </div>

            {isOwner && availableBranches.length > 0 && (
              <div>
                <label className="text-zinc-400 text-xs mb-2 block">
                  Branch Assignments {role === "manager" && "(Managers can have multiple branches)"}
                </label>
                <div className="space-y-2">
                  {availableBranches.map(branch => (
                    <label key={branch.id} className="flex items-center gap-3 cursor-pointer">
                      <input
                        type="checkbox"
                        checked={selectedBranches.includes(branch.id)}
                        onChange={() => toggleBranch(branch.id)}
                        className="w-4 h-4 text-emerald-500 bg-zinc-800 border-zinc-600 rounded focus:ring-emerald-500"
                      />
                      <div className="flex-1">
                        <p className="text-white text-sm">{branch.name}</p>
                        <p className="text-zinc-500 text-xs">{branch.code || 'No code'}</p>
                      </div>
                    </label>
                  ))}
                </div>
              </div>
            )}

            <div className="flex gap-3">
              <UiButton variant="primary" className="flex-1" onClick={handleSave} disabled={saving}>
                {saving ? "Saving..." : "Save Changes"}
              </UiButton>
              <UiButton variant="secondary" onClick={() => setEditing(false)}>
                Cancel
              </UiButton>
            </div>
          </UiCard>
        ) : (
          <UiCard className="p-4 space-y-4">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-zinc-800 rounded-full flex items-center justify-center">
                <span className="text-white text-lg font-bold">{employee.full_name?.charAt(0)}</span>
              </div>
              <div>
                <h3 className="text-white font-semibold">{employee.full_name}</h3>
                <p className="text-zinc-500 text-sm">{employee.email}</p>
                <div className="flex items-center gap-2 mt-1">
                  <span className={`text-xs px-2 py-1 rounded-full capitalize ${
                    employee.is_active !== false ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400"
                  }`}>
                    {employee.is_active !== false ? "Active" : "Inactive"}
                  </span>
                  <span className="text-xs px-2 py-1 rounded-full bg-zinc-800 text-zinc-300 capitalize">
                    {employee.role}
                  </span>
                </div>
              </div>
            </div>

            {isOwner && availableBranches.length > 0 && (
              <div>
                <h4 className="text-zinc-300 font-medium text-sm mb-2">Branch Assignments</h4>
                <div className="space-y-2">
                  {selectedBranches.length > 0 ? (
                    selectedBranches.map(branchId => {
                      const branch = availableBranches.find(b => b.id === branchId)
                      return branch ? (
                        <div key={branchId} className="flex items-center justify-between bg-zinc-800 rounded-lg px-3 py-2">
                          <div>
                            <p className="text-white text-sm">{branch.name}</p>
                            <p className="text-zinc-500 text-xs">{branch.code || 'No code'}</p>
                          </div>
                        </div>
                      ) : null
                    })
                  ) : (
                    <p className="text-zinc-500 text-sm">No branch assignments</p>
                  )}
                </div>
              </div>
            )}
          </UiCard>
        )}
      </div>
    </AppShell>
  )
}

import { useEffect, useMemo, useState } from "react"
import { useNavigate } from "react-router-dom"
import { AppShell, UiButton, UiCard, UiSectionTitle } from "../../components/ui"
import PaymentIcon from "../../components/ui/PaymentIcon"
import { useBranchContext } from "../../context/BranchContext"
import { useCurrentBusiness, useUser } from "../../hooks/useRole"
import { supabase } from "../../lib/supabase"
import { getDb } from "../../lib/db"
import { BranchSelector } from "../../components/BranchSelector"

export default function HistoricalSales() {
  const navigate = useNavigate()
  const { user: authUser } = useUser()
  const { businessId } = useCurrentBusiness()
  const {
    canViewAll,
    availableBranches,
    effectiveBranchId,
    readyToFetch,
  } = useBranchContext()

  const [userId, setUserId] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const resolvedBranchId = effectiveBranchId

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split("T")[0])
  const [openingDate, setOpeningDate] = useState(null)
  const [products, setProducts] = useState([])
  const [productSearch, setProductSearch] = useState("")
  const [cartItems, setCartItems] = useState([])
  const [paymentAccount, setPaymentAccount] = useState("cash")
  const [discountEnabled, setDiscountEnabled] = useState(false)
  const [discountType, setDiscountType] = useState("pct")
  const [discountValue, setDiscountValue] = useState("")
  const [pendingTransactions, setPendingTransactions] = useState([])
  const [showPendingReview, setShowPendingReview] = useState(false)

  const [datesWithSales, setDatesWithSales] = useState({})
  const [todaysSales, setTodaysSales] = useState([])

  const fetchInitialData = async () => {
    try {
      const { data: baseline } = await supabase
        .from("float_baseline")
        .select("opening_stock_date")
        .eq("business_id", businessId)
        .maybeSingle()

      if (!baseline?.opening_stock_date) {
        setOpeningDate(null)
        setError("Opening stock not set. Please set opening stock first.")
        return
      }

      setOpeningDate(baseline.opening_stock_date)
      setUserId(authUser.id)
      setError("")

      if (canViewAll && !resolvedBranchId) {
        setProducts([])
        setError("Select a branch before recording historical sales")
        return
      }

      let productsQuery = supabase
        .from("products")
        .select("id, name, sku_id, selling_price, current_quantity, unit_of_measure, vat_type, branch_id")
        .eq("business_id", businessId)
        .not("is_active", "eq", false)
        .order("name")

      if (resolvedBranchId) {
        productsQuery = productsQuery.eq("branch_id", resolvedBranchId)
      }

      const { data: productsData, error: productsError } = await productsQuery
      if (productsError) throw productsError
      setProducts(productsData || [])

      const { data: transactions, error: transactionsError } = await supabase
        .from("transactions")
        .select("id, date, payment_account, sale_items(product_id, quantity, unit_price, total_amount)")
        .eq("business_id", businessId)
        .eq("type", "sale")
        .gte("date", `${baseline.opening_stock_date}T00:00:00.000Z`)
        .lte("date", `${selectedDate}T23:59:59.999Z`)
        .order("date", { ascending: true })

      if (transactionsError) throw transactionsError

      const grouped = {}
      const normalizedTransactions =
        transactions?.flatMap((txn) => {
          const items = Array.isArray(txn.sale_items) ? txn.sale_items : []
          return items.map((item, index) => ({
            id: `${txn.id}-${index}`,
            transaction_id: txn.id,
            transaction_date: new Date(txn.date).toISOString().split("T")[0],
            payment_account: txn.payment_account,
            product_id: item.product_id,
            quantity: item.quantity,
            unit_price: item.unit_price,
            total_amount: item.total_amount,
          }))
        }) || []

      normalizedTransactions.forEach((item) => {
        const date = item.transaction_date
        if (!grouped[date]) grouped[date] = []
        grouped[date].push(item)
      })

      setDatesWithSales(grouped)
      setTodaysSales(grouped[selectedDate] || [])
    } catch (err) {
      setError(err.message || "Failed to load historical sales")
    }
  }

  useEffect(() => {
    if (businessId && authUser && readyToFetch) {
      void fetchInitialData()
    }
  }, [businessId, authUser, resolvedBranchId, readyToFetch])

  const filteredProducts = useMemo(() => {
    const search = productSearch.trim().toLowerCase()
    if (!search) return []
    return products.filter((product) => {
      return (
        product.name?.toLowerCase().includes(search) ||
        product.sku_id?.toLowerCase().includes(search)
      )
    })
  }, [productSearch, products])

  const subtotal = cartItems.reduce((sum, item) => sum + item.unit_price * item.quantity, 0)
  const discountAmount = discountEnabled
    ? discountType === "pct"
      ? subtotal * ((parseFloat(discountValue) || 0) / 100)
      : Math.min(parseFloat(discountValue) || 0, subtotal)
    : 0
  const total = subtotal - discountAmount
  const itemCount = cartItems.reduce((sum, item) => sum + item.quantity, 0)

  const pendingRows = pendingTransactions
    .flatMap((transaction) =>
      transaction.items.map((item) => ({
        transactionId: transaction.id,
        date: transaction.date,
        branchName: transaction.branchName,
        paymentAccount: transaction.paymentAccount,
        ...item,
      }))
    )
    .sort((a, b) => a.date.localeCompare(b.date))

  const fmt = (value) =>
    `KES ${Number(value || 0).toLocaleString("en-KE", { minimumFractionDigits: 2 })}`

  const formatDate = (dateStr) => {
    const date = new Date(dateStr)
    return new Intl.DateTimeFormat("en-KE", {
      weekday: "short",
      month: "short",
      day: "numeric",
    }).format(date)
  }

  const resetComposer = () => {
    setCartItems([])
    setDiscountEnabled(false)
    setDiscountType("pct")
    setDiscountValue("")
    setProductSearch("")
  }

  const addToCart = (product) => {
    const existing = cartItems.find((item) => item.product_id === product.id)
    if (existing) {
      setCartItems(
        cartItems.map((item) =>
          item.product_id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        )
      )
    } else {
      setCartItems((current) => [
        ...current,
        {
          product_id: product.id,
          name: product.name,
          sku_id: product.sku_id,
          unit_price: Number(product.selling_price || 0),
          quantity: 1,
          max_quantity: Number(product.current_quantity || 0),
        },
      ])
    }
    setProductSearch("")
  }

  const updateQty = (productId, qty) => {
    if (qty <= 0) {
      setCartItems((current) => current.filter((item) => item.product_id !== productId))
      return
    }

    setCartItems((current) =>
      current.map((item) => (item.product_id === productId ? { ...item, quantity: qty } : item))
    )
  }

  const handleRecordSale = () => {
    if (cartItems.length === 0) {
      setError("Add at least one product")
      return
    }

    if (canViewAll && !resolvedBranchId) {
      setError("Select a branch before recording a sale")
      return
    }

    if (openingDate && selectedDate < openingDate) {
      setError("Sale date cannot be before opening stock date")
      return
    }

    setError("")

    const pendingTransaction = {
      id: crypto.randomUUID(),
      date: selectedDate,
      branchId: resolvedBranchId,
      branchName: availableBranches.find(b => b.id === resolvedBranchId)?.name || "Unassigned branch",
      paymentAccount,
      subtotal,
      discountAmount,
      total,
      items: cartItems.map((item) => ({
        product_id: item.product_id,
        name: item.name,
        sku_id: item.sku_id,
        quantity: item.quantity,
        unit_price: item.unit_price,
        total_amount: item.unit_price * item.quantity,
      })),
    }

    setPendingTransactions((current) => [...current, pendingTransaction])
    resetComposer()
  }

  const handleSubmit = async () => {
    if (pendingTransactions.length === 0) {
      setError("Record at least one staged sale first")
      return
    }

    setLoading(true)
    setError("")

    try {
      for (const stagedTransaction of pendingTransactions) {
        const transactionDate = new Date(`${stagedTransaction.date}T12:00:00Z`).toISOString()
        const { data: txn, error: txnError } = await supabase
          .from("transactions")
          .insert({
            business_id: businessId,
            branch_id: stagedTransaction.branchId,
            type: "sale",
            transaction_type_tag: "income",
            payment_account: stagedTransaction.paymentAccount,
            account_code: "4100",
            date: transactionDate,
            created_by: userId,
          })
          .select()
          .single()

        if (txnError) throw txnError

        const items = stagedTransaction.items.map((item) => ({
          transaction_id: txn.id,
          product_id: item.product_id,
          quantity: item.quantity,
          unit_price: item.unit_price,
          total_amount: item.total_amount,
          vat_applied: 0,
          etims_receipt_no: null,
        }))

        const db = await getDb()
        const { error: itemsError } = await db.transactions.insert({
          id: `sale-items-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
          business_id: businessId,
          branch_id: resolvedBranchId,
          type: 'sale_items_batch',
          transaction_type_tag: 'sale',
          payment_account: stagedTransaction.paymentAccount,
          account_code: stagedTransaction.paymentAccount,
          date: stagedTransaction.date,
          created_by: authUser.id,
          lifecycle_state: 'completed',
          amount: stagedTransaction.total,
          display_name: 'Historical Sale Items',
          sale_items: items,
          _modified: Date.now(),
          _deleted: false,
        })
        if (itemsError) throw itemsError

        const stockUpdates = stagedTransaction.items.map((item) =>
          supabase.rpc("decrement_stock", {
            product_id: item.product_id,
            amount: item.quantity,
          })
        )

        await Promise.all(stockUpdates)
      }

      setPendingTransactions([])
      setShowPendingReview(false)
      resetComposer()
      await fetchInitialData()
      navigate("/settings", { replace: true })
    } catch (err) {
      setError(err.message || "Failed to submit transactions")
    } finally {
      setLoading(false)
    }
  }

  const goBack = () => navigate("/settings", { replace: true })

  if (showPendingReview) {
    return (
      <AppShell
        title="Finalize onboarding"
        subtitle="Review staged sales before final submission"
        contentClassName="max-w-6xl"
        right={
          <UiButton variant="secondary" size="sm" onClick={() => setShowPendingReview(false)}>
            Back
          </UiButton>
        }
      >
        <div className="space-y-4">
          {error && <p className="rounded-lg bg-red-400/10 px-3 py-2 text-sm text-red-400">{error}</p>}

          <UiCard className="space-y-3 p-4">
            <UiSectionTitle
              title="Transactions table"
              caption={`${pendingRows.length} line${pendingRows.length !== 1 ? "s" : ""} across ${pendingTransactions.length} staged sale${pendingTransactions.length !== 1 ? "s" : ""}`}
            />
            <div className="overflow-x-auto">
              <table className="w-full min-w-[760px]">
                <thead>
                  <tr className="border-b border-zinc-800 text-left text-[10px] uppercase tracking-wider text-zinc-500">
                    <th className="py-3 pr-4 font-medium">Date</th>
                    <th className="py-3 pr-4 font-medium">Product</th>
                    <th className="py-3 pr-4 font-medium">SKU</th>
                    <th className="py-3 pr-4 font-medium">Branch</th>
                    <th className="py-3 pr-4 font-medium">Payment</th>
                    <th className="py-3 px-2 text-right font-medium">Qty</th>
                    <th className="py-3 px-2 text-right font-medium">Unit price</th>
                    <th className="py-3 pl-2 text-right font-medium">Line total</th>
                  </tr>
                </thead>
                <tbody>
                  {pendingRows.map((row, index) => (
                    <tr
                      key={`${row.transactionId}-${row.product_id}-${index}`}
                      className="border-b border-zinc-900"
                    >
                      <td className="py-3 pr-4 font-mono text-sm text-zinc-300">{row.date}</td>
                      <td className="py-3 pr-4 text-sm text-white">{row.name}</td>
                      <td className="py-3 pr-4 text-sm text-zinc-300">{row.sku_id || "-"}</td>
                      <td className="py-3 pr-4 text-sm text-zinc-300">{row.branchName}</td>
                      <td className="py-3 pr-4 text-sm capitalize text-zinc-300">{row.paymentAccount}</td>
                      <td className="py-3 px-2 text-right font-mono text-sm text-zinc-300">{row.quantity}</td>
                      <td className="py-3 px-2 text-right font-mono text-sm text-zinc-300">{fmt(row.unit_price)}</td>
                      <td className="py-3 pl-2 text-right font-mono text-sm text-emerald-400">{fmt(row.total_amount)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </UiCard>

          <UiCard className="space-y-2 p-4">
            <UiSectionTitle title="Summary" />
            <div className="flex justify-between">
              <p className="text-sm text-zinc-400">Transactions</p>
              <p className="font-mono text-sm text-white">{pendingTransactions.length}</p>
            </div>
            <div className="flex justify-between">
              <p className="text-sm text-zinc-400">Lines</p>
              <p className="font-mono text-sm text-white">{pendingRows.length}</p>
            </div>
            <div className="mt-2 flex justify-between border-t border-zinc-800 pt-2">
              <p className="text-sm font-semibold text-white">Grand total</p>
              <p className="font-mono font-bold text-emerald-400">
                {fmt(pendingTransactions.reduce((sum, transaction) => sum + transaction.total, 0))}
              </p>
            </div>
          </UiCard>

          <div className="flex justify-end">
            <UiButton
              variant="primary"
              className="px-6 py-3"
              onClick={handleSubmit}
              disabled={loading || pendingTransactions.length === 0}
            >
              {loading ? "Submitting..." : "Submit & finish"}
            </UiButton>
          </div>
        </div>
      </AppShell>
    )
  }

  return (
    <AppShell
      title="Backdated sales"
      subtitle={
        resolvedBranchId
          ? `${availableBranches.find(b => b.id === resolvedBranchId)?.name} ┬╖ Backfill missed sales before final review`
          : "Backfill missed sales before final review"
      }
      showHeader={true}
      contentClassName="max-w-6xl"
      right={
        <div className="flex w-full flex-wrap items-stretch gap-1.5 sm:w-auto sm:items-center sm:gap-3">
          <UiButton
            variant="secondary"
            size="sm"
            onClick={goBack}
            className="flex-1 px-2 text-xs sm:flex-none sm:px-3"
          >
            Settings
          </UiButton>
          {canViewAll && (
            <BranchSelector value={resolvedBranchId || "all"} />
          )}
        </div>
      }
    >
      <div className="grid gap-4 lg:grid-cols-[1.35fr_0.65fr]">
        <div className="space-y-4">
          {error && <p className="rounded-lg bg-red-400/10 px-3 py-2 text-sm text-red-400">{error}</p>}

          {!openingDate && (
            <p className="rounded-lg bg-yellow-400/10 px-3 py-2 text-sm text-yellow-400">
              Opening stock not set. Go back and set opening inventory first.
            </p>
          )}

          {openingDate && (
            <>
              {canViewAll && !resolvedBranchId && (
                <UiCard className="space-y-3 border-amber-400/20 bg-amber-400/5 p-4">
                  <UiSectionTitle
                    title="Choose branch"
                    caption="Historical sales are recorded per branch"
                  />
                  <div className="flex items-center justify-between gap-3">
                    <p className="text-sm text-zinc-300">
                      Pick the branch you want to backdate sales for before submitting.
                    </p>
                    <div className="shrink-0"><BranchSelector value={resolvedBranchId || "all"} /></div>
                  </div>
                </UiCard>
              )}

              <UiCard className="space-y-3 p-4">
                <UiSectionTitle title="Sale date" caption="Record a past sale after opening stock" />
                <div className="flex items-center justify-between gap-3">
                  <input
                    type="date"
                    min={openingDate}
                    max={new Date().toISOString().split("T")[0]}
                    value={selectedDate}
                    onChange={(event) => setSelectedDate(event.target.value)}
                    className="w-full rounded-xl border border-zinc-800 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors focus:border-emerald-500"
                  />
                  <p className="hidden whitespace-nowrap text-sm text-zinc-500 sm:block">
                    {formatDate(selectedDate)}
                  </p>
                </div>
              </UiCard>

              <UiCard className="space-y-3 p-4">
                <UiSectionTitle title="Add products" caption="Search and build the cart" />
                <input
                  type="text"
                  value={productSearch}
                  onChange={(event) => setProductSearch(event.target.value)}
                  placeholder="Search product name or SKU..."
                  className="w-full rounded-xl border border-zinc-800 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
                />
                {productSearch && (
                  <div className="max-h-56 space-y-1 overflow-y-auto">
                    {filteredProducts.length === 0 ? (
                      <div className="rounded-xl border border-zinc-800 bg-zinc-950 px-4 py-3 text-sm text-zinc-500">
                        No matching products found.
                      </div>
                    ) : (
                      filteredProducts.map((product) => (
                        <button
                          key={product.id}
                          onClick={() => addToCart(product)}
                          className="flex w-full items-center justify-between rounded-xl border border-zinc-800 bg-zinc-950 px-4 py-3 text-left transition-colors hover:border-zinc-700"
                        >
                          <div>
                            <p className="text-sm text-white">{product.name}</p>
                            <p className="text-xs text-zinc-500">
                              {product.sku_id || "No SKU"} ┬╖ {product.current_quantity || 0} in stock
                            </p>
                          </div>
                          <p className="text-sm font-mono text-emerald-400">
                            {fmt(product.selling_price)}
                          </p>
                        </button>
                      ))
                    )}
                  </div>
                )}
              </UiCard>

              {cartItems.length > 0 && (
                <UiCard className="space-y-3 p-4">
                  <UiSectionTitle
                    title="Cart"
                    caption={`${itemCount} items across ${cartItems.length} lines`}
                  />
                  <div className="space-y-3">
                    {cartItems.map((item) => (
                      <div
                        key={item.product_id}
                        className="flex items-center justify-between gap-3 rounded-2xl border border-zinc-800 bg-zinc-950/60 px-3 py-3"
                      >
                        <div className="min-w-0 flex-1">
                          <p className="truncate text-sm text-white">{item.name}</p>
                          <p className="text-xs text-zinc-500">
                            {item.sku_id || "No SKU"} ┬╖ {fmt(item.unit_price)} / unit
                          </p>
                        </div>
                        <div className="flex items-center gap-2">
                          <UiButton
                            variant="ghost"
                            size="sm"
                            className="h-8 w-8 px-0"
                            onClick={() => updateQty(item.product_id, item.quantity - 1)}
                          >
                            -
                          </UiButton>
                          <span className="w-6 text-center font-mono text-sm text-white">
                            {item.quantity}
                          </span>
                          <UiButton
                            variant="ghost"
                            size="sm"
                            className="h-8 w-8 px-0"
                            onClick={() => updateQty(item.product_id, item.quantity + 1)}
                          >
                            +
                          </UiButton>
                        </div>
                        <p className="w-24 text-right font-mono text-sm text-emerald-400">
                          {fmt(item.unit_price * item.quantity)}
                        </p>
                      </div>
                    ))}
                  </div>
                </UiCard>
              )}

              {cartItems.length > 0 && (
                <UiCard className="space-y-3 p-4">
                  <UiSectionTitle
                    title="Sales to record"
                    caption="Review the current sale before you record it"
                  />
                  <div className="overflow-x-auto">
                    <table className="w-full min-w-[560px]">
                      <thead>
                        <tr className="border-b border-zinc-800 text-left text-[10px] uppercase tracking-wider text-zinc-500">
                          <th className="py-3 pr-4 font-medium">Product</th>
                          <th className="py-3 pr-4 font-medium">SKU</th>
                          <th className="py-3 px-2 text-right font-medium">Qty</th>
                          <th className="py-3 px-2 text-right font-medium">Unit price</th>
                          <th className="py-3 pl-2 text-right font-medium">Line total</th>
                        </tr>
                      </thead>
                      <tbody>
                        {cartItems.map((item) => (
                          <tr key={item.product_id} className="border-b border-zinc-900">
                            <td className="py-3 pr-4 text-sm text-white">{item.name}</td>
                            <td className="py-3 pr-4 text-sm text-zinc-300">{item.sku_id || "-"}</td>
                            <td className="py-3 px-2 text-right font-mono text-sm text-zinc-300">
                              {item.quantity}
                            </td>
                            <td className="py-3 px-2 text-right font-mono text-sm text-zinc-300">
                              {fmt(item.unit_price)}
                            </td>
                            <td className="py-3 pl-2 text-right font-mono text-sm text-emerald-400">
                              {fmt(item.unit_price * item.quantity)}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                  <div className="space-y-2 border-t border-zinc-800 pt-3">
                    <div className="flex justify-between text-sm">
                      <span className="text-zinc-500">Date</span>
                      <span className="font-mono text-zinc-200">{selectedDate}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-zinc-500">Branch</span>
                      <span className="text-zinc-200">{availableBranches.find((branch) => branch.id === resolvedBranchId)?.name || "Select branch"}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-zinc-500">Payment</span>
                      <span className="capitalize text-zinc-200">{paymentAccount}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-zinc-500">Subtotal</span>
                      <span className="font-mono text-zinc-200">{fmt(subtotal)}</span>
                    </div>
                    {discountAmount > 0 && (
                      <div className="flex justify-between text-sm">
                        <span className="text-zinc-500">Discount</span>
                        <span className="font-mono text-red-400">-{fmt(discountAmount)}</span>
                      </div>
                    )}
                    <div className="flex justify-between border-t border-zinc-800 pt-2 text-sm">
                      <span className="font-medium text-white">Final total</span>
                      <span className="font-mono font-bold text-emerald-400">{fmt(total)}</span>
                    </div>
                  </div>
                </UiCard>
              )}

              <UiCard className="space-y-3 p-4">
                <UiSectionTitle title="Discount" />
                <div className="flex items-center justify-between">
                  <p className="text-sm text-zinc-400">Apply discount</p>
                  <UiButton
                    variant={discountEnabled ? "primary" : "secondary"}
                    size="sm"
                    onClick={() => {
                      setDiscountEnabled(!discountEnabled)
                      setDiscountValue("")
                    }}
                  >
                    {discountEnabled ? "On" : "Off"}
                  </UiButton>
                </div>
                {discountEnabled && (
                  <div className="space-y-3">
                    <div className="flex gap-2">
                      <UiButton
                        variant={discountType === "pct" ? "primary" : "secondary"}
                        size="sm"
                        className="flex-1"
                        onClick={() => {
                          setDiscountType("pct")
                          setDiscountValue("")
                        }}
                      >
                        % Percentage
                      </UiButton>
                      <UiButton
                        variant={discountType === "fixed" ? "primary" : "secondary"}
                        size="sm"
                        className="flex-1"
                        onClick={() => {
                          setDiscountType("fixed")
                          setDiscountValue("")
                        }}
                      >
                        KES Fixed
                      </UiButton>
                    </div>
                    <input
                      type="number"
                      value={discountValue}
                      onChange={(event) => setDiscountValue(event.target.value)}
                      placeholder={discountType === "pct" ? "e.g. 10" : "e.g. 200"}
                      className="w-full rounded-xl border border-zinc-800 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors placeholder:text-zinc-600 focus:border-emerald-500"
                    />
                  </div>
                )}
              </UiCard>

              <UiCard className="space-y-3 p-4">
                <UiSectionTitle title="Payment" />
                <div className="flex gap-2">
                  {["cash", "mpesa", "bank"].map((method) => (
                    <UiButton
                      key={method}
                      variant={paymentAccount === method ? "primary" : "secondary"}
                      size="sm"
                      className="flex-1 capitalize"
                      onClick={() => setPaymentAccount(method)}
                    >
                      <div className="flex items-center justify-center gap-2">
                        <PaymentIcon type={method} className="h-4 w-4 text-zinc-200" />
                        <span>
                          {method === "mpesa"
                            ? "M-Pesa"
                            : method.charAt(0).toUpperCase() + method.slice(1)}
                        </span>
                      </div>
                    </UiButton>
                  ))}
                </div>
              </UiCard>

              <UiCard className="space-y-2 p-4">
                <UiSectionTitle title="Total" />
                <div className="flex justify-between">
                  <p className="text-sm text-zinc-400">Subtotal</p>
                  <p className="font-mono text-sm text-white">{fmt(subtotal)}</p>
                </div>
                {discountAmount > 0 && (
                  <div className="flex justify-between">
                    <p className="text-sm text-zinc-400">
                      Discount {discountType === "pct" ? `(${discountValue}%)` : ""}
                    </p>
                    <p className="font-mono text-sm text-red-400">-{fmt(discountAmount)}</p>
                  </div>
                )}
                <div className="mt-2 flex justify-between border-t border-zinc-800 pt-2">
                  <p className="text-sm font-semibold text-white">Total</p>
                  <p className="font-mono font-bold text-emerald-400">{fmt(total)}</p>
                </div>
              </UiCard>

              {todaysSales.length > 0 && (
                <UiCard className="space-y-3 p-4">
                  <UiSectionTitle
                    title={`Sales entered for ${formatDate(selectedDate)}`}
                    caption={`${todaysSales.length} line${todaysSales.length !== 1 ? "s" : ""}`}
                  />
                  <div className="space-y-2">
                    {todaysSales.map((sale) => {
                      const prod = products.find((product) => product.id === sale.product_id)
                      return (
                        <div
                          key={sale.id}
                          className="flex items-start justify-between rounded-lg border border-zinc-800 bg-zinc-900 p-3"
                        >
                          <div>
                            <p className="text-sm font-medium text-white">
                              {prod?.name || "Unknown product"}
                            </p>
                            <p className="text-xs text-zinc-500">
                              {sale.quantity} x {fmt(sale.unit_price)}
                            </p>
                          </div>
                          <p className="text-sm font-mono text-emerald-400">
                            {fmt(sale.total_amount || sale.quantity * sale.unit_price)}
                          </p>
                        </div>
                      )
                    })}
                  </div>
                  <div className="border-t border-zinc-800 pt-3">
                    <div className="flex justify-between">
                      <span className="text-sm text-zinc-500">Day total</span>
                      <span className="font-mono font-bold text-emerald-400">
                        {fmt(
                          todaysSales.reduce(
                            (sum, sale) =>
                              sum + Number(sale.total_amount || sale.quantity * sale.unit_price),
                            0
                          )
                        )}
                      </span>
                    </div>
                  </div>
                </UiCard>
              )}

              {Object.keys(datesWithSales).length > 0 && (
                <UiCard className="space-y-3 p-4">
                  <UiSectionTitle
                    title="Dates with sales"
                    caption={`${Object.keys(datesWithSales).length} date${Object.keys(datesWithSales).length !== 1 ? "s" : ""}`}
                  />
                  <div className="grid grid-cols-2 gap-2 sm:grid-cols-3 md:grid-cols-4">
                    {Object.entries(datesWithSales).map(([date, sales]) => (
                      <button
                        key={date}
                        onClick={() => setSelectedDate(date)}
                        className={`rounded-xl border p-3 text-center text-xs transition-colors ${
                          selectedDate === date
                            ? "border-emerald-500 bg-emerald-500/10"
                            : "border-zinc-800 bg-zinc-900 hover:border-zinc-700"
                        }`}
                      >
                        <p className="font-medium text-white">{formatDate(date).split(" ")[0]}</p>
                        <p className="text-zinc-400">
                          {formatDate(date).split(" ").slice(1).join(" ")}
                        </p>
                        <p className="mt-1 text-xs text-emerald-400">{sales.length} lines</p>
                      </button>
                    ))}
                  </div>
                </UiCard>
              )}
            </>
          )}
        </div>

        <div className="space-y-4 self-start lg:sticky lg:top-6">
          <UiCard className="p-5">
            <UiSectionTitle title="Live receipt" caption="Backdated sale preview" />
            <div className="space-y-2 text-sm">
              <div className="flex items-center justify-between">
                <p className="text-zinc-500">Date</p>
                <p className="font-mono text-zinc-200">{selectedDate}</p>
              </div>
              <div className="flex items-center justify-between">
                <p className="text-zinc-500">Items</p>
                <p className="font-mono text-zinc-200">{itemCount}</p>
              </div>
              <div className="flex items-center justify-between">
                <p className="text-zinc-500">Lines</p>
                <p className="font-mono text-zinc-200">{cartItems.length}</p>
              </div>
              <div className="flex items-center justify-between">
                <p className="text-zinc-500">Staged sales</p>
                <p className="font-mono text-zinc-200">{pendingTransactions.length}</p>
              </div>
              <div className="flex items-center justify-between">
                <p className="text-zinc-500">Payment</p>
                <p className="capitalize text-zinc-200">{paymentAccount}</p>
              </div>
              <div className="flex items-center justify-between border-t border-zinc-800 pt-2">
                <p className="text-zinc-500">Final total</p>
                <p className="font-mono font-bold text-emerald-400">{fmt(total)}</p>
              </div>
            </div>
          </UiCard>

          <UiCard className="p-5">
            <UiSectionTitle title="Confidence checklist" />
            {[
              { ok: !!openingDate, text: "Opening stock exists" },
              { ok: cartItems.length > 0, text: "At least one product added" },
              { ok: !discountEnabled || discountValue !== "", text: "Discount value provided if enabled" },
              { ok: !!paymentAccount, text: "Payment account selected" },
            ].map((item, index) => (
              <div key={index} className="flex items-center justify-between py-1 text-xs">
                <p className={item.ok ? "text-zinc-300" : "text-zinc-600"}>{item.text}</p>
                <span className={item.ok ? "text-emerald-400" : "text-zinc-700"}>
                  {item.ok ? "OK" : "..."}
                </span>
              </div>
            ))}
          </UiCard>

          <UiCard className="space-y-3 p-5">
            <UiSectionTitle
              title="Actions"
              caption={`${pendingTransactions.length} staged sale${pendingTransactions.length !== 1 ? "s" : ""} ready for review`}
            />
            <UiButton
              variant="primary"
              className="w-full"
              onClick={handleRecordSale}
              disabled={loading || cartItems.length === 0 || !openingDate}
            >
              {loading ? "Recording..." : `Record sale ┬╖ ${fmt(total)}`}
            </UiButton>
            <UiButton
              variant="secondary"
              className="w-full"
              onClick={() => setShowPendingReview(true)}
              disabled={loading || pendingTransactions.length === 0}
            >
              Complete transactions
            </UiButton>
          </UiCard>
        </div>
      </div>
    </AppShell>
  )
}

import { useState, useEffect, useMemo, useRef } from "react"
import { supabase } from "../../lib/supabase"
import { useNavigate } from "react-router-dom"
import { useUser, useCurrentBusiness } from "../../hooks/useRole"
import { useBranchContext } from "../../context/BranchContext"
import { AppShell, UiButton, UiCard, UiSectionTitle, CategorySelect } from "../../components/ui"
import { BranchSelector } from "../../components/BranchSelector"

export default function OpeningStock() {
  const navigate = useNavigate()
  const { user: authUser } = useUser()
  const { businessId } = useCurrentBusiness()
  const {
    canViewAll,
    availableBranches,
    effectiveBranchId,
    isOwner,
    isManager,
    readyToFetch,
  } = useBranchContext()
  const [userId, setUserId] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const [success, setSuccess] = useState(false)
  const resolvedBranchId = effectiveBranchId

  // Product states
  const [existingProducts, setExistingProducts] = useState([])
  const [addedStock, setAddedStock] = useState([])
  const [selectedProduct, setSelectedProduct] = useState(null)
  const [productSearch, setProductSearch] = useState("")
  const [name, setName] = useState("")
  const [category, setCategory] = useState("")
  const [quantity, setQuantity] = useState("")
  const [unitCost, setUnitCost] = useState("")
  const [sellingPrice, setSellingPrice] = useState("")
  const [additionalCosts, setAdditionalCosts] = useState([])
  const [openingDate, setOpeningDate] = useState("")
  const [step, setStep] = useState(1)
  const [isNewProduct, setIsNewProduct] = useState(true)
  const previousBranchIdRef = useRef(null)
  const defaultUnit = "pcs"
  const activeBranchInfo = useMemo(() => {
    return availableBranches.find((branch) => branch.id === resolvedBranchId) || null
  }, [availableBranches, resolvedBranchId])

  const categoryOptions = useMemo(() => {
    return Array.from(
      new Set([
        ...existingProducts.map((product) => product.category).filter(Boolean),
        ...addedStock.map((item) => item.category).filter(Boolean),
      ])
    ).sort((a, b) => String(a).localeCompare(String(b)))
  }, [existingProducts, addedStock])

  useEffect(() => {
    const previousBranchId = previousBranchIdRef.current
    if (!previousBranchId) {
      previousBranchIdRef.current = resolvedBranchId
      return
    }

    if (resolvedBranchId && previousBranchId !== resolvedBranchId) {
      // Prevent cross-branch contamination when owner switches branch scope.
      setSelectedProduct(null)
      setProductSearch("")
      setAddedStock([])
      setStep(1)
      setError("")
    }

    previousBranchIdRef.current = resolvedBranchId
  }, [resolvedBranchId])

  const fetchInitialData = async () => {
    if (canViewAll && !resolvedBranchId) {
      setExistingProducts([])
      setError("Select a branch before setting opening stock")
      return
    }
    if (!resolvedBranchId) {
      setExistingProducts([])
      setError("Your branch is not assigned yet. Contact the owner.")
      return
    }

    setError("")
    setUserId(authUser.id)

    let query = supabase
      .from("products")
      .select("id, name, sku_id, selling_price, unit_of_measure, category, branch_id, branches!left(name, code)")
      .eq("business_id", businessId)
      .not("is_active", "eq", false)
      .order("name")

    query = query.eq("branch_id", resolvedBranchId)

    const { data: productsData } = await query
    setExistingProducts(productsData || [])
  }

  useEffect(() => {
    if (businessId && authUser && readyToFetch) {
      void fetchInitialData()
    }
  }, [businessId, authUser, resolvedBranchId, readyToFetch, canViewAll])

  const generateSKU = (productName) => {
    const words = productName.trim().toUpperCase().split(" ")
    const base = words.map((w) => w.slice(0, 3)).join("-")
    const suffix = Math.floor(Math.random() * 900 + 100)
    return `${base}-${suffix}`
  }

  const generateUniqueSKU = (productName, reservedSkus) => {
    let candidate = generateSKU(productName)
    while (reservedSkus.has(candidate)) {
      candidate = generateSKU(productName)
    }
    reservedSkus.add(candidate)
    return candidate
  }

  const qty = parseFloat(quantity) || 0
  const cost = parseFloat(unitCost) || 0
  const additionalTotal = additionalCosts.reduce((sum, item) => sum + (parseFloat(item.amount) || 0), 0)
  const totalLandedCost = (qty * cost) + additionalTotal
  const landedCostPerUnit = qty > 0 ? totalLandedCost / qty : 0
  const suggestedLow = Math.ceil(landedCostPerUnit * 1.4)
  const suggestedHigh = Math.ceil(landedCostPerUnit * 1.8)
  const sp = parseFloat(sellingPrice) || 0
  const profitPerUnit = sp - landedCostPerUnit
  const profitTotal = profitPerUnit * qty

  const canProceedStep1 = isNewProduct ? Boolean(name.trim()) : Boolean(selectedProduct)
  const canProceedStep2 = Boolean(quantity) && Boolean(unitCost)
  const canProceedStep3 = Boolean(sellingPrice)
  const canSubmit = canProceedStep1 && canProceedStep2 && canProceedStep3

  const fmt = (n) => `KES ${Number(n).toLocaleString("en-KE", { minimumFractionDigits: 2 })}`
  const fmtShort = (n) => `KES ${Math.round(n).toLocaleString("en-KE")}`

  const addCostLine = () => setAdditionalCosts([...additionalCosts, { label: "", amount: "" }])
  const updateCostLine = (index, field, value) => {
    const updated = [...additionalCosts]
    updated[index][field] = value
    setAdditionalCosts(updated)
  }
  const removeCostLine = (index) => setAdditionalCosts(additionalCosts.filter((_, i) => i !== index))

  const resetEntryForm = () => {
    setSelectedProduct(null)
    setProductSearch("")
    setName("")
    setCategory("")
    setQuantity("")
    setUnitCost("")
    setSellingPrice("")
    setAdditionalCosts([])
    setStep(1)
  }

  const handleAddProduct = () => {
    setError("")
    if (!quantity || !unitCost) { setError("Quantity and unit cost are required"); return }
    if (isNewProduct && !name) { setError("Product name is required"); return }
    if (!isNewProduct && !selectedProduct) { setError("Please select a product"); return }
    if (!sellingPrice) { setError("Selling price is required"); return }
    if (!resolvedBranchId) { setError("Select a branch before adding stock"); return }
    if (!isNewProduct && selectedProduct?.branch_id && selectedProduct.branch_id !== resolvedBranchId) {
      setError("Selected product does not belong to the active branch")
      return
    }

    setAddedStock([
      ...addedStock,
      {
        mode: isNewProduct ? "new" : "existing",
        productId: selectedProduct?.id || null,
        productName: isNewProduct ? name.trim() : selectedProduct.name,
        category: isNewProduct ? (category || null) : selectedProduct?.category || null,
        unit: isNewProduct ? defaultUnit : selectedProduct?.unit_of_measure || defaultUnit,
        quantity: qty,
        unitCost: cost,
        landedCostPerUnit,
        sellingPrice: sp,
        sku: isNewProduct ? generateSKU(name) : selectedProduct?.sku_id || null,
      },
    ])

    resetEntryForm()
  }

  const handleSaveBaseline = async () => {
    if (addedStock.length === 0) { setError("Add at least one product"); return }
    if (!openingDate) { setError("Select opening date"); return }

    if (canViewAll && !resolvedBranchId) { setError("Select a branch before saving baseline"); return }
    if (!resolvedBranchId) { setError("Your branch is not assigned yet. Contact the owner."); return }

    setLoading(true)
    setError("")

    try {
      const reservedSkus = new Set(existingProducts.map((product) => product.sku_id).filter(Boolean))
      const branchId = resolvedBranchId
      const stagedItems = addedStock.map((item, index) => ({ ...item, index }))
      const newItems = stagedItems.filter((item) => item.mode === "new")
      const existingItems = stagedItems.filter((item) => item.mode === "existing")

      const newProductPayload = newItems
        .map((item) => ({
          index: item.index,
          sku: generateUniqueSKU(item.productName, reservedSkus),
          business_id: businessId,
          branch_id: branchId,
          is_active: true,
          sku_id: null,
          name: item.productName,
          category: item.category,
          unit_of_measure: item.unit || defaultUnit,
          buying_price: item.landedCostPerUnit,
          selling_price: item.sellingPrice,
          current_quantity: item.quantity,
        }))
        .map((row) => ({
          ...row,
          sku_id: row.sku,
        }))

      let insertedProducts = []
      if (newProductPayload.length > 0) {
        const { data, error: insertError } = await supabase
          .from("products")
          .insert(newProductPayload.map((row) => {
            const insertRow = { ...row }
            delete insertRow.index
            delete insertRow.sku
            return insertRow
          }))
          .select("id, name, sku_id")

        if (insertError) throw insertError
        insertedProducts = data || []
      }

      if (existingItems.length > 0) {
        const updateResults = await Promise.all(
          existingItems.map(async (item) => {
            const { data: scopedProduct, error: scopeError } = await supabase
              .from("products")
              .select("id")
              .eq("id", item.productId)
              .eq("business_id", businessId)
              .eq("branch_id", branchId)
              .maybeSingle()

            if (scopeError) throw scopeError
            if (!scopedProduct) {
              throw new Error(`Product "${item.productName}" does not belong to the selected branch`)
            }

            return supabase
              .from("products")
              .update({
                current_quantity: item.quantity,
                buying_price: item.landedCostPerUnit,
                selling_price: item.sellingPrice,
              })
              .eq("id", item.productId)
              .eq("business_id", businessId)
              .eq("branch_id", branchId)
          })
        )

        const failedUpdate = updateResults.find((result) => result.error)
        if (failedUpdate?.error) throw failedUpdate.error
      }

      const insertedByIndex = new Map(
        newItems.map((item, idx) => [
          item.index,
          {
            productId: insertedProducts[idx]?.id || null,
            productName: insertedProducts[idx]?.name || item.productName,
            sku: insertedProducts[idx]?.sku_id || newProductPayload[idx]?.sku || null,
          },
        ])
      )

      const persistedItems = stagedItems
        .map((item) => {
          if (item.mode === "existing") return item

          const inserted = insertedByIndex.get(item.index)
          return {
            ...item,
            productId: inserted?.productId,
            productName: inserted?.productName || item.productName,
            sku: inserted?.sku || item.sku,
          }
        })
        .sort((a, b) => a.index - b.index)

      const snapshot = {
        branchId,
        branchName: activeBranchInfo?.name || null,
        stockTakeDate: openingDate,
        products: persistedItems.map((item) => ({
          productId: item.productId,
          productName: item.productName,
          quantity: item.quantity,
          unitCost: item.unitCost,
        })),
        createdBy: userId,
        createdAt: new Date().toISOString(),
      }

      const { data: baseline } = await supabase
        .from("float_baseline")
        .select("opening_stock")
        .eq("business_id", businessId)
        .maybeSingle()

      const existingSnapshots = Array.isArray(baseline?.opening_stock) ? baseline.opening_stock : []
      const updatedSnapshots = [
        ...existingSnapshots.filter((s) => s.branchId !== snapshot.branchId),
        snapshot,
      ]

      const { error: upsertError } = await supabase
        .from("float_baseline")
        .upsert({
          business_id: businessId,
          opening_stock: updatedSnapshots,
          opening_stock_date: openingDate,
          updated_at: new Date().toISOString(),
        }, { onConflict: "business_id" })

      if (upsertError) throw upsertError

      setSuccess(true)
      setAddedStock(persistedItems)
    } catch (err) {
      setError(err.message || "Failed to save baseline")
    } finally {
      setLoading(false)
    }
  }

  const goBack = () => {
    if (window.history.length > 1) navigate(-1)
    else navigate("/settings", { replace: true })
  }

  const totalInventoryValue = addedStock.reduce((sum, item) => sum + (item.quantity * item.unitCost), 0)

  if (success) {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center px-4">
        <div className="w-full max-w-md text-center space-y-6">
          <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto border border-emerald-500/20">
            <span className="text-emerald-400 text-4xl">├ó┼ôΓÇ£</span>
          </div>
          <div>
            <h2 className="text-white font-bold text-2xl tracking-tight">Baseline saved</h2>
            <p className="text-zinc-500 text-sm mt-2">Baseline captured for {addedStock.length} products</p>
          </div>
          <div className="flex gap-3 pt-2">
            <button onClick={() => navigate("/settings/historical-sales")} className="flex-1 bg-emerald-500 hover:bg-emerald-400 text-black font-semibold rounded-xl py-3 text-sm transition-colors">
              Continue to backdated sales
            </button>
            <button onClick={() => navigate("/settings")} className="flex-1 bg-zinc-900 hover:bg-zinc-800 border border-zinc-700 text-white font-medium rounded-xl py-3 text-sm transition-colors">
              Back to settings
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <AppShell
      title="Reorientation stock"
      subtitle={`Step ${step} of 4 ┬╖ Product ΓåÆ Opening qty ΓåÆ Pricing ΓåÆ Review`}
      contentClassName="max-w-6xl"
      right={
        <div className="flex items-center gap-2">
          <UiButton variant="tertiary" size="sm" onClick={goBack}>ΓåÉ Back</UiButton>
          {canViewAll ? <BranchSelector /> : null}
        </div>
      }
    >
      <div className="grid gap-4 lg:grid-cols-[1.3fr_0.7fr]">
        <div className="space-y-4">
          {error && (
            <div className="bg-red-400/10 border border-red-400/20 rounded-xl px-4 py-3">
              <p className="text-red-400 text-sm">{error}</p>
            </div>
          )}

          <div className="grid grid-cols-4 gap-2">
            {[
              { n: 1, label: "Identity" },
              { n: 2, label: "Opening" },
              { n: 3, label: "Pricing" },
              { n: 4, label: "Review" },
            ].map((s) => (
              <button
                key={s.n}
                onClick={() => {
                  if (s.n === 1) setStep(1)
                  if (s.n === 2 && canProceedStep1) setStep(2)
                  if (s.n === 3 && canProceedStep1 && canProceedStep2) setStep(3)
                  if (s.n === 4 && addedStock.length > 0) setStep(4)
                }}
                className={`rounded-xl px-3 py-2 text-xs font-medium transition-colors ${
                  step === s.n
                    ? "bg-emerald-500 text-black"
                    : "bg-zinc-900 border border-zinc-800 text-zinc-500"
                }`}
              >
                {s.label}
              </button>
            ))}
          </div>

          <UiCard className="p-4 space-y-3">
            <UiSectionTitle title="Opening date" caption="This anchors the baseline inventory snapshot" />
            <input
              type="date"
              value={openingDate}
              onChange={(e) => setOpeningDate(e.target.value)}
              className="w-full rounded-xl border border-zinc-800 bg-zinc-950 px-4 py-3 text-sm text-white outline-none transition-colors focus:border-emerald-500"
            />
                      </UiCard>

          {step === 1 && (
            <Section label="01 ΓÇö Product Identity">
              <UiSectionTitle title="Choose what you are opening with" caption="Create a new product or set a starting level for an existing one" />
              <div className="flex gap-2 mb-5">
                <ToggleBtn active={isNewProduct} onClick={() => setIsNewProduct(true)}>New product</ToggleBtn>
                <ToggleBtn active={!isNewProduct} onClick={() => setIsNewProduct(false)}>Existing product</ToggleBtn>
              </div>

              {canViewAll && !resolvedBranchId && (
                <p className="text-amber-400 text-xs mb-3">Select a branch from the header before continuing.</p>
              )}

              {isNewProduct ? (
                <div className="space-y-4">
                  <Field label="Product name">
                    <Input value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Premium Rice 50kg" />
                    {name && <p className="text-zinc-600 text-xs mt-1.5 font-mono tracking-wide">SKU auto-generated on save</p>}
                  </Field>
                  <CategorySelect
                    label="Category"
                    value={category}
                    onChange={setCategory}
                    options={categoryOptions}
                    placeholder="Type or choose a category"
                  />
                  <p className="text-[11px] text-zinc-600">Unit is managed centrally and defaults to pcs for now.</p>
                </div>
              ) : (
                <div className="space-y-3">
                  <Input value={productSearch} onChange={e => setProductSearch(e.target.value)} placeholder="Search products..." />
                  <div className="space-y-1.5 max-h-64 overflow-y-auto">
                    {existingProducts
                      .filter((p) => p.name.toLowerCase().includes(productSearch.toLowerCase()) || p.sku_id?.toLowerCase().includes(productSearch.toLowerCase()))
                      .map((p) => (
                        <div
                          key={p.id}
                          onClick={() => setSelectedProduct(p)}
                          className={`flex items-center justify-between px-4 py-3 rounded-xl cursor-pointer transition-colors ${
                            selectedProduct?.id === p.id
                              ? "bg-emerald-500/10 border border-emerald-500/30"
                              : "bg-zinc-900 hover:bg-zinc-800 border border-zinc-800"
                          }`}
                        >
                          <div>
                            <p className="text-white text-sm font-medium">{p.name}</p>
                            <p className="text-zinc-600 text-xs font-mono mt-0.5">{p.sku_id}</p>
                          </div>
                          {selectedProduct?.id === p.id && <span className="text-emerald-400 text-sm">├ó┼ôΓÇ£</span>}
                        </div>
                      ))}
                  </div>
                </div>
              )}
            </Section>
          )}

          {step === 2 && (
            <Section label="02 ΓÇö Opening Quantity & Cost">
              <UiSectionTitle title="Capture the starting inventory" caption="Use physical count and landed cost at opening" />
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-3">
                  <Field label="Quantity on hand">
                    <Input type="number" value={quantity} onChange={e => setQuantity(e.target.value)} placeholder="0.00" />
                  </Field>
                  <Field label="Unit cost (KES)">
                    <Input type="number" value={unitCost} onChange={e => setUnitCost(e.target.value)} placeholder="0.00" />
                  </Field>
                </div>

                <div>
                  <div className="flex items-center justify-between mb-2">
                    <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium">Additional costs</p>
                    <button onClick={addCostLine} className="text-xs text-emerald-500 hover:text-emerald-400 transition-colors font-medium">+ Add line</button>
                  </div>
                  {additionalCosts.length > 0 && (
                    <div className="space-y-2">
                      {additionalCosts.map((costLine, i) => (
                        <div key={i} className="flex items-center gap-2">
                          <input
                            type="text"
                            value={costLine.label}
                            onChange={e => updateCostLine(i, "label", e.target.value)}
                            placeholder="Label (e.g. Transport)"
                            className="flex-1 bg-zinc-950 border border-zinc-800 text-white rounded-xl px-3 py-2.5 text-xs outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
                          />
                          <input
                            type="number"
                            value={costLine.amount}
                            onChange={e => updateCostLine(i, "amount", e.target.value)}
                            placeholder="0.00"
                            className="w-28 bg-zinc-950 border border-zinc-800 text-white rounded-xl px-3 py-2.5 text-xs outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
                          />
                          <button onClick={() => removeCostLine(i)} className="text-zinc-700 hover:text-red-400 transition-colors text-sm px-1">├ù</button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                {landedCostPerUnit > 0 && (
                  <>
                    <StatRow label="Landed cost / unit" value={fmt(landedCostPerUnit)} accent />
                    <StatRow label="Opening stock value" value={fmt(totalLandedCost)} />
                  </>
                )}
              </div>
            </Section>
          )}

          {step === 3 && (
            <Section label="03 ΓÇö Pricing">
              <UiSectionTitle title="Set the selling strategy" caption="Price from the opening landed cost" />
              <div className="space-y-5">
                <StatRow label="Landed cost / unit" value={fmt(landedCostPerUnit)} accent />
                <Field label="Selling price (KES)">
                  <Input type="number" value={sellingPrice} onChange={e => setSellingPrice(e.target.value)} placeholder="0.00" />
                  {landedCostPerUnit > 0 && (
                    <p className="text-zinc-600 text-xs mt-1.5">Suggested range ┬╖ {fmtShort(suggestedLow)} ΓÇô {fmtShort(suggestedHigh)}</p>
                  )}
                </Field>

                {sp > 0 && (
                  <div className="space-y-2.5">
                    <div className="flex items-center justify-between">
                      <p className="text-sm text-zinc-400">Profit per unit</p>
                      <p className={`text-sm font-mono font-bold ${profitPerUnit > 0 ? "text-emerald-400" : "text-red-400"}`}>{fmt(profitPerUnit)}</p>
                    </div>
                    <div className="flex items-center justify-between border-t border-zinc-800 pt-3">
                      <p className="text-sm text-white font-medium">Profit for {qty} units</p>
                      <p className={`text-sm font-mono font-bold ${profitTotal > 0 ? "text-emerald-400" : "text-red-400"}`}>{fmt(profitTotal)}</p>
                    </div>
                  </div>
                )}
              </div>
            </Section>
          )}

          {step === 4 && (
            <Section label="04 ΓÇö Review & Save">
              <UiSectionTitle title="Opening stock batch" caption="Review the products staged for this baseline" />
              <div className="mb-4">
                <UiButton
                  variant="secondary"
                  className="w-full"
                  onClick={() => {
                    resetEntryForm()
                    setIsNewProduct(true)
                    setStep(1)
                  }}
                >
                  {addedStock.length > 0 ? "Add another SKU" : "New SKU"}
                </UiButton>
              </div>
              {addedStock.length === 0 ? (
                <div className="bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-5 text-center">
                  <p className="text-zinc-400 text-sm">No products added yet</p>
                </div>
              ) : (
                <div className="space-y-2">
                  {addedStock.map((item, idx) => (
                    <div key={idx} className="flex items-center justify-between px-4 py-3 rounded-xl bg-zinc-950 border border-zinc-800">
                      <div>
                        <p className="text-white text-sm font-medium">{item.productName}</p>
                        <p className="text-zinc-600 text-xs mt-0.5">{item.quantity} ├ù {fmt(item.unitCost)}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-emerald-400 text-sm font-mono font-bold">{fmt(item.quantity * item.unitCost)}</p>
                        <button onClick={() => setAddedStock(addedStock.filter((_, i) => i !== idx))} className="text-zinc-600 hover:text-red-400 transition-colors text-xs mt-1">Remove</button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </Section>
          )}

          <UiCard className="p-4">
            <div className="flex items-center justify-between gap-2">
              <UiButton
                variant="secondary"
                onClick={() => setStep((s) => Math.max(1, s - 1))}
                disabled={step === 1 || loading}
              >
                Back
              </UiButton>

              {step < 3 && (
                <UiButton
                  variant="primary"
                  onClick={() => setStep((s) => Math.min(3, s + 1))}
                  disabled={
                    (step === 1 && !canProceedStep1) ||
                    (step === 2 && !canProceedStep2)
                  }
                >
                  Continue
                </UiButton>
              )}

              {step === 3 && (
                <UiButton
                  variant="primary"
                  onClick={() => {
                    handleAddProduct()
                    if (canSubmit) setStep(4)
                  }}
                  disabled={loading || !canProceedStep3}
                >
                  Add to baseline
                </UiButton>
              )}

              {step === 4 && (
                <UiButton variant="primary" onClick={handleSaveBaseline} disabled={loading || addedStock.length === 0}>
                  {loading ? "Saving..." : "Save opening baseline"}
                </UiButton>
              )}
            </div>
          </UiCard>
        </div>

        <div className="space-y-4 lg:sticky lg:top-6 self-start">
          <UiCard className="p-5 space-y-3">
            <UiSectionTitle title="Live preview" caption="Realtime opening stock impact" />
            <StatRow label="Product" value={isNewProduct ? (name || "Draft") : (selectedProduct?.name || "Select product")} />
            <StatRow label="Qty" value={qty || 0} />
            <StatRow label="Unit cost" value={fmt(cost)} />
            <StatRow label="Landed / unit" value={fmt(landedCostPerUnit)} accent />
            <StatRow label="Sell price" value={fmt(sp)} />
          </UiCard>

          <UiCard className="p-5 space-y-3">
            <UiSectionTitle title="Baseline summary" />
            <StatRow label="Opening date" value={openingDate || "-"} />
            <StatRow label="Products added" value={addedStock.length} />
            <StatRow label="Inventory value" value={fmt(totalInventoryValue)} accent />
          </UiCard>

          <UiCard className="p-5 space-y-3">
            <UiSectionTitle title="Confidence checklist" />
            {[
              { ok: canProceedStep1, text: "Product is selected or named" },
              { ok: canProceedStep2, text: "Opening quantity and cost provided" },
              { ok: canProceedStep3, text: "Selling price set" },
              { ok: addedStock.length > 0, text: "At least one product staged" },
            ].map((item, i) => (
              <div key={i} className="flex items-center justify-between text-xs">
                <p className={item.ok ? "text-zinc-300" : "text-zinc-600"}>{item.text}</p>
                <span className={item.ok ? "text-emerald-400" : "text-zinc-700"}>{item.ok ? "Γ£ô" : "ΓÇó"}</span>
              </div>
            ))}
          </UiCard>
        </div>
      </div>
    </AppShell>
  )
}

function Section({ label, children }) {
  return (
    <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
      <p className="text-zinc-500 text-[10px] uppercase tracking-widest font-medium mb-5">{label}</p>
      {children}
    </div>
  )
}

function Field({ label, children }) {
  return (
    <div>
      <label className="text-zinc-400 text-xs mb-2 block">{label}</label>
      {children}
    </div>
  )
}

function Input({ value, onChange, placeholder, type = "text" }) {
  return (
    <input
      type={type}
      value={value}
      onChange={onChange}
      placeholder={placeholder}
      className="w-full bg-zinc-950 border border-zinc-800 text-white rounded-xl px-4 py-3 text-sm outline-none focus:border-emerald-500 transition-colors placeholder:text-zinc-700"
    />
  )
}

function ToggleBtn({ active, onClick, children }) {
  return (
    <button
      onClick={onClick}
      className={`flex-1 py-2.5 rounded-xl text-xs font-medium transition-colors ${
        active ? "bg-emerald-500 text-black" : "bg-zinc-950 border border-zinc-800 text-zinc-400 hover:text-white"
      }`}
    >
      {children}
    </button>
  )
}

function StatRow({ label, value, accent }) {
  return (
    <div className="flex items-center justify-between bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3">
      <p className="text-zinc-400 text-sm">{label}</p>
      <p className={`text-sm font-mono font-bold ${accent ? "text-emerald-400" : "text-white"}`}>{value}</p>
    </div>
  )
}

